-- Schema for Domain: annuity | Business: Life Insurance | Version: v1_mvm
-- Generated on: 2026-05-04 07:01:17

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `life_insurance_ecm`.`annuity` COMMENT 'Dedicated operational domain for annuity contract administration distinct from life policy processing. Owns AV (Account Value), accumulation phase tracking, payout phase calculations, GMWB/GMIB/GMAB benefit base management, RMD tracking, 1035 exchange processing, withdrawal processing (systematic and ad-hoc), annuitization, and FIA index crediting. Manages annuity-specific compliance including tax reporting under IRC Section 72.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`contract` (
    `contract_id` BIGINT COMMENT 'Unique surrogate identifier for each annuity contract record in the lakehouse silver layer. Primary key for the annuity_contract master entity.',
    `account_id` BIGINT COMMENT 'Foreign key linking to billing.billing_account. Business justification: Annuity contracts require billing accounts for premium collection, systematic withdrawals, and benefit disbursements. Real business process: premium payment processing, bank account management for own',
    `cohort_definition_id` BIGINT COMMENT 'Foreign key linking to actuarial.cohort_definition. Business justification: LDTI (ASC 944) and IFRS 17 require every annuity contract to be assigned to an actuarial cohort for CSM, LFPB, and DAC amortization measurement. This is a direct regulatory accounting requirement; eve',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Fixed and indexed annuity general account liabilities are backed by investment portfolios. ALM analysis, reserve adequacy testing, RBC C3 interest rate risk calculations, and ORSA stress testing requi',
    `hierarchy_node_id` BIGINT COMMENT 'Foreign key linking to agent.hierarchy_node. Business justification: Production reporting, override commission calculations, and territory performance management require linking each annuity contract to its distribution hierarchy node. Insurers roll up contract counts ',
    `ifrs17_contract_group_id` BIGINT COMMENT 'Foreign key linking to finance.ifrs17_contract_group. Business justification: Annuity contracts are grouped into IFRS 17 cohorts by issue year and profitability for CSM calculation, risk adjustment, and international financial reporting. Required for companies reporting under I',
    `irc7702_parameter_id` BIGINT COMMENT 'Foreign key linking to product.irc7702_parameter. Business justification: IRS compliance and MEC determination require knowing which IRC 7702 parameter set governs a contract. annuity_contract has tax_qualification_status and is_mec fields whose values are calculated from i',
    `jurisdiction_license_id` BIGINT COMMENT 'Foreign key linking to compliance.jurisdiction_license. Business justification: Contracts can only be issued in states where carrier holds active license. Links contract state_of_issue to jurisdiction license for validation at issue and ongoing compliance monitoring. Prevents una',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Annuity contracts are issued by specific legal entities for NAIC company code reporting, statutory reserve allocation, RBC calculations, and consolidated financial statements. Fundamental regulatory a',
    `party_id` BIGINT COMMENT 'Reference to the party record representing the contract owner — the individual, joint owner, trust, or entity that holds legal ownership of the annuity contract and has rights to make changes, withdrawals, and surrender. Maps to the owner record in the CRM or policyholder master.',
    `pbr_model_segment_id` BIGINT COMMENT 'Foreign key linking to actuarial.pbr_model_segment. Business justification: VM-21 principle-based reserving requires each annuity contract to be assigned to a PBR model segment for stochastic and deterministic reserve calculations. This is a direct NAIC regulatory requirement',
    `plan_id` BIGINT COMMENT 'Reference to the annuity product definition record in the product master, identifying the specific product series, plan code, and feature set (e.g., crediting strategy options, rider availability, surrender charge schedule template) associated with this contract.',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Contracts issued under specific plan versions require version-level rate guarantees, benefit structures, and regulatory compliance parameters. Critical for rate action processing, benefit calculations',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Contracts must use state-approved policy forms at issue. Links contract to approved form filing for state_of_issue validation. Essential for market conduct exam defense and form usage audits. Prevents',
    `primary_annuity_annuitant_party_id` BIGINT COMMENT 'Reference to the party record representing the annuitant — the individual whose life expectancy governs the payout calculations and upon whose death the death benefit or survivor benefit is triggered. May differ from the contract owner in trust-owned or entity-owned contracts.',
    `producer_id` BIGINT COMMENT 'Reference to the agent or producer record in the Agent and Commission Management System who sold and submitted this annuity contract. Used for commission calculation, suitability review attribution, and distribution analytics.',
    `rate_action_id` BIGINT COMMENT 'Foreign key linking to product.rate_action. Business justification: Rate actions drive renewal cap/participation rate changes on FIA contracts. Policyholder notification, opt-out processing, and actuarial impact reporting require linking each contract to the rate_acti',
    `risk_class_id` BIGINT COMMENT 'Foreign key linking to underwriting.risk_class. Business justification: Life-contingent annuity contracts (life-only payout, GMDB riders) are issued under a specific underwriting risk class governing mortality assumptions, COI charges, and statutory reserve calculations. ',
    `agency_id` BIGINT COMMENT 'Foreign key linking to agent.agency. Business justification: Agency-level commission statements, production reports, and state appointment verification at contract issuance require linking each annuity contract to its selling agency. The existing producer_id ca',
    `separate_account_id` BIGINT COMMENT 'Foreign key linking to investment.separate_account. Business justification: Variable annuity contracts are issued under a registered separate account (SEC/NAIC requirement). This link supports contract administration, SEC registration reporting, and NAIC Schedule D filing. A ',
    `state_approval_id` BIGINT COMMENT 'Foreign key linking to product.state_approval. Business justification: State-specific contract terms (free look period, grace period, nonforfeiture options) derive from the state_approval record for the plan/state combination. DOI compliance and state-specific benefit ad',
    `suitability_rule_id` BIGINT COMMENT 'Foreign key linking to product.suitability_rule. Business justification: Regulatory compliance (FINRA Rule 2330, state suitability laws) requires tracing which suitability_rule version governed each contract at issuance. Compliance audits and DOI examinations depend on thi',
    `charge_schedule_id` BIGINT COMMENT 'Reference to the surrender charge schedule definition record that governs this contracts declining surrender charge percentages by contract year, free withdrawal allowance percentage, MVA applicability, and waiver conditions (nursing home, terminal illness, unemployment, disability). Determined at issuance based on product and state.',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Annuity contracts often originate from underwriting applications (deferred annuities sold with life insurance, standalone annuity applications requiring underwriting for large cases or impaired risk a',
    `decision_id` BIGINT COMMENT 'Foreign key linking to underwriting.decision. Business justification: New business processing and audit trails require tracing which underwriting decision authorized contract issuance. Compliance and new business operations teams use this link to verify approved face am',
    `account_value` DECIMAL(18,2) COMMENT 'Current Account Value (AV) of the annuity contract as of the last valuation date — the total accumulated value including all premiums paid, interest/index credits earned, and minus all withdrawals, fees, and charges. The AV is the primary valuation metric for deferred annuity contracts and drives CSV, death benefit, and GMWB benefit base calculations.',
    `account_value_date` DATE COMMENT 'The valuation date as of which the account_value field was last calculated and recorded. Essential for point-in-time reporting, actuarial reserving, and reconciliation with the Actuarial Valuation System (e.g., AXIS, Prophet).',
    `annuitization_date` DATE COMMENT 'The date on which the contract transitioned from the accumulation phase to the payout (annuitization) phase. Null for contracts still in accumulation. Populated when contract_status = ANNUITIZED. Drives payout benefit calculations and IRC Section 72 exclusion ratio computations.',
    `contract_number` STRING COMMENT 'Externally-known, human-readable contract number assigned by the Annuity Administration Platform (e.g., Sapiens Annuity, FAST Annuity) at issuance. Used in all owner correspondence, statements, and regulatory filings. Maps to the contract_id field in the source system.',
    `contract_status` STRING COMMENT 'Current lifecycle state of the annuity contract as maintained in the Annuity Administration Platform. ACTIVE = in-force accumulation or payout; SURRENDERED = full surrender processed; ANNUITIZED = converted to payout phase; LAPSED = terminated for non-payment; PENDING = application received, not yet issued; DEATH_CLAIM = death benefit claim in progress.. Valid values are `ACTIVE|SURRENDERED|ANNUITIZED|LAPSED|PENDING|DEATH_CLAIM`',
    `contract_type` STRING COMMENT 'Classification of the annuity product type: FIXED (traditional fixed annuity), FIA (Fixed Indexed Annuity), VARIABLE (Variable Annuity / VUL-linked), SPIA (Single Premium Immediate Annuity), or MYGA (Multi-Year Guaranteed Annuity). Drives product-specific processing rules, crediting methods, and regulatory treatment.. Valid values are `FIXED|FIA|VARIABLE|SPIA|MYGA`',
    `cost_basis_amount` DECIMAL(18,2) COMMENT 'The owners investment in the contract (cost basis) for IRC Section 72 tax purposes — the total after-tax premiums paid minus any previously recovered basis through tax-free distributions. Used to calculate the taxable portion of withdrawals and the exclusion ratio upon annuitization. Carried forward from prior contract in 1035 exchanges.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this annuity contract record was first created in the lakehouse silver layer, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Represents the data ingestion audit trail timestamp, not the contract issue date. Required for SOX audit trail and data lineage compliance.',
    `csv_amount` DECIMAL(18,2) COMMENT 'The Cash Surrender Value (CSV) — the net amount the contract owner would receive upon full surrender, calculated as the Account Value minus applicable surrender charges and market value adjustment (MVA). Represents the owners actual liquidity value at any point in time.',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the annuity contract is denominated (e.g., USD). All monetary values on this contract record are expressed in this currency. Supports multi-currency operations for international annuity products.. Valid values are `^[A-Z]{3}$`',
    `current_surrender_charge_pct` DECIMAL(18,2) COMMENT 'The surrender charge percentage currently applicable to this contract based on the current contract year within the surrender charge schedule (e.g., 0.0700 = 7%). Updated annually on the contract anniversary. Used to calculate CSV and net surrender proceeds.',
    `exchange_prior_contract_number` STRING COMMENT 'The contract or policy number of the prior insurance or annuity contract that was exchanged into this contract via a 1035 Exchange. Populated only when is_1035_exchange = True. Required for IRS cost basis continuity and tax reporting compliance.',
    `fia_index_strategy` STRING COMMENT 'For FIA (Fixed Indexed Annuity) contracts, the selected index crediting strategy (e.g., S&P 500 Annual Point-to-Point with Cap, S&P 500 Monthly Sum with Cap, Bloomberg US Dynamic Balance Index). Determines how index-linked interest credits are calculated. Null for non-FIA contract types. May reference a crediting strategy code from the product definition.',
    `free_look_expiry_date` DATE COMMENT 'The date on which the owners free-look (right to return) period expires. During the free-look period, the owner may cancel the contract and receive a full refund of premiums paid. Typically 10–30 days from contract delivery, as mandated by state insurance regulations.',
    `free_withdrawal_pct` DECIMAL(18,2) COMMENT 'The percentage of the account value (or premium) that the owner may withdraw each contract year without incurring surrender charges, as defined in the contract (e.g., 0.1000 = 10% free withdrawal allowance). Unused free withdrawal amounts typically do not carry forward.',
    `initial_premium_amount` DECIMAL(18,2) COMMENT 'The first premium payment received at contract issuance, in contract currency. For single-premium products (SPIA, MYGA), this is the total purchase payment. For flexible-premium products, this is the first deposit. Used as the baseline for surrender charge calculations and cost basis tracking.',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether this annuity contract was funded via a 1035 Exchange (tax-free exchange of an existing life insurance policy, endowment, or annuity contract under IRC Section 1035). True = funded by 1035 exchange; False = direct premium payment. Affects cost basis tracking and tax reporting.',
    `is_mva_applicable` BOOLEAN COMMENT 'Indicates whether a Market Value Adjustment (MVA) applies to surrenders or withdrawals in excess of the free withdrawal allowance during the surrender charge period. True = MVA applies (adjusts surrender proceeds up or down based on interest rate movements); False = no MVA. Relevant primarily for MYGA and fixed annuity products.',
    `issue_date` DATE COMMENT 'The date on which the annuity contract was formally issued and became effective. Serves as the anchor date for surrender charge schedule calculations, free-look period, and contract year determinations. Corresponds to the policy_effective_date in the Annuity Administration Platform.',
    `maturity_date` DATE COMMENT 'The date on which the annuity contract reaches its scheduled maturity, typically triggering mandatory annuitization or lump-sum distribution. Relevant for MYGA and deferred annuity products. Null for SPIA contracts which begin payout immediately.',
    `ownership_type` STRING COMMENT 'Categorizes the legal ownership structure of the annuity contract: INDIVIDUAL (single natural person), JOINT (two natural persons, typically spouses), TRUST (e.g., ILIT — Irrevocable Life Insurance Trust), or ENTITY (corporation, partnership, or other non-natural person). Affects tax treatment, RMD rules, and death benefit distribution.. Valid values are `INDIVIDUAL|JOINT|TRUST|ENTITY`',
    `payout_frequency` STRING COMMENT 'The frequency at which annuity income payments are made to the annuitant or payee during the payout phase (MONTHLY, QUARTERLY, SEMI_ANNUAL, ANNUAL). Null for contracts in accumulation phase or with LUMP_SUM payout option.. Valid values are `MONTHLY|QUARTERLY|SEMI_ANNUAL|ANNUAL`',
    `payout_option` STRING COMMENT 'The elected payout option governing how annuity income is distributed during the payout phase: LIFE_ONLY (payments for annuitants lifetime), LIFE_PERIOD_CERTAIN (lifetime with guaranteed minimum period), JOINT_SURVIVOR (payments continue to survivor), PERIOD_CERTAIN (fixed period regardless of survival), LUMP_SUM (single payment). Null for contracts still in accumulation phase.. Valid values are `LIFE_ONLY|LIFE_PERIOD_CERTAIN|JOINT_SURVIVOR|PERIOD_CERTAIN|LUMP_SUM`',
    `phase` STRING COMMENT 'Indicates whether the annuity contract is currently in the ACCUMULATION phase (premiums growing tax-deferred) or the PAYOUT phase (periodic income distributions being made to the annuitant). Drives which processing modules are active in the Annuity Administration Platform.. Valid values are `ACCUMULATION|PAYOUT`',
    `rmd_amount_current_year` DECIMAL(18,2) COMMENT 'The calculated Required Minimum Distribution (RMD) amount that must be distributed from this contract in the current calendar year, based on the prior year-end account value and the IRS Uniform Lifetime Table. Null if rmd_required = False. Tracked by the RMD module of the Annuity Administration Platform.',
    `rmd_required` BOOLEAN COMMENT 'Indicates whether this contract is subject to IRS Required Minimum Distribution (RMD) rules. True = qualified contract (IRA, 403b, etc.) where the owner has reached RMD age and annual distributions are mandated; False = not subject to RMD (non-qualified or owner below RMD age). Drives RMD tracking module in the Annuity Administration Platform.',
    `state_of_issue` STRING COMMENT 'The two-letter US state code of the state in which the annuity contract was issued and delivered. Determines applicable state insurance regulations, surrender charge requirements, free-look period, suitability rules, and tax withholding requirements. Aligns with NAIC state-specific filing requirements.. Valid values are `^[A-Z]{2}$`',
    `surrender_charge_period_years` STRING COMMENT 'The total number of contract years during which surrender charges apply, as defined by the products surrender charge schedule (e.g., 7-year, 10-year surrender charge period). After this period, the contract is fully liquid without surrender charges.',
    `tax_qualification_status` STRING COMMENT 'Indicates the tax qualification status of the annuity contract under IRS rules. NON_QUALIFIED = funded with after-tax dollars, IRC Section 72 exclusion ratio applies; TRADITIONAL_IRA / ROTH_IRA / 403B / 457B / SEP_IRA / SIMPLE_IRA = qualified plan funding with specific RMD and distribution rules. Drives tax reporting (1099-R) and RMD calculations. [ENUM-REF-CANDIDATE: NON_QUALIFIED|TRADITIONAL_IRA|ROTH_IRA|403B|457B|SEP_IRA|SIMPLE_IRA — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this annuity contract record was last modified in the lakehouse silver layer, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Updated on every change event sourced from the Annuity Administration Platform. Required for SOX audit trail, change data capture, and data lineage.',
    CONSTRAINT pk_contract PRIMARY KEY(`contract_id`)
) COMMENT 'Master record for each annuity contract issued by the company, serving as the SSOT for all annuity contract administration. Captures contract type (Fixed, Fixed Indexed, Variable, SPIA, MYGA), issue date, contract status, annuitant identity, owner identity, contract phase (accumulation vs payout), surrender charge schedule (declining charge percentages by contract year, free withdrawal allowance, MVA applicability, and waiver conditions for nursing home, terminal illness, unemployment, disability), market value adjustment (MVA) flag, tax qualification status (qualified IRA, Roth IRA, 403b, 457, non-qualified), IRC Section 72 tax treatment, 1035 exchange indicator, ownership type (individual, joint, trust, entity), and contract currency. Serves as the parent entity for all annuity domain transactions and valuations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`account_value` (
    `account_value_id` BIGINT COMMENT 'Unique surrogate identifier for each periodic account value snapshot record in the annuity valuation ledger. Primary key for this table. Entity role: TRANSACTION_HEADER — represents a discrete periodic valuation event for an annuity contract.',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract for which this account value snapshot is recorded. Links to the annuity contract master record in the Annuity Administration Platform (e.g., Sapiens Annuity, FAST Annuity).',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Daily account value changes (credited interest, rider charges, index credits, COI deductions) generate GAAP/SAP journal entries. Finance teams reconcile account value movements to GL postings each val',
    `legal_entity_id` BIGINT COMMENT 'Foreign key linking to finance.legal_entity. Business justification: Account values must be attributed to issuing legal entity for consolidated balance sheet reporting, statutory reserve calculations, and regulatory capital adequacy (RBC) filings. Required for multi-en',
    `party_id` BIGINT COMMENT 'Reference to the annuity contract owner (policyholder/annuitant) associated with this valuation record. Supports PARTY_REFERENCE requirement for TRANSACTION_HEADER role. Used for policyholder annual statement generation and KYC/AML compliance.',
    `valuation_run_id` BIGINT COMMENT 'Foreign key linking to actuarial.valuation_run. Business justification: Account value snapshots are produced within actuarial valuation cycles. Linking to valuation_run enables reconciliation between contract-level account values and aggregate reserve totals, a standard a',
    `bov_account_value` DECIMAL(18,2) COMMENT 'The Account Value (AV) at the beginning of the valuation period (BOY/BOM/BOQ/BOD depending on cycle). Represents the opening balance before any transactions, credits, or charges are applied during the period. Sourced from the Annuity Administration Platform contract administration module.',
    `coi_charge` DECIMAL(18,2) COMMENT 'Cost of Insurance (COI) charge deducted from the account value during the valuation period. Applicable primarily to variable annuities and indexed products with mortality and expense risk charges. Calculated based on the Net Amount at Risk (NAR) and applicable COI rates.',
    `contract_phase` STRING COMMENT 'Current phase of the annuity contract lifecycle at the time of this valuation: accumulation (premium growth phase), annuitization (conversion to income stream), payout (systematic income payments), surrender (contract terminated by owner), or lapse (contract terminated for non-payment). Critical for determining applicable valuation rules.. Valid values are `accumulation|annuitization|payout|surrender|lapse`',
    `contract_year` STRING COMMENT 'The contract year number at the valuation date, calculated from the contract issue date. Used to determine applicable surrender charge rates, free withdrawal corridors, and benefit base roll-up periods.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this account value record was first created in the Silver Layer lakehouse. Satisfies RECORD_AUDIT_CREATED requirement for TRANSACTION_HEADER role. Used for data lineage, audit trails, and SOX compliance.',
    `credited_interest_amount` DECIMAL(18,2) COMMENT 'Total interest credited to the contract account value during the valuation period for fixed and fixed-indexed annuity products. Includes declared interest rates for fixed products and guaranteed minimum interest for FIA products. Excludes index credits which are tracked separately.',
    `csv` DECIMAL(18,2) COMMENT 'Cash Surrender Value (CSV) of the annuity contract at the valuation date, representing the net amount the contract owner would receive upon full surrender after deducting applicable surrender charges, market value adjustments (MVA), and outstanding loans. Key metric for policyholder statements and regulatory reporting.',
    `death_benefit_amount` DECIMAL(18,2) COMMENT 'Current death benefit (DB) payable upon the death of the annuitant or insured at the valuation date. May equal the account value, a return-of-premium amount, or a stepped-up value depending on the contract terms and any applicable GMDB rider.',
    `eov_account_value` DECIMAL(18,2) COMMENT 'The Account Value (AV) at the end of the valuation period (EOY/EOM/EOQ/EOD depending on cycle). Represents the closing balance after all transactions, credits, and charges have been applied. This is the primary AV figure used for policyholder statements, ALM, and actuarial reserving.',
    `fia_cap_rate` DECIMAL(18,2) COMMENT 'The maximum index credit rate (cap) applied to the linked index return for FIA products during the crediting period (as a decimal, e.g., 0.06 = 6%). Null for non-FIA products or strategies without a cap.',
    `fia_floor_rate` DECIMAL(18,2) COMMENT 'The minimum index credit rate (floor) guaranteed for FIA products during the crediting period (as a decimal, e.g., 0.00 = 0%). Protects the contract owner from negative index returns. Null for non-FIA products.',
    `fia_index_strategy` STRING COMMENT 'The index crediting strategy elected by the contract owner for FIA products (e.g., S&P 500 Annual Point-to-Point with Cap, S&P 500 Monthly Sum, MSCI EAFE Participation Rate). Determines how index credits are calculated. Null for non-FIA products.',
    `fia_participation_rate` DECIMAL(18,2) COMMENT 'The participation rate (as a decimal, e.g., 0.80 = 80%) applied to the linked index return when calculating index credits for FIA products. Null for non-FIA products. Sourced from the Annuity Administration Platform crediting parameters.',
    `free_withdrawal_amount` DECIMAL(18,2) COMMENT 'Maximum amount that can be withdrawn from the contract during the current contract year without incurring surrender charges, typically 10% of the account value or premium. Used for withdrawal processing and policyholder servicing.',
    `gaap_reserve` DECIMAL(18,2) COMMENT 'GAAP reserve for this annuity contract at the valuation date, calculated per FASB ASC 944 Long Duration Targeted Improvements (LDTI). Represents the present value of future benefit payments less the present value of future gross premiums under GAAP accounting.',
    `gmab_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Accumulation Benefit (GMAB) benefit base at the valuation date. Represents the guaranteed minimum account value at the end of the accumulation period. Null if no GMAB rider is attached.',
    `gmdb_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Death Benefit (GMDB) benefit base at the valuation date. Represents the guaranteed floor for the death benefit, which may be higher than the current account value due to step-up provisions or roll-up features. Used for NAR calculation and actuarial reserving under LDTI.',
    `gmib_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Income Benefit (GMIB) benefit base at the valuation date. Represents the accumulation value used to calculate the guaranteed minimum annuitization income. Null if no GMIB rider is attached.',
    `gmwb_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Withdrawal Benefit (GMWB) benefit base at the valuation date. Represents the principal amount from which guaranteed withdrawal amounts are calculated. May grow through roll-up credits or step-ups. Null if no GMWB rider is attached.',
    `gross_withdrawal_amount` DECIMAL(18,2) COMMENT 'Total gross amount withdrawn from the contract account value during the valuation period, including both systematic withdrawals and ad-hoc partial surrenders. Used to calculate surrender charges, tax reporting under IRC Section 72, and GMWB benefit base adjustments.',
    `index_credit_amount` DECIMAL(18,2) COMMENT 'Index-linked interest credit applied to the contract account value during the valuation period for Fixed Indexed Annuity (FIA) products. Calculated based on the performance of the linked index (e.g., S&P 500), subject to applicable cap, floor, and participation rate. Zero for non-FIA products.',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether this annuity contract was funded in whole or in part through a tax-free 1035 Exchange (IRC Section 1035). Affects cost basis tracking, tax reporting, and gain/loss calculations for IRC Section 72 purposes.',
    `is_mec` BOOLEAN COMMENT 'Indicates whether the annuity contract has been classified as a Modified Endowment Contract (MEC) under IRC Section 7702A. MEC status affects the tax treatment of withdrawals and loans, triggering LIFO tax treatment and potential 10% penalty.',
    `is_qualified_contract` BOOLEAN COMMENT 'Indicates whether the annuity contract is a qualified contract (held within a tax-qualified retirement plan such as IRA, 401(k), 403(b)) or a non-qualified contract. Determines applicable tax treatment under IRC Section 72 and RMD requirements.',
    `nar_gmdb` DECIMAL(18,2) COMMENT 'Net Amount at Risk (NAR) for the GMDB guarantee, calculated as the excess of the GMDB benefit base over the current account value (max of zero). Used for COI charge calculation, reinsurance cession, and actuarial reserving under LDTI/IFRS 17.',
    `nar_living_benefit` DECIMAL(18,2) COMMENT 'Net Amount at Risk (NAR) for living benefit guarantees (GMWB/GMIB/GMAB), representing the present value of the excess of guaranteed benefit payments over the projected account value. Used for actuarial reserving under LDTI and IFRS 17 and reinsurance reporting.',
    `net_premium_applied` DECIMAL(18,2) COMMENT 'Total net premium (after applicable premium loads and taxes) credited to the contract account value during the valuation period. Includes initial premiums, subsequent premiums, and 1035 exchange proceeds applied during the period.',
    `product_code` STRING COMMENT 'Internal product code identifying the annuity product type (e.g., FIA, VUL, SPIA, GMWB annuity). Used to apply product-specific valuation rules, crediting methods, and benefit base calculations.',
    `product_type` STRING COMMENT 'Classification of the annuity product: Fixed Indexed Annuity (FIA), Variable Annuity (VA), Single Premium Immediate Annuity (SPIA), Multi-Year Guaranteed Annuity (MYGA), Fixed Premium Deferred Annuity (FPDA), or Fixed Premium Immediate Annuity (FPIA). Drives crediting method and benefit calculation logic. [ENUM-REF-CANDIDATE: FIA|VA|SPIA|MYGA|FPDA|FPIA|RILA|DIA — promote to reference product]. Valid values are `FIA|VA|SPIA|MYGA|FPDA|FPIA`',
    `rider_charge_total` DECIMAL(18,2) COMMENT 'Total of all rider charges (GMWB, GMIB, GMAB, GMDB, LTC, etc.) deducted from the account value during the valuation period. Represents the aggregate cost of all optional benefit riders attached to the contract.',
    `rmd_amount` DECIMAL(18,2) COMMENT 'Required Minimum Distribution (RMD) amount calculated for this contract for the current tax year, applicable to qualified annuity contracts held in IRAs or employer-sponsored retirement plans. Tracked per IRS regulations to ensure compliance with IRC Section 401(a)(9).',
    `source_system_code` STRING COMMENT 'The native record identifier from the originating Annuity Administration Platform (e.g., Sapiens Annuity, FAST Annuity) for this account value snapshot. Used for data lineage, reconciliation, and ETL traceability between the operational system and the Silver Layer lakehouse.',
    `statutory_reserve` DECIMAL(18,2) COMMENT 'Estimated statutory reserve for this annuity contract at the valuation date, calculated per NAIC Statutory Accounting Principles (SAP) and Principle-Based Reserving (PBR) requirements. Sourced from or reconciled with the Actuarial Valuation System (e.g., MoSes, AXIS, Prophet).',
    `sub_account_gain_loss` DECIMAL(18,2) COMMENT 'Net investment gain or loss from variable annuity sub-account performance during the valuation period. Applicable only to Variable Annuity (VA) and Variable Universal Life (VUL) products. Reflects market value changes in the separate account sub-accounts.',
    `surrender_charge_amount` DECIMAL(18,2) COMMENT 'Applicable surrender charge that would be assessed if the contract were fully surrendered at the valuation date. Calculated based on the surrender charge schedule and contract duration. Used for CSV calculation and policyholder disclosure.',
    `surrender_charge_rate` DECIMAL(18,2) COMMENT 'Applicable surrender charge rate (as a decimal, e.g., 0.07 = 7%) at the valuation date based on the contracts surrender charge schedule and contract year. Used to calculate the surrender charge amount and free withdrawal corridor.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this account value record was last modified in the Silver Layer lakehouse. Satisfies RECORD_AUDIT_UPDATED requirement for TRANSACTION_HEADER role. Populated on restatements, corrections, or status changes.',
    `valuation_cycle` STRING COMMENT 'Frequency classification of this valuation snapshot indicating whether it is a daily, monthly, quarterly, or annual valuation record. Drives downstream actuarial and ALM processing cadence.. Valid values are `daily|monthly|quarterly|annual`',
    `valuation_date` DATE COMMENT 'The as-of date for this account value snapshot. Represents the principal real-world business event date (BUSINESS_EVENT_TIMESTAMP category). May be daily, month-end, quarter-end, or year-end depending on the valuation cycle. Used for actuarial reserving, ALM, and regulatory reporting.',
    `valuation_status` STRING COMMENT 'Current lifecycle status of this account value record indicating whether the valuation is preliminary (in-process), final (approved), restated (corrected after finalization), or voided (cancelled). Supports LIFECYCLE_STATUS requirement for TRANSACTION_HEADER role.. Valid values are `preliminary|final|restated|voided`',
    CONSTRAINT pk_account_value PRIMARY KEY(`account_value_id`)
) COMMENT 'Authoritative periodic valuation ledger and contract valuation snapshot for each annuity contract, capturing the full financial position at each valuation date (daily, monthly, quarterly, annually). Records beginning-of-period and ending-of-period Account Value (AV), net premiums applied, withdrawals deducted, COI charges, rider charges, credited interest, index credits (FIA), sub-account performance (variable), surrender value (CSV), death benefit amount, GMDB value, GMWB/GMIB/GMAB benefit base snapshots, net amount at risk (NAR) for each guarantee, accrued rider charges, and statutory reserve estimate. Serves as the single source of truth for ALL annuity contract valuations and periodic valuation snapshots (subsumes contract_valuation), supporting policyholder annual statements, ALM, actuarial reserving (LDTI/IFRS 17), valuation cycle feeds, and regulatory reporting.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`benefit_base` (
    `benefit_base_id` BIGINT COMMENT 'Unique surrogate identifier for the guaranteed benefit base record associated with a living benefit rider on an annuity contract. Primary key for this entity.',
    `annuitant_id` BIGINT COMMENT 'Foreign key linking to policyholder.annuitant. Business justification: GMWB/GMIB/GMAB living benefit administration requires the annuitants age for guaranteed withdrawal rate determination, step-up eligibility, and roll-up period calculations. benefit_base tracks owner_',
    `assumption_set_id` BIGINT COMMENT 'Foreign key linking to actuarial.assumption_set. Business justification: Living benefit (GMWB/GMIB/GMAB) benefit base net amount at risk drives rider reserve calculations. The assumption set (lapse, utilization, mortality) used for those reserves must be traceable from the',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract to which this benefit base and living benefit rider are attached. Links the benefit base to the parent annuity contract record.',
    `gaap_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.gaap_reserve. Business justification: Benefit base values (GMWB, GMIB, GMAB, GMDB) are the primary inputs to LDTI/GAAP MRB fair value reserve calculations. Actuaries and finance teams must link each benefit base record to its GAAP reserve',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Living benefit riders (GMWB, GMIB, GMAB) create market risk hedged via derivative portfolios. Actuarial teams calculate net amount at risk, hedge effectiveness (ASC 815), and RBC C3 charges by linking',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Living benefit riders (GMWB/GMIB/GMAB) have version-specific roll-up rates, step-up provisions, and guaranteed withdrawal rates. Essential for benefit base calculations, rider charge assessments, and ',
    `rider_benefit_id` BIGINT COMMENT 'Foreign key linking to annuity.rider_benefit. Business justification: benefit_base manages the guaranteed benefit base amounts for living benefit riders (GMWB, GMIB, GMAB). rider_benefit is the master record for each optional rider attached to an annuity contract. A ben',
    `rider_id` BIGINT COMMENT 'Reference to the specific living benefit rider (GMWB, GMIB, or GMAB) attached to the annuity contract that governs this benefit base record.',
    `statutory_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.statutory_reserve. Business justification: Benefit base amounts drive CARVM/PBR statutory reserve calculations for living benefit riders. State regulators require insurers to demonstrate reserve adequacy at the benefit base level; statutory ac',
    `valuation_run_id` BIGINT COMMENT 'Foreign key linking to actuarial.valuation_run. Business justification: Benefit base values (GMWB, GMIB, GMAB) are calculated during actuarial valuation runs. Regulatory reserve reporting requires tracing benefit base amounts to the specific valuation run that produced th',
    `annual_guaranteed_withdrawal` DECIMAL(18,2) COMMENT 'For GMWB riders, the maximum dollar amount the contract owner may withdraw annually while maintaining the guaranteed benefit base. Calculated as the benefit base multiplied by the guaranteed withdrawal rate. Recalculated upon step-up events.',
    `benefit_base_number` STRING COMMENT 'Externally-known alphanumeric identifier for the benefit base record, used in policyholder statements, actuarial reports, and regulatory filings. Typically derived from the contract number with a rider suffix.',
    `benefit_base_status` STRING COMMENT 'Current lifecycle state of the benefit base. Active = benefit base is in force and accumulating or being drawn down; Suspended = temporarily inactive due to excess withdrawal or contract lapse; Exhausted = benefit base has been fully depleted; Terminated = rider has been surrendered or cancelled; Annuitized = contract has entered payout phase under GMIB election.. Valid values are `active|suspended|exhausted|terminated|annuitized`',
    `benefit_election_status` STRING COMMENT 'Indicates whether the contract owner has formally elected to begin receiving guaranteed benefits under the rider. Not Elected = owner has not yet begun taking guaranteed withdrawals or income; Elected = owner is actively receiving guaranteed withdrawals (GMWB) or income (GMIB); Annuitized = contract has been annuitized under GMIB; Exhausted = benefit base depleted.. Valid values are `not_elected|elected|annuitized|exhausted`',
    `contract_anniversary_date` DATE COMMENT 'The most recent contract anniversary date, used as the reference point for automatic step-up evaluation, roll-up credit application, and annual rider charge assessment. Derived from the contract issue date but stored here for operational processing efficiency.',
    `cumulative_withdrawals` DECIMAL(18,2) COMMENT 'The total dollar amount of withdrawals that have been charged against the benefit base since rider inception. Used to track benefit base depletion and determine remaining guaranteed withdrawal capacity. Excess withdrawals beyond the annual guaranteed amount reduce the benefit base proportionally.',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which all benefit base monetary amounts are denominated (e.g., USD). Required for multi-currency annuity platforms and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `current_benefit_base` DECIMAL(18,2) COMMENT 'The current guaranteed benefit base balance as of the most recent valuation date, reflecting all roll-up credits, step-up elections, and withdrawal reductions applied since inception. This is the principal amount used to calculate the guaranteed withdrawal or income benefit. Critical for actuarial reserving under LDTI and IFRS 17.',
    `excess_withdrawal_flag` BOOLEAN COMMENT 'Indicates whether the contract owner has taken a withdrawal in excess of the annual guaranteed withdrawal amount in the current or any prior contract year. An excess withdrawal triggers a proportional reduction of the benefit base rather than a dollar-for-dollar reduction, and may reset or suspend certain rider provisions.',
    `first_withdrawal_date` DATE COMMENT 'The date on which the contract owner first took a withdrawal against the benefit base, triggering the transition from the accumulation phase to the distribution phase. Null if no withdrawals have been taken. Marks the end of the roll-up credit period for most product designs.',
    `gmab_guaranteed_floor` DECIMAL(18,2) COMMENT 'For GMAB riders, the minimum Account Value guaranteed at the GMAB maturity date. If the actual AV at maturity is below this floor, the insurer credits the difference to the contract. Null for GMWB and GMIB riders. Key input for LDTI and IFRS 17 reserve calculations.',
    `gmab_maturity_date` DATE COMMENT 'For GMAB riders, the contractually defined date on which the guaranteed minimum accumulation amount becomes payable if the contract Account Value is below the guaranteed floor. Null for GMWB and GMIB riders. Triggers actuarial reserve strengthening as the maturity date approaches.',
    `gmib_annuitization_rate` DECIMAL(18,2) COMMENT 'For GMIB riders, the guaranteed annuitization rate (expressed as a decimal income factor per dollar of benefit base) used to convert the benefit base into a guaranteed lifetime income stream upon GMIB election. Null for GMWB and GMAB riders. Locked in at rider inception regardless of prevailing interest rates at annuitization.',
    `gmib_eligible_date` DATE COMMENT 'For GMIB riders, the earliest date on which the contract owner may elect to annuitize under the GMIB guarantee. Derived from inception date plus the GMIB waiting period. Null for GMWB and GMAB riders. Used in benefit election processing and policyholder communications.',
    `gmib_waiting_period_years` STRING COMMENT 'For GMIB riders, the minimum number of contract years that must elapse before the contract owner is eligible to elect the GMIB annuitization option. Typically 10 years. Null for GMWB and GMAB riders.',
    `guaranteed_withdrawal_rate` DECIMAL(18,2) COMMENT 'For GMWB riders, the contractually guaranteed annual withdrawal percentage applied to the benefit base to determine the maximum guaranteed annual withdrawal amount. Expressed as a decimal (e.g., 0.050000 for 5%). May vary by age band at first withdrawal election.',
    `in_the_money_flag` BOOLEAN COMMENT 'Indicates whether the living benefit guarantee is currently in-the-money, meaning the benefit base exceeds the contract Account Value (AV). True = guarantee is in-the-money (NAR > 0); False = guarantee is out-of-the-money (AV >= benefit base). Used for actuarial triage, reserve prioritization, and risk management reporting.',
    `inception_date` DATE COMMENT 'The date on which the living benefit rider and its associated benefit base became effective on the annuity contract. Marks the start of the benefit base accumulation or guarantee period. Used as the anchor date for roll-up credit calculations.',
    `inception_value` DECIMAL(18,2) COMMENT 'The initial guaranteed benefit base amount established at rider inception, typically equal to the contract Account Value (AV) at the time the rider was issued or the premium amount for a single-premium contract. Serves as the floor for step-up and roll-up calculations.',
    `last_step_up_date` DATE COMMENT 'The most recent date on which the benefit base was stepped up to the contract Account Value under the step-up provision. Null if no step-up has occurred since inception. Used to track step-up history and determine eligibility for future step-ups.',
    `last_step_up_value` DECIMAL(18,2) COMMENT 'The benefit base amount recorded at the time of the most recent step-up event. Provides an audit trail of the step-up history and supports actuarial analysis of step-up frequency and magnitude.',
    `max_anniversary_value` DECIMAL(18,2) COMMENT 'The highest contract Account Value (AV) recorded on any contract anniversary date since rider inception. Used as the step-up candidate value in automatic anniversary step-up provisions. The benefit base is stepped up to the MAV if it exceeds the current benefit base.',
    `net_amount_at_risk` DECIMAL(18,2) COMMENT 'The excess of the current benefit base over the contract Account Value (AV), representing the insurers current financial exposure on the living benefit guarantee. A positive NAR indicates the guarantee is in-the-money. Critical input for actuarial reserving under LDTI, IFRS 17, and RBC calculations.',
    `owner_age_at_first_withdrawal` STRING COMMENT 'The age of the contract owner (in whole years) at the time of the first withdrawal from the benefit base. Determines the applicable guaranteed withdrawal rate tier for age-banded GMWB products. Null if no withdrawals have been taken.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this benefit base record was first created in the data platform, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements under SOX and state insurance department data retention regulations.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this benefit base record was most recently updated in the data platform, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for incremental ETL processing and change data capture in the Databricks Silver Layer.',
    `rider_charge_basis` STRING COMMENT 'Indicates whether the annual rider charge is assessed as a percentage of the benefit base or the contract Account Value (AV). Benefit Base = charge applied to the guaranteed benefit base amount; Account Value = charge applied to the current AV. Affects the charge amount when AV diverges from the benefit base.. Valid values are `benefit_base|account_value`',
    `rider_charge_rate` DECIMAL(18,2) COMMENT 'The annual fee rate charged for the living benefit rider, expressed as a decimal applied to the benefit base (e.g., 0.010000 for 1.00% per annum). Deducted from the contract Account Value periodically. Used in product profitability analysis and policyholder cost disclosure.',
    `rider_expiry_date` DATE COMMENT 'The date on which the living benefit rider and its associated benefit base guarantee period ends, if applicable. Null for riders with no fixed expiry. Relevant for GMAB riders with a defined accumulation period end date.',
    `rider_type` STRING COMMENT 'Classification of the living benefit rider governing this benefit base. GMWB = Guaranteed Minimum Withdrawal Benefit; GMIB = Guaranteed Minimum Income Benefit; GMAB = Guaranteed Minimum Accumulation Benefit; GMDB = Guaranteed Minimum Death Benefit. Determines the benefit calculation methodology applied.. Valid values are `GMWB|GMIB|GMAB|GMDB`',
    `roll_up_credits_inception_to_date` DECIMAL(18,2) COMMENT 'The total cumulative dollar amount of guaranteed roll-up credits applied to the benefit base from rider inception through the current valuation date. Key metric for actuarial cost-of-guarantee analysis and LDTI/IFRS 17 reserve adequacy assessment.',
    `roll_up_credits_ytd` DECIMAL(18,2) COMMENT 'The cumulative dollar amount of guaranteed roll-up credits applied to the benefit base in the current contract year. Resets at each contract anniversary. Used for in-force management reporting and actuarial experience studies.',
    `roll_up_end_date` DATE COMMENT 'The calendar date on which the guaranteed roll-up credit period expires for this benefit base. Derived from the inception date plus the roll-up period in years, but stored explicitly for operational processing and actuarial projection.',
    `roll_up_period_years` STRING COMMENT 'The maximum number of contract years during which the guaranteed roll-up rate is applied to grow the benefit base. After this period expires, the benefit base no longer accrues roll-up credits. Common values are 10 or 20 years depending on product design.',
    `roll_up_rate` DECIMAL(18,2) COMMENT 'The contractually guaranteed annual percentage rate at which the benefit base grows during the accumulation phase, expressed as a decimal (e.g., 0.060000 for 6%). Applied to the benefit base each year regardless of actual contract Account Value performance. Ceases upon first withdrawal or at the end of the roll-up period.',
    `source_system_code` STRING COMMENT 'Code identifying the operational annuity administration system from which this benefit base record was sourced (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Supports data lineage tracking and ETL reconciliation in the Databricks Silver Layer.',
    `step_up_count` STRING COMMENT 'The cumulative number of step-up events that have occurred on this benefit base since rider inception. Used in actuarial experience studies and product profitability analysis.',
    `step_up_provision` STRING COMMENT 'Indicates the type of step-up provision available under the rider. Automatic Anniversary = benefit base is automatically stepped up to the contract AV on each anniversary if AV exceeds current benefit base; Owner Elected = policyholder must actively elect a step-up; None = no step-up provision available.. Valid values are `automatic_anniversary|owner_elected|none`',
    `valuation_date` DATE COMMENT 'The most recent date as of which the benefit base values (current benefit base, cumulative withdrawals, roll-up credits) were calculated and recorded. Aligns with the actuarial valuation cycle for LDTI and IFRS 17 reserving.',
    CONSTRAINT pk_benefit_base PRIMARY KEY(`benefit_base_id`)
) COMMENT 'Manages the guaranteed benefit base amounts for living benefit riders attached to annuity contracts, including GMWB (Guaranteed Minimum Withdrawal Benefit), GMIB (Guaranteed Minimum Income Benefit), and GMAB (Guaranteed Minimum Accumulation Benefit). Tracks benefit base inception value, step-up events, roll-up credits, maximum anniversary value, current benefit base balance, rider charge rate, and benefit base type. Critical for actuarial reserving under LDTI and IFRS 17 and for benefit calculation at claim time.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`withdrawal_transaction` (
    `withdrawal_transaction_id` BIGINT COMMENT 'Unique surrogate identifier for each withdrawal transaction or systematic withdrawal plan (SWP) instruction record. Primary key for the withdrawal_transaction data product.',
    `account_id` BIGINT COMMENT 'Foreign key linking to billing.billing_account. Business justification: Withdrawal disbursements are processed through billing accounts containing bank routing and account information. Real business process: payment disbursement, ACH/wire processing, 1099-R tax reporting ',
    `aml_case_id` BIGINT COMMENT 'Foreign key linking to compliance.aml_case. Business justification: Large or structured withdrawals trigger AML monitoring per BSA requirements. Links suspicious withdrawal patterns to AML case investigations. Required for SAR filing and transaction monitoring rule va',
    `benefit_base_id` BIGINT COMMENT 'Foreign key linking to annuity.benefit_base. Business justification: withdrawal_transaction captures gmwb_benefit_base_before and gmwb_benefit_base_after, indicating the transaction directly affects a GMWB benefit_base record. Linking withdrawal_transaction to the spec',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract against which this withdrawal transaction or SWP instruction is recorded. Links to the annuity contract master record.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Withdrawals generate journal entries for cash disbursement (credit), surrender charge revenue (credit), tax withholding liability (credit), and account value reduction (debit). Direct GL posting requi',
    `party_id` BIGINT COMMENT 'Reference to the annuity contract owner (policyholder) who authorized or is associated with this withdrawal transaction. Required for tax reporting and KYC compliance.',
    `rmd_schedule_id` BIGINT COMMENT 'Foreign key linking to annuity.rmd_schedule. Business justification: withdrawal_transaction has is_rmd_coordinated and rmd_amount fields indicating RMD-coordinated withdrawals. When a withdrawal satisfies an RMD obligation, it must reference the rmd_schedule that gover',
    `sar_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.sar_filing. Business justification: BSA/AML regulations require SAR filings for suspicious withdrawal transactions. withdrawal_transaction needs a direct sar_filing_id to support the SAR reporting workflow — distinct from benefit_paymen',
    `surrender_charge_id` BIGINT COMMENT 'Foreign key linking to annuity.surrender_charge. Business justification: withdrawal_transaction captures surrender_charge_amount and surrender_charge_rate for withdrawals that incur surrender charges. surrender_charge holds the schedule and rate table governing those charg',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Withdrawal requests require a signed withdrawal request form retained per transaction for audit and regulatory compliance. Operations must link the executed document to the transaction record to satis',
    `account_value_after` DECIMAL(18,2) COMMENT 'The annuity contracts Account Value (AV) immediately after this withdrawal transaction has been applied. Confirms the post-withdrawal contract value for owner statements, benefit base recalculation, and subsequent transaction processing.',
    `account_value_before` DECIMAL(18,2) COMMENT 'The annuity contracts Account Value (AV) immediately prior to this withdrawal transaction being applied. Used for surrender charge calculation, benefit base adjustments, and reconciliation of AV movement.',
    `bank_account_last4` STRING COMMENT 'Last four digits of the owners bank account number used for ACH or direct deposit disbursement of withdrawal proceeds. Stored in masked format for security compliance. Full account details are maintained in the EFT authorization record.. Valid values are `^[0-9]{4}$`',
    `bank_routing_number` STRING COMMENT 'The 9-digit ABA routing transit number of the financial institution receiving the withdrawal proceeds via ACH or wire transfer. Required for electronic disbursement processing.. Valid values are `^[0-9]{9}$`',
    `cost_basis_recovered_amount` DECIMAL(18,2) COMMENT 'The non-taxable portion of the withdrawal representing return of the owners after-tax investment (cost basis) in the annuity contract under IRC Section 72. Reduces the remaining cost basis tracked on the contract.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this withdrawal transaction record was first created in the annuity administration system. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this withdrawal transaction. Typically USD for domestic US annuity contracts. Required for the MONETARY_TRIPLET and multi-currency reporting.. Valid values are `^[A-Z]{3}$`',
    `distribution_code` STRING COMMENT 'IRS-defined distribution code reported in Box 7 of Form 1099-R indicating the nature of the distribution for tax purposes. Common codes: 1=early distribution no exception; 2=early distribution exception applies; 3=disability; 4=death; 7=normal distribution; D=annuity payments from non-qualified annuity; Q=qualified distribution from Roth IRA. [ENUM-REF-CANDIDATE: 1|2|3|4|7|D|Q|G|L|M|N|P|R|S|T|U|W — promote to reference product]',
    `effective_date` DATE COMMENT 'The contractual effective date on which the withdrawal is applied to the annuity contracts Account Value (AV). This is the valuation date used for surrender charge calculation, MVA adjustment, and 1099-R tax year determination. May differ from request_date due to processing cycles or market close timing.',
    `federal_tax_withheld_amount` DECIMAL(18,2) COMMENT 'Dollar amount of federal income tax withheld from this withdrawal per the owners withholding election or mandatory withholding rules under IRC Section 3405. Reported on IRS Form 1099-R Box 4.',
    `federal_withholding_election` STRING COMMENT 'The contract owners federal income tax withholding election for this withdrawal. withhold = owner elected voluntary withholding; do_not_withhold = owner opted out of withholding; mandatory = mandatory withholding applies (e.g., eligible rollover distributions). Governs IRS Form W-4P compliance.. Valid values are `withhold|do_not_withhold|mandatory`',
    `free_withdrawal_amount` DECIMAL(18,2) COMMENT 'The contractual free withdrawal allowance amount available for the current contract year, typically 10% of Account Value (AV) or accumulated premiums, within which no surrender charge applies. Used to determine the surrender-charge-free portion of this withdrawal.',
    `gmwb_benefit_base_after` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Withdrawal Benefit (GMWB) benefit base amount immediately after this withdrawal has been applied. Reflects any proportional reduction due to excess withdrawal above the contractual GMWB annual withdrawal amount.',
    `gmwb_benefit_base_before` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Withdrawal Benefit (GMWB) benefit base amount immediately prior to this withdrawal. Excess withdrawals above the GMWB annual withdrawal amount reduce the benefit base proportionally. Required for variable and indexed annuity contracts with GMWB riders.',
    `gross_amount` DECIMAL(18,2) COMMENT 'The total gross dollar amount of the withdrawal before deduction of surrender charges, Market Value Adjustment (MVA), and tax withholding. Represents the amount deducted from the contracts Account Value (AV). Core monetary field for the MONETARY_TRIPLET.',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether this withdrawal is part of a tax-free 1035 Exchange (IRC Section 1035) where proceeds are being transferred directly to another annuity or life insurance contract. True = 1035 exchange; proceeds are not taxable to the owner at time of withdrawal.',
    `is_excess_withdrawal` BOOLEAN COMMENT 'Indicates whether this withdrawal exceeds the contractual GMWB or GMIB annual withdrawal amount, triggering a proportional reduction of the guaranteed benefit base. True = excess withdrawal occurred; False = withdrawal is within the guaranteed annual withdrawal amount.',
    `is_rmd_coordinated` BOOLEAN COMMENT 'Indicates whether this withdrawal is coordinated with the contracts Required Minimum Distribution (RMD) calculation under IRC Section 401(a)(9). True = RMD coordination is active and this withdrawal satisfies or partially satisfies the annual RMD obligation. Applicable to qualified annuity contracts.',
    `is_within_free_withdrawal` BOOLEAN COMMENT 'Indicates whether the entire gross withdrawal amount falls within the contractual free withdrawal allowance corridor and therefore no surrender charge was applied. True = fully within free withdrawal; False = surrender charge applies to some or all of the withdrawal.',
    `mva_adjustment_amount` DECIMAL(18,2) COMMENT 'Dollar amount of the Market Value Adjustment (MVA) applied to this withdrawal. Can be positive (in owners favor when interest rates have fallen) or negative (charge when rates have risen). Applicable only to fixed annuity contracts with MVA provisions. Zero if not applicable.',
    `net_proceeds_amount` DECIMAL(18,2) COMMENT 'Net dollar amount disbursed to the contract owner after deducting surrender charges, MVA adjustment, and federal/state tax withholding from the gross withdrawal amount. Represents the actual cash received by the owner. Core monetary field for the MONETARY_TRIPLET.',
    `payment_method` STRING COMMENT 'The disbursement method used to deliver net withdrawal proceeds to the contract owner. ach = Automated Clearing House electronic funds transfer; check = paper check mailed to owner; wire = wire transfer; direct_deposit = direct deposit to owners bank account; 1035_transfer = direct transfer to receiving carrier for 1035 exchange.. Valid values are `ach|check|wire|direct_deposit|1035_transfer`',
    `processed_timestamp` TIMESTAMP COMMENT 'The precise date and time when the withdrawal transaction was executed and posted to the annuity contract in the administration system. Serves as the principal business event timestamp for audit, reconciliation, and regulatory reporting.',
    `request_date` DATE COMMENT 'Calendar date on which the withdrawal request was received from the contract owner or their authorized representative. Establishes the business event initiation date for processing, valuation, and regulatory timing purposes.',
    `rmd_amount` DECIMAL(18,2) COMMENT 'The calculated Required Minimum Distribution (RMD) amount for the current tax year applicable to this annuity contract under IRC Section 401(a)(9). Populated when is_rmd_coordinated is True. Used to ensure the withdrawal satisfies the minimum distribution requirement and avoid IRS excise tax penalties.',
    `source_system_code` STRING COMMENT 'Identifies the operational annuity administration system that originated this withdrawal transaction record. sapiens_annuity = Sapiens Annuity platform; fast_annuity = FAST Annuity platform. Required for data lineage, reconciliation, and ETL audit in the Databricks Silver Layer.. Valid values are `sapiens_annuity|fast_annuity`',
    `state_tax_withheld_amount` DECIMAL(18,2) COMMENT 'Dollar amount of state income tax withheld from this withdrawal per the owners state withholding election or mandatory state withholding requirements. Reported on IRS Form 1099-R Box 14.',
    `state_withholding_state_code` STRING COMMENT 'Two-letter US state code identifying the state for which income tax withholding was applied on this withdrawal. Determines applicable state withholding rates and mandatory withholding rules. Aligns with the owners state of residence.. Valid values are `^[A-Z]{2}$`',
    `surrender_charge_amount` DECIMAL(18,2) COMMENT 'Dollar amount of the contingent deferred sales charge (CDSC) or surrender charge applied to this withdrawal. Calculated based on the contracts surrender charge schedule and the amount withdrawn in excess of the free withdrawal allowance. Zero if within free withdrawal corridor.',
    `surrender_charge_rate` DECIMAL(18,2) COMMENT 'The applicable surrender charge rate (as a decimal, e.g., 0.07 = 7%) applied to the excess withdrawal amount above the free withdrawal allowance. Derived from the contracts contingent deferred sales charge (CDSC) schedule for the current surrender charge year.',
    `surrender_charge_year` STRING COMMENT 'The contract year number within the surrender charge schedule at the time of this withdrawal. Determines the applicable surrender charge rate percentage per the contracts CDSC schedule. For example, year 1 may carry a 7% charge, declining to 0% by year 8.',
    `swp_amount_type` STRING COMMENT 'Specifies whether the SWP disbursement is a fixed dollar amount, a percentage of the current Account Value (AV), or a system-calculated RMD amount. Drives the withdrawal amount calculation logic in the annuity administration platform.. Valid values are `fixed_dollar|percentage_of_av|rmd_calculated`',
    `swp_end_date` DATE COMMENT 'The date on which the Systematic Withdrawal Plan (SWP) instruction is scheduled to terminate or was terminated. Null if the SWP is open-ended (e.g., lifetime income or until contract exhaustion). Populated for fixed-duration SWP plans.',
    `swp_frequency` STRING COMMENT 'The payment frequency of the Systematic Withdrawal Plan (SWP) instruction. Applicable when withdrawal_type is systematic. Determines the schedule on which recurring withdrawals are processed from the annuity contract.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `swp_start_date` DATE COMMENT 'The date on which the Systematic Withdrawal Plan (SWP) instruction became effective and the first scheduled withdrawal was processed. Establishes the SWP plan inception date for scheduling and anniversary calculations.',
    `swp_status` STRING COMMENT 'Current status of the Systematic Withdrawal Plan (SWP) instruction associated with this transaction. active = SWP is running per schedule; suspended = temporarily halted by owner request; terminated = SWP permanently stopped; pending_setup = SWP instruction received but not yet activated.. Valid values are `active|suspended|terminated|pending_setup`',
    `taxable_amount` DECIMAL(18,2) COMMENT 'The portion of the gross withdrawal amount that is taxable as ordinary income under IRC Section 72, reported on IRS Form 1099-R Box 2a. Equals gross amount minus the non-taxable cost basis (investment in contract) recovered in this withdrawal.',
    `transaction_number` STRING COMMENT 'Externally visible, human-readable transaction reference number assigned by the annuity administration platform (Sapiens Annuity or FAST Annuity) at the time of withdrawal processing. Used for customer correspondence, audit trails, and reconciliation.',
    `transaction_status` STRING COMMENT 'Current lifecycle state of the withdrawal transaction or SWP instruction. pending = request received but not yet processed; in_process = funds movement initiated; completed = disbursement confirmed; reversed = transaction unwound; cancelled = request voided before processing; suspended = SWP plan temporarily halted.. Valid values are `pending|in_process|completed|reversed|cancelled|suspended`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this withdrawal transaction record in the annuity administration system. Supports change tracking, reconciliation, and audit compliance.',
    `withdrawal_type` STRING COMMENT 'Classification of the withdrawal event. systematic = scheduled SWP disbursement; ad_hoc = owner-initiated one-time withdrawal; rmd = Required Minimum Distribution (RMD) mandated under IRC Section 401(a)(9); full_surrender = complete contract liquidation; partial_surrender = partial contract liquidation with surrender charge; free_withdrawal = withdrawal within the contractual free withdrawal allowance.. Valid values are `systematic|ad_hoc|rmd|full_surrender|partial_surrender|free_withdrawal`',
    CONSTRAINT pk_withdrawal_transaction PRIMARY KEY(`withdrawal_transaction_id`)
) COMMENT 'Records all withdrawal events and manages standing systematic withdrawal plan (SWP) instructions against annuity contracts — serving as the single source of truth for ALL withdrawal activity, both ad-hoc and systematic (subsumes systematic_withdrawal_plan). For individual withdrawals: captures withdrawal request date, effective date, gross amount, surrender charge applied, MVA adjustment, net proceeds, withdrawal type (systematic, ad-hoc, RMD, full surrender), tax withholding, 1099-R reportable amount, and free withdrawal allowance status. For SWP plans: captures plan start date, frequency, amount or percentage, end date or duration, tax withholding elections (federal and state), payment method and banking instructions, RMD coordination flag, plan status, and SWP suspension/reinstatement history. Sourced from Sapiens Annuity and FAST Annuity withdrawal processing modules.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`rmd_schedule` (
    `rmd_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each RMD schedule record within the annuity administration platform. Primary key for the rmd_schedule data product.',
    `annuitant_id` BIGINT COMMENT 'Foreign key linking to policyholder.annuitant. Business justification: IRS RMD rules require the annuitants date of birth and life expectancy for distribution period calculation. rmd_schedule already has party_id but annuitant holds annuity-specific demographics (issue_',
    `contract_id` BIGINT COMMENT 'Reference to the qualified annuity contract for which this RMD schedule is maintained. Links the RMD obligation to the underlying annuity contract in the Annuity Administration Platform.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: RMD distributions generate journal entries for federal/state tax withholding remittances and distribution accounting. Finance teams reconcile RMD payment amounts to GL postings for IRS Form 945 withho',
    `mortality_table_id` BIGINT COMMENT 'Foreign key linking to actuarial.mortality_table. Business justification: RMD calculations use IRS life expectancy tables (Uniform Lifetime, Single Life, Joint Life) which are mortality tables. Required for accurate RMD calculation, IRS compliance, and audit trail of which ',
    `party_id` BIGINT COMMENT 'Reference to the annuity contract owner (policyholder) who is subject to the RMD obligation. The owners age and applicable IRS life expectancy table are derived from this party record.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: IRC 401(a)(9) requires annual RMD notices be sent to contract owners. The rmd_schedule drives notice generation; linking the issued notice document to the schedule enables regulatory proof of timely n',
    `aggregation_group_code` STRING COMMENT 'Identifier grouping multiple IRA or annuity contracts owned by the same individual for RMD aggregation purposes. IRS rules permit owners to aggregate RMDs across multiple IRAs and satisfy the total from one or more accounts. Used for cross-contract RMD satisfaction tracking and IRS Form 5498 reporting.',
    `april_1_deferral_elected` BOOLEAN COMMENT 'Indicates whether the contract owner has elected to defer the first-year RMD to April 1 of the following calendar year as permitted by IRS rules. Applicable only when first_rmd_year_flag is True. When True, the rmd_due_date is set to April 1 of the year following the first RMD year.',
    `beneficiary_age_at_rmd_year` STRING COMMENT 'Age of the designated beneficiary (typically spouse) as of their birthday in the RMD calculation year. Required only when the Joint and Last Survivor Table is applicable (sole beneficiary is a spouse more than 10 years younger than the owner). Null when Uniform Lifetime or Single Life tables are used.',
    `calculated_rmd_amount` DECIMAL(18,2) COMMENT 'The gross RMD amount calculated for the calendar year, derived by dividing the prior year-end Account Value (AV) by the applicable IRS distribution period factor. This is the minimum amount the contract owner must withdraw to satisfy IRS RMD requirements and avoid the IRC Section 4974 excise tax.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this RMD schedule record was first created in the data platform. Supports audit trails, data lineage, and Silver Layer record management. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `distribution_period` DECIMAL(18,2) COMMENT 'The life expectancy factor (in years) retrieved from the applicable IRS life expectancy table for the owners age (and beneficiarys age if Joint table applies) in the RMD year. This divisor is applied to the prior year-end account value to compute the RMD amount. Updated per SECURE Act 2.0 tables effective 2022.',
    `excise_tax_exposure_amount` DECIMAL(18,2) COMMENT 'The dollar amount of the potential IRS excise tax exposure under IRC Section 4974 if the RMD is not fully satisfied by the due date. Calculated as 25% of the remaining_rmd_balance (reduced to 10% if corrected within the correction window under SECURE Act 2.0). Supports proactive owner outreach and compliance risk management.',
    `first_rmd_year_flag` BOOLEAN COMMENT 'Indicates whether this is the first calendar year in which the contract owner is subject to RMD requirements. When True, the owner may elect to defer the first RMD to April 1 of the following year per IRS rules, which may result in two RMDs being taken in the same calendar year.',
    `form_1099r_issued_flag` BOOLEAN COMMENT 'Indicates whether IRS Form 1099-R (Distributions From Pensions, Annuities, Retirement or Profit-Sharing Plans) has been issued to the contract owner for distributions taken toward the RMD in the calendar year. Supports tax reporting compliance and owner communication.',
    `form_5498_report_date` DATE COMMENT 'The date on which the IRS Form 5498 reporting the RMD obligation was filed or transmitted to the IRS. Null if form_5498_reported_flag is False. Supports tax reporting audit trails.',
    `form_5498_reported_flag` BOOLEAN COMMENT 'Indicates whether the RMD obligation for this calendar year has been reported to the IRS on Form 5498 (IRA Contribution Information), which requires insurers to report the RMD amount and indicate that an RMD is required for the year. Supports IRS tax reporting compliance.',
    `inherited_contract_flag` BOOLEAN COMMENT 'Indicates whether the annuity contract is an inherited (beneficiary) contract subject to the IRS 10-year rule or life expectancy payout rules under SECURE Act 2.0. When True, the Single Life Expectancy Table and beneficiary-specific RMD rules apply.',
    `notification_method` STRING COMMENT 'The channel through which the RMD notification was delivered to the contract owner. suppressed indicates the owner opted out of notifications or the notification was withheld for a documented reason.. Valid values are `mail|email|portal|phone|suppressed`',
    `original_owner_dod` DATE COMMENT 'The date of death of the original annuity contract owner, applicable when inherited_contract_flag is True. Determines the commencement of the beneficiarys RMD obligation and the applicable distribution rules under SECURE Act 2.0 (10-year rule vs. life expectancy payout).',
    `owner_age_at_rmd_year` STRING COMMENT 'The age of the annuity contract owner as of their birthday in the RMD calculation year. Used to look up the applicable distribution period from the IRS life expectancy table. Per IRS rules, age is determined as of the owners birthday in the distribution year.',
    `owner_notification_date` DATE COMMENT 'The date on which the contract owner was notified of their RMD obligation and calculated amount for the calendar year. IRS regulations require insurers to notify IRA owners of their RMD amount by January 31 of the distribution year. Supports regulatory compliance tracking.',
    `prior_calculated_rmd_amount` DECIMAL(18,2) COMMENT 'The RMD amount from the most recent prior calculation before the current recalculation. Populated only when recalculation_flag is True. Supports audit trails and change management for IRS reporting.',
    `prior_year_end_av` DECIMAL(18,2) COMMENT 'The Account Value (AV) of the annuity contract as of December 31 of the year immediately preceding the RMD calculation year. This is the IRS-mandated valuation date for RMD calculation purposes. Sourced from the Annuity Administration Platforms end-of-year account value snapshot.',
    `prior_year_end_av_date` DATE COMMENT 'The specific date on which the prior year-end Account Value (AV) was captured for RMD calculation purposes. Should be December 31 of the prior year. Recorded explicitly to support audit trails and IRS Form 5498 reporting.',
    `qualified_plan_type` STRING COMMENT 'The type of qualified retirement plan or IRA under which the annuity contract is held, which determines the applicable RMD rules, tax treatment, and reporting requirements. [ENUM-REF-CANDIDATE: traditional_ira|sep_ira|simple_ira|401k|403b|457b|inherited_ira — promote to reference product]',
    `recalculation_flag` BOOLEAN COMMENT 'Indicates whether the RMD amount for this calendar year has been recalculated after the initial calculation, typically due to a correction in the prior year-end account value, a change in the applicable life expectancy table, or a data correction. When True, recalculation_reason should be populated.',
    `recalculation_reason` STRING COMMENT 'Free-text description of the reason the RMD was recalculated for the calendar year. Applicable only when recalculation_flag is True. Examples include account value restatement, beneficiary designation change, table correction, or data quality remediation.',
    `remaining_rmd_balance` DECIMAL(18,2) COMMENT 'The outstanding RMD amount still required to be distributed to satisfy the IRS obligation for the calendar year. Computed as calculated_rmd_amount minus ytd_distributions_applied. A zero or negative value indicates the RMD has been satisfied. Used for proactive owner notifications and IRS compliance monitoring.',
    `rmd_calculation_date` DATE COMMENT 'The date on which the RMD amount was calculated by the Annuity Administration Platform for the given calendar year. Supports audit trails and recalculation tracking when account values are restated or corrected.',
    `rmd_due_date` DATE COMMENT 'The IRS deadline by which the RMD must be fully distributed to avoid the IRC Section 4974 excise tax. For most owners, this is December 31 of the RMD year. For the first RMD year (the year the owner reaches the applicable RMD age), the deadline may be extended to April 1 of the following year per IRS rules.',
    `rmd_satisfied_date` DATE COMMENT 'The date on which the RMD obligation for the calendar year was fully satisfied (i.e., cumulative distributions reached or exceeded the calculated RMD amount). Null if the RMD has not yet been satisfied. Used for IRS Form 1099-R reporting and compliance monitoring.',
    `rmd_start_age` STRING COMMENT 'The IRS-mandated age at which the contract owner is required to begin taking RMDs from the qualified annuity. Reflects the applicable RMD age under current law (e.g., age 73 under SECURE Act 2.0 for owners born 1951–1959; age 75 for owners born 1960 or later). Stored to support historical accuracy as legislation changes.',
    `rmd_status` STRING COMMENT 'Current lifecycle status of the RMD obligation for the given calendar year. pending = RMD calculated but no distributions taken; in_progress = partial distributions applied; satisfied = full RMD amount distributed; waived = IRS-approved waiver applied (e.g., first-year RMD deferral); overdue = due date passed without satisfaction; cancelled = contract no longer subject to RMD (e.g., annuitized, surrendered).. Valid values are `pending|in_progress|satisfied|waived|overdue|cancelled`',
    `rmd_year` STRING COMMENT 'The calendar year (YYYY) for which this RMD obligation applies. Each qualified annuity contract generates one RMD schedule record per applicable calendar year. Determines the December 31 prior-year account value snapshot used in the RMD calculation.',
    `source_system_code` STRING COMMENT 'The identifier of the operational source system record from which this RMD schedule was originated or last updated (e.g., Sapiens Annuity contract ID, FAST Annuity record key). Supports data lineage, reconciliation, and ETL audit trails in the Databricks Silver Layer.',
    `systematic_rmd_flag` BOOLEAN COMMENT 'Indicates whether the contract owner is enrolled in the annuity platforms automatic systematic RMD distribution program, which automatically calculates and distributes the RMD amount on a scheduled basis (monthly, quarterly, or annually) to ensure timely satisfaction.',
    `systematic_rmd_frequency` STRING COMMENT 'The frequency at which systematic RMD distributions are scheduled when the owner is enrolled in the automatic RMD program (systematic_rmd_flag = True). Null when systematic RMD is not elected.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `systematic_rmd_start_date` DATE COMMENT 'The date on which the contract owners enrollment in the systematic RMD distribution program became effective. Null when systematic RMD is not elected.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this RMD schedule record was most recently modified in the data platform. Updated whenever distributions are applied, recalculations occur, or status changes. Supports audit trails and change tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `waiver_reason` STRING COMMENT 'The reason code explaining why the RMD obligation has been waived for the calendar year. Applicable only when rmd_status is waived. Examples include first-year deferral election, IRS-approved waiver, contract annuitization, full surrender, or regulatory relief (e.g., COVID-19 CARES Act waiver).. Valid values are `first_year_deferral|irs_approved_waiver|contract_annuitized|contract_surrendered|regulatory_relief`',
    `ytd_distributions_applied` DECIMAL(18,2) COMMENT 'The cumulative amount of distributions taken from the annuity contract during the RMD calendar year that have been applied toward satisfying the RMD obligation. Updated each time a qualifying withdrawal is processed. Used to compute the remaining RMD balance.',
    CONSTRAINT pk_rmd_schedule PRIMARY KEY(`rmd_schedule_id`)
) COMMENT 'Manages Required Minimum Distribution (RMD) schedules for qualified annuity contracts subject to IRS RMD rules under IRC Section 72 and IRS Publication 590-B. Tracks RMD calculation year, applicable IRS life expectancy table (Uniform, Joint, Single), account value as of December 31 prior year, calculated RMD amount, distributions already taken toward RMD, remaining RMD balance, RMD due date, and RMD satisfaction status. Supports IRS Form 5498 and 1099-R tax reporting obligations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`index_crediting_strategy` (
    `index_crediting_strategy_id` BIGINT COMMENT 'Unique surrogate identifier for each index crediting strategy or sub-account allocation record associated with an annuity contract. Serves as the primary key for this entity.',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract to which this index crediting strategy or sub-account allocation belongs. Links the strategy to its parent contract in the Annuity Administration Platform.',
    `crediting_strategy_id` BIGINT COMMENT 'Foreign key linking to product.crediting_strategy. Business justification: Contract-level strategy elections reference product crediting strategy definitions for cap/participation rates, index types, crediting methods, and allocation limits. Essential for index credit calcul',
    `derivative_contract_id` BIGINT COMMENT 'Foreign key linking to investment.derivative_contract. Business justification: Each FIA index crediting strategy term is hedged by a specific index option (derivative contract). This link supports GAAP ASC 815 hedge accounting, NAIC Schedule DB derivative reporting, and hedge ef',
    `security_id` BIGINT COMMENT 'Foreign key linking to investment.security. Business justification: FIA index strategies reference specific market indices (S&P 500, NASDAQ-100) that are securities in the investment master. Crediting calculations, cap/participation rate setting, and option pricing re',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: FIA crediting strategies with cap rates, participation rates, and index options are version-specific and change with product filings. Required for rate renewal processing, strategy availability valida',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: FIA crediting strategies (cap, participation, spread rates) must match approved policy forms and illustrations. Links strategy elections to approved form language for regulatory compliance validation.',
    `prior_strategy_index_crediting_strategy_id` BIGINT COMMENT 'Reference to the predecessor index crediting strategy record that this record replaced or was renewed from. Enables transfer and rebalance history tracking and supports audit trail requirements for policyholder allocation changes.',
    `rate_action_id` BIGINT COMMENT 'Foreign key linking to product.rate_action. Business justification: FIA renewal rate-setting is driven by rate_action records. index_crediting_strategy has renewal_election and renewal_rate_flag indicating rate renewal events. Linking to rate_action enables renewal ra',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: FIA index crediting strategy parameters (cap rates, participation rates, spreads) are subject to state rate filings. The index_crediting_strategy must reference the approved rate filing to validate th',
    `scenario_set_id` BIGINT COMMENT 'Foreign key linking to actuarial.scenario_set. Business justification: FIA index crediting strategies are priced and hedged using economic scenario sets for option budget calculations and hedge effectiveness testing. Actuaries use this link to validate that credited rate',
    `allocation_pct` DECIMAL(18,2) COMMENT 'Percentage of new premium and/or account value directed to this specific strategy or sub-account. Expressed as a decimal percentage (e.g., 25.0000 = 25%). All active strategy allocations for a contract must sum to 100%. Governs how premium deposits and rebalancing flows are distributed.',
    `allocation_status` STRING COMMENT 'Current lifecycle status of this strategy election on the contract. active = currently receiving allocations and crediting; pending = elected but not yet effective; terminated = no longer active; suspended = temporarily halted; transferred = funds moved to another strategy.. Valid values are `active|pending|terminated|suspended|transferred`',
    `av_at_term_end` DECIMAL(18,2) COMMENT 'Account Value (AV) allocated to this FIA strategy at the end of the crediting term after interest has been credited, in USD. Reflects the starting AV plus credited interest minus any withdrawals during the term. Null for open terms and VA sub-account strategies.',
    `av_at_term_start` DECIMAL(18,2) COMMENT 'Account Value (AV) allocated to this FIA strategy at the beginning of the crediting term, in USD. Serves as the basis for interest crediting calculations at term end. Null for VA sub-account strategies where unit-based valuation applies.',
    `buffer_rate` DECIMAL(18,2) COMMENT 'Percentage of index loss absorbed by the carrier before the policyholder bears downside risk, expressed as a decimal percentage (e.g., 10.0000 = 10%). Used in buffered or RILA-style FIA strategies as an alternative to a floor. Null for floor-based strategies and VA sub-accounts.',
    `cap_rate` DECIMAL(18,2) COMMENT 'Maximum index-linked interest rate that can be credited to the FIA strategy in a given crediting term, expressed as a decimal percentage (e.g., 8.5000 = 8.5%). Limits the upside participation in index gains. Null for uncapped strategies and VA sub-accounts. Set by the carrier and subject to contractual minimums filed with state regulators.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this index crediting strategy record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail and data lineage requirements.',
    `credited_interest_rate` DECIMAL(18,2) COMMENT 'Actual index-linked interest rate credited to the FIA strategy at the end of the crediting term, expressed as a decimal percentage. Reflects the application of cap, participation rate, spread, floor, and buffer mechanics to the raw index change. Populated only after term completion. Null for open terms and VA sub-accounts.',
    `crediting_term_months` STRING COMMENT 'Duration of the FIA index crediting term in months (e.g., 12 for annual, 24 for two-year). Defines the measurement period over which index performance is evaluated and interest is credited. Null for VA sub-account strategies.',
    `declared_interest_rate` DECIMAL(18,2) COMMENT 'Fixed interest rate declared by the carrier for a fixed declared rate strategy bucket, expressed as a decimal percentage (e.g., 3.5000 = 3.5%). Applicable only to FIXED_DECLARED and DECLARED_RATE strategy types. Null for index-linked and variable sub-account strategies.',
    `dollar_cost_averaging_flag` BOOLEAN COMMENT 'Indicates whether this strategy is part of a Dollar Cost Averaging (DCA) program, where premium is systematically transferred from a fixed account into this strategy over a defined period. Common in variable annuity new business processing.',
    `effective_date` DATE COMMENT 'Date on which this strategy election became or becomes effective for the contract. For FIA strategies, this typically aligns with the start of the crediting term. For VA sub-accounts, this is the date the allocation instruction took effect.',
    `election_source` STRING COMMENT 'Identifies the business event that created or last modified this strategy election. new_business = elected at contract issue; policyholder_change = changed via service request; renewal = auto-renewed at term end; rebalance = created by rebalancing event; transfer = result of a fund transfer; dca_program = created by DCA program.. Valid values are `new_business|policyholder_change|renewal|rebalance|transfer|dca_program`',
    `expiry_date` DATE COMMENT 'Date on which this strategy election expires or is scheduled to terminate. For FIA strategies, this is the end of the crediting term. Null for open-ended variable annuity sub-account allocations. Used to trigger renewal or reallocation workflows.',
    `floor_rate` DECIMAL(18,2) COMMENT 'Minimum index-linked interest rate guaranteed to be credited to the FIA strategy in a given crediting term, expressed as a decimal percentage (e.g., 0.0000 = 0%). Protects the policyholder from negative index returns. Typically 0% for most FIA products. Null for VA sub-accounts.',
    `fund_cusip` STRING COMMENT 'Committee on Uniform Securities Identification Procedures (CUSIP) identifier for the variable annuity sub-account fund. Uniquely identifies the registered investment fund underlying the sub-account. Null for FIA index crediting strategies and fixed declared rate strategies. Required for SEC-registered variable products.. Valid values are `^[A-Z0-9]{9}$`',
    `fund_ticker` STRING COMMENT 'Exchange ticker symbol for the underlying investment fund of a variable annuity sub-account (e.g., VFINX, AGTHX). Used for market data feeds and NAV lookups. Null for FIA index crediting strategies.. Valid values are `^[A-Z]{1,5}$`',
    `index_end_value` DECIMAL(18,2) COMMENT 'The closing value of the underlying market index on the crediting term end date. Used in conjunction with the index start value to calculate the index change percentage for interest crediting. Populated at term maturity. Null for VA sub-account strategies and open terms.',
    `index_start_value` DECIMAL(18,2) COMMENT 'The closing value of the underlying market index on the crediting term start date. Used as the baseline for calculating index-linked interest at term end. Captured at term inception and locked for the duration of the crediting term. Null for VA sub-account strategies.',
    `market_value` DECIMAL(18,2) COMMENT 'Current market value of the policyholders holding in the variable annuity sub-account, in USD. Calculated as units held multiplied by the current unit value. Updated daily. Null for FIA index crediting strategies where AV-based valuation applies.',
    `maximum_allocation_pct` DECIMAL(18,2) COMMENT 'Maximum allocation percentage permitted for this strategy as specified in the product filing, expressed as a decimal percentage. Enforced during allocation change processing to prevent over-concentration in a single strategy.',
    `minimum_allocation_pct` DECIMAL(18,2) COMMENT 'Minimum allocation percentage required for this strategy as specified in the product filing, expressed as a decimal percentage. Enforced during allocation change processing to ensure compliance with product design constraints.',
    `participation_rate` DECIMAL(18,2) COMMENT 'Percentage of the index gain credited to the FIA strategy, expressed as a decimal percentage (e.g., 80.0000 = 80%). Determines the proportion of index performance passed through to the policyholders account value. Null for VA sub-accounts. Subject to contractual minimums per state-filed product specifications.',
    `product_type` STRING COMMENT 'Classifies the annuity product type to which this strategy applies. FIA = Fixed Indexed Annuity; VA = Variable Annuity; SPIA = Single Premium Immediate Annuity; FIXED = Traditional Fixed Annuity; IUL = Indexed Universal Life. Determines which crediting mechanics and regulatory frameworks apply.. Valid values are `FIA|VA|SPIA|FIXED|IUL`',
    `rebalancing_flag` BOOLEAN COMMENT 'Indicates whether automatic periodic rebalancing is enabled for this strategy allocation. When True, the contracts account value is periodically rebalanced back to the target allocation percentage. Applicable primarily to variable annuity sub-account strategies.',
    `rebalancing_frequency` STRING COMMENT 'Frequency at which automatic rebalancing is performed for this strategy allocation. Applicable when rebalancing_flag is True. Null or none when automatic rebalancing is not elected.. Valid values are `monthly|quarterly|semi_annual|annual|none`',
    `renewal_election` STRING COMMENT 'Policyholders standing instruction for what to do with the FIA strategy allocation at the end of the crediting term. renew_same = automatically renew into the same strategy; reallocate = redistribute per new allocation instructions; annuitize = begin annuity payout; surrender = surrender the contract. Drives automated renewal processing.. Valid values are `renew_same|reallocate|annuitize|surrender`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this strategy record originated (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Supports data lineage tracking in the Databricks Silver Layer and ETL reconciliation.. Valid values are `SAPIENS_ANNUITY|FAST_ANNUITY|POLICY_ADMIN|MANUAL`',
    `spread_rate` DECIMAL(18,2) COMMENT 'Margin or asset fee deducted from the index gain before crediting to the FIA strategy, expressed as a decimal percentage (e.g., 2.0000 = 2%). Also known as the margin or asset fee. Reduces the effective credited rate. Null for strategies using cap or participation rate mechanics and for VA sub-accounts.',
    `strategy_available_flag` BOOLEAN COMMENT 'Indicates whether this strategy is currently available for new elections or reallocation on the contract. A strategy may become unavailable if the carrier discontinues it, if it is closed to new money, or if the policyholders contract vintage does not support it.',
    `term_end_date` DATE COMMENT 'End date of the current FIA index crediting term. The index value on this date serves as the ending point for point-to-point crediting calculations. Interest is credited to the account value at term end. Null for VA sub-account strategies.',
    `term_start_date` DATE COMMENT 'Start date of the current FIA index crediting term. The index value on this date serves as the starting point for point-to-point and other crediting method calculations. Null for VA sub-account strategies.',
    `transfer_restriction_flag` BOOLEAN COMMENT 'Indicates whether transfers out of this strategy are currently restricted (e.g., due to market timing restrictions, surrender charge periods, or contractual lock-in provisions). When True, transfer requests from this strategy will be pended for compliance review.',
    `unit_value` DECIMAL(18,2) COMMENT 'Current Net Asset Value (NAV) per accumulation unit for the variable annuity sub-account, in USD. Updated daily based on the underlying funds NAV. Used to calculate the current market value of the policyholders sub-account holding. Null for FIA index crediting strategies.',
    `units_held` DECIMAL(18,2) COMMENT 'Number of accumulation units held in the variable annuity sub-account as of the most recent valuation date. Multiplied by the unit value to derive the current sub-account market value. Null for FIA index crediting strategies.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this index crediting strategy record was most recently modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Updated on every change to the record. Supports audit trail and change tracking requirements.',
    `valuation_date` DATE COMMENT 'Date as of which the current unit value, units held, and market value figures are reported. For VA sub-accounts, this is the most recent business day NAV date. For FIA strategies, this is the most recent account value calculation date.',
    CONSTRAINT pk_index_crediting_strategy PRIMARY KEY(`index_crediting_strategy_id`)
) COMMENT 'Defines and manages all investment allocation strategies elected for annuity contracts, covering both FIA index crediting strategies and variable annuity sub-account fund allocations — serving as the single source of truth for ALL annuity investment allocation management (subsumes sub_account_allocation). For FIA: captures index name (S&P 500, Russell 2000, MSCI EAFE), crediting method (annual point-to-point, monthly average, monthly cap), cap rate, participation rate, spread/margin, floor rate, buffer rate, and crediting term dates. For variable annuity: captures sub-account fund name, fund CUSIP, allocation percentage, current unit value, number of units held, current market value, allocation effective date, and rebalancing instructions. Common fields: allocation percentage, allocation effective date, strategy/fund election status, and transfer/rebalance history. Supports FIA index credit calculations, VA NAV-based AV calculations, and policyholder allocation reporting.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`index_credit_event` (
    `index_credit_event_id` BIGINT COMMENT 'Unique surrogate identifier for each Fixed Indexed Annuity (FIA) index crediting event record in the Silver layer. Primary key for this transactional entity.',
    `contract_id` BIGINT COMMENT 'Reference to the FIA annuity contract to which this index crediting event applies. Links the crediting event to the owning contract in the Annuity Administration Platform.',
    `crediting_strategy_id` BIGINT COMMENT 'Foreign key linking to product.crediting_strategy. Business justification: Index credit events reference product crediting strategy definitions to validate cap/participation rates, crediting methods, and index calculation rules. Required for credit calculation validation, he',
    `index_crediting_strategy_id` BIGINT COMMENT 'Foreign key linking to annuity.index_crediting_strategy. Business justification: index_credit_event records each FIA crediting event applied at the end of a crediting term. index_crediting_strategy defines the strategy (cap rate, participation rate, floor, buffer, term) that gover',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: FIA index crediting events generate journal entries for interest credited to policyholder accounts (GAAP interest expense, SAP reserve increase). Finance teams reconcile index credit amounts to GL pos',
    `reversed_event_index_credit_event_id` BIGINT COMMENT 'Reference to the original index credit event record that this record reverses, when reversal_flag is True. Enables audit trail linkage between reversal and original crediting events. Null for original (non-reversal) events.',
    `sub_account_allocation_id` BIGINT COMMENT 'Reference to the specific index allocation segment within the FIA contract that this crediting event applies to. A contract may have multiple index allocations across different indices and crediting strategies.',
    `actuarial_basis_code` STRING COMMENT 'Code identifying the actuarial valuation basis under which this index credit event is recognized for reserve and liability calculations (e.g., GAAP, SAP, IFRS). Supports multi-basis reporting in the Actuarial Valuation System (AXIS, Prophet, MoSes) and LDTI compliance.',
    `allocation_av_after_credit` DECIMAL(18,2) COMMENT 'The Account Value (AV) of this specific index allocation segment immediately after the index credit has been applied. Equals allocation_av_start plus credited_amount, adjusted for any withdrawals processed at term end.',
    `allocation_av_start` DECIMAL(18,2) COMMENT 'The Account Value (AV) of this specific index allocation segment at the beginning of the crediting term, before any withdrawals or adjustments during the term. Used as the base for calculating the credited dollar amount.',
    `buffer_rate` DECIMAL(18,2) COMMENT 'The percentage of index loss absorbed by the insurance company before any loss is passed to the policyholder in a buffer-based FIA crediting strategy. Expressed as a decimal (e.g., 0.100000 = 10% buffer). Null if a floor applies instead of a buffer.',
    `cap_rate` DECIMAL(18,2) COMMENT 'The maximum index-linked interest rate that can be credited to the FIA contract for this crediting term, as specified in the contract terms. Limits the upside participation in index gains. Expressed as a decimal (e.g., 0.060000 = 6.0%). Null if no cap applies to this crediting strategy.',
    `contract_av_after_credit` DECIMAL(18,2) COMMENT 'The total Account Value (AV) across all allocation segments of the FIA contract immediately after this index credit has been applied. Reflects the contract-level AV used for policyholder statements and benefit base calculations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this index credit event record was first created in the source Annuity Administration Platform system. Used for audit trail and data lineage tracking.',
    `credited_amount` DECIMAL(18,2) COMMENT 'The dollar amount of index-linked interest credited to the FIA contract allocation for this term, calculated by applying the credited_interest_rate to the allocation_av_start. This is the actual monetary value added to the Account Value (AV).',
    `credited_interest_rate` DECIMAL(18,2) COMMENT 'The final index-linked interest rate credited to the FIA contract allocation for this term, after applying cap, participation rate, floor, buffer, and spread constraints to the raw index return. Expressed as a decimal (e.g., 0.060000 = 6.0%). This is the rate that drives the credited dollar amount.',
    `crediting_event_timestamp` TIMESTAMP COMMENT 'The principal real-world business event timestamp representing when the index credit was officially applied to the FIA contract Account Value (AV) in the Annuity Administration Platform. Distinct from record audit timestamps.',
    `declared_rate_date` DATE COMMENT 'The date on which the insurance company declared the cap rate, participation rate, or spread applicable to this crediting term. Required for regulatory disclosure and policyholder notification compliance.',
    `event_number` STRING COMMENT 'Externally-visible business identifier for this index crediting event, as assigned by the Annuity Administration Platform (e.g., Sapiens Annuity or FAST Annuity). Used on policyholder statements and audit trails.',
    `event_status` STRING COMMENT 'Current lifecycle status of the index crediting event within the Annuity Administration Platform workflow. pending = term ended but credit not yet calculated; calculated = credit computed awaiting posting; applied = credit posted to Account Value (AV); reversed = previously applied credit reversed; voided = event cancelled before application.. Valid values are `pending|calculated|applied|reversed|voided`',
    `floor_rate` DECIMAL(18,2) COMMENT 'The minimum index-linked interest rate that will be credited to the FIA contract for this crediting term, protecting the policyholder from negative index returns. Typically 0% (zero floor). Expressed as a decimal (e.g., 0.000000 = 0%). Null if a buffer applies instead of a floor.',
    `gmab_benefit_base_after_credit` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Accumulation Benefit (GMAB) benefit base value immediately after this index crediting event, if a GMAB rider is attached to the contract. Tracks whether the AV meets or exceeds the guaranteed accumulation target. Null if no GMAB rider is present.',
    `gmib_benefit_base_after_credit` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Income Benefit (GMIB) benefit base value immediately after this index crediting event, if a GMIB rider is attached to the contract. Updated when the credited AV triggers a step-up. Null if no GMIB rider is present.',
    `gmwb_benefit_base_after_credit` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Withdrawal Benefit (GMWB) benefit base value immediately after this index crediting event, if a GMWB rider is attached to the contract. Updated when the credited AV exceeds the prior benefit base (step-up). Null if no GMWB rider is present.',
    `index_end_value` DECIMAL(18,2) COMMENT 'The closing value of the external market index on the crediting term end date. Used in conjunction with the index start value to calculate the raw index return percentage.',
    `index_option_type` STRING COMMENT 'The type of derivative option instrument used by the insurance company to hedge the index crediting obligation for this allocation segment. Relevant for actuarial valuation, ALM (Asset Liability Management), and investment portfolio management.. Valid values are `call_option|put_option|collar|other`',
    `index_return_pct` DECIMAL(18,2) COMMENT 'The raw percentage change in the external market index over the crediting term, calculated as (index_end_value - index_start_value) / index_start_value. This is the pre-cap, pre-floor, pre-buffer gross index performance. Expressed as a decimal (e.g., 0.085000 = 8.5%).',
    `index_start_value` DECIMAL(18,2) COMMENT 'The closing value of the external market index on the crediting term start date. Used as the baseline for calculating the index return percentage at the end of the term.',
    `participation_rate` DECIMAL(18,2) COMMENT 'The percentage of the index gain that is credited to the FIA contract for this crediting term. Applied to the index return before cap and floor constraints. Expressed as a decimal (e.g., 0.800000 = 80%). Null if no participation rate applies to this crediting strategy.',
    `renewal_rate_flag` BOOLEAN COMMENT 'Indicates whether the cap rate, participation rate, or spread applied in this crediting term was a renewal rate (True) or the initial declared rate at contract issue (False). Renewal rates may differ from initial rates and are subject to NAIC disclosure requirements.',
    `reversal_flag` BOOLEAN COMMENT 'Indicates whether this index credit event record represents a reversal of a previously applied credit (True) or an original crediting event (False). Reversals occur due to data corrections, index value restatements, or system errors.',
    `source_event_reference` STRING COMMENT 'The native event or transaction identifier from the originating Annuity Administration Platform (e.g., Sapiens Annuity transaction ID or FAST Annuity event reference). Used for reconciliation between the Silver layer and the source system.',
    `source_system_code` STRING COMMENT 'The identifier of the Annuity Administration Platform source system that originated this index credit event record (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Supports data lineage and multi-system reconciliation in the Databricks Silver layer.',
    `spread_rate` DECIMAL(18,2) COMMENT 'A fixed percentage deducted from the index return before crediting in a spread-based FIA crediting strategy. Expressed as a decimal (e.g., 0.020000 = 2.0% spread). Null if cap/participation rate applies instead of a spread.',
    `step_up_triggered` BOOLEAN COMMENT 'Indicates whether this index crediting event triggered a benefit base step-up on any attached guaranteed living benefit rider (GMWB, GMIB, or GMAB). True when the post-credit AV exceeds the prior benefit base, resulting in a ratchet to the higher value.',
    `tax_year` STRING COMMENT 'The calendar tax year in which this index crediting event falls, relevant for IRC Section 72 tax reporting on annuity contract earnings. Used for IRS Form 1099-R preparation and tax deferred growth tracking.',
    `term_duration_months` STRING COMMENT 'The length of the index crediting term expressed in months (e.g., 12 for a one-year term, 24 for a two-year term). Determines the measurement window for index performance.',
    `term_end_date` DATE COMMENT 'The last date of the index crediting term for this allocation segment. The index end value is typically captured on this date. Defines the end of the measurement period for index return calculation.',
    `term_start_date` DATE COMMENT 'The first date of the index crediting term for this allocation segment. The index start value is typically captured on this date. Defines the beginning of the measurement period for index return calculation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this index credit event record was last modified in the source Annuity Administration Platform system. Tracks reversals, corrections, and recalculations.',
    `withdrawal_adjustment_amount` DECIMAL(18,2) COMMENT 'The dollar amount of withdrawals processed during the crediting term that reduced the allocation base used for interest crediting. Reflects the impact of systematic or ad-hoc withdrawals on the credited amount calculation.',
    CONSTRAINT pk_index_credit_event PRIMARY KEY(`index_credit_event_id`)
) COMMENT 'Records each index crediting event applied to a FIA contract at the end of a crediting term. Captures crediting term start and end dates, index start value, index end value, calculated index return, cap applied, participation rate applied, floor applied, buffer applied, credited interest rate, credited dollar amount, and resulting AV after credit. This is the transactional record of FIA index performance and credit application, supporting policyholder statements and actuarial experience studies.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`annuitization_election` (
    `annuitization_election_id` BIGINT COMMENT 'Unique surrogate identifier for the annuitization election record in the Silver Layer lakehouse. Primary key for this entity.',
    `benefit_base_id` BIGINT COMMENT 'Foreign key linking to annuity.benefit_base. Business justification: annuitization_election has gmib_benefit_base_amount and gmib_rider_applied fields. When a GMIB rider is applied at annuitization, the election uses the guaranteed income benefit base to determine the ',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract undergoing annuitization. Links this election to the parent contract record in the annuity domain.',
    `contract_owner_id` BIGINT COMMENT 'Reference to the policyholder or contract owner who submitted the annuitization election. Used for party-level reporting and KYC compliance.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Annuitization elections require signed election forms per state insurance regulations. Links election record to executed document for regulatory audit trail, rescission period tracking, and irrevocabl',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Annuitization converts accumulation value to payout stream backed by specific portfolio assets. ALM requires duration-matching payout obligations to portfolio holdings. Investment teams need to reserv',
    `gaap_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.gaap_reserve. Business justification: Annuitization elections reclassify contracts from accumulation to payout phase, triggering GAAP reserve reclassification under LDTI. Finance teams link elections to GAAP reserve records to measure the',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Annuitization elections trigger accounting entries: transfer from accumulation to payout reserve, DAC acceleration/write-off, and deferred gain recognition. Finance teams require a direct link from th',
    `mortality_table_id` BIGINT COMMENT 'Foreign key linking to actuarial.mortality_table. Business justification: Annuitization rates are calculated using specific mortality tables (e.g., 2012 IAM, Annuity 2000). Critical for pricing annuity payouts, regulatory compliance, and ensuring consistent rate application',
    `payout_schedule_id` BIGINT COMMENT 'Foreign key linking to annuity.payout_schedule. Business justification: When a contract owner elects to annuitize (annuitization_election), the system creates a payout_schedule that defines the ongoing payment stream. The election captures the DECISION and election-time p',
    `pricing_basis_id` BIGINT COMMENT 'Foreign key linking to actuarial.pricing_basis. Business justification: Annuity option rates applied at annuitization election are derived from actuarial pricing_basis assumptions (interest rate basis, mortality table). This link supports GMIB exercise pricing validation ',
    `annuitant_id` BIGINT COMMENT 'Reference to the annuitant whose life expectancy governs the payout calculations. May differ from the contract owner in owner-driven annuity structures.',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or financial professional who facilitated the annuitization election. Used for commission impact tracking and suitability compliance documentation.',
    `risk_class_id` BIGINT COMMENT 'Foreign key linking to underwriting.risk_class. Business justification: Annuitization elections determine payout rates using the annuitants risk class (standard, preferred, rated). The risk class directly drives the annuity option rate applied at election. Annuity operat',
    `suitability_review_id` BIGINT COMMENT 'Reference to the suitability review record completed prior to or at the time of the annuitization election, as required under NAIC Annuity Suitability Model Regulation and DOL fiduciary standards.',
    `surrender_charge_id` BIGINT COMMENT 'Foreign key linking to annuity.surrender_charge. Business justification: annuitization_election captures surrender_charge_amount and surrender_charge_waived for contracts that annuitize during the surrender charge period. surrender_charge holds the schedule governing those',
    `annuitant_age_at_election` STRING COMMENT 'The age of the primary annuitant (in whole years) at the time of the annuitization election date. Used in actuarial factor selection, mortality table lookup, and IRC Section 72 expected return calculations.',
    `annuitization_basis` STRING COMMENT 'The value basis used to calculate the annuity income stream. account_value (AV) = current contract account value; guaranteed_annuitization_value = contractually guaranteed minimum value per rider (e.g., GMIB benefit base); greater_of = higher of AV or guaranteed value. Determines the starting principal for payout calculations.. Valid values are `account_value|guaranteed_annuitization_value|greater_of`',
    `annuitization_value_amount` DECIMAL(18,2) COMMENT 'The dollar amount of the annuitization basis (AV or guaranteed annuitization value) used to calculate the periodic income payment at the time of election. Captured as a point-in-time snapshot at the effective date.',
    `annuity_option_rate` DECIMAL(18,2) COMMENT 'The annuity factor or option rate (per $1,000 of annuitization value) used to convert the annuitization basis into the periodic payment amount. Derived from the applicable mortality table and interest rate assumption at the time of annuitization.',
    `annuity_type` STRING COMMENT 'The type of annuity contract being annuitized. fixed = guaranteed fixed payment; variable = payments vary with separate account performance relative to AIR; fixed_indexed = FIA with index-linked crediting. Governs payout calculation methodology and SEC/FINRA regulatory requirements.. Valid values are `fixed|variable|fixed_indexed`',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time when the annuitization election was formally approved by the insurance companys new business or contract servicing team. Null if election is still pending or was cancelled.',
    `assumed_interest_rate` DECIMAL(18,2) COMMENT 'The Assumed Interest Rate (AIR) used in the annuity factor calculation at the time of annuitization. Expressed as a decimal (e.g., 0.0350 = 3.50%). Relevant for variable annuity payout calculations where actual performance is compared to AIR.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this election record. Typically USD for domestic US annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'The date on which the contract officially transitions from the accumulation phase to the payout phase. Also known as the Annuity Start Date (ASD) or Annuity Commencement Date. Governs IRC Section 72 tax treatment.',
    `election_date` DATE COMMENT 'The calendar date on which the contract owner formally submitted the annuitization election request. Serves as the principal business event date for this transaction.',
    `election_number` STRING COMMENT 'Externally-visible business identifier assigned to this annuitization election by the Annuity Administration Platform. Used in correspondence, confirmations, and regulatory filings.',
    `election_received_timestamp` TIMESTAMP COMMENT 'The date and time when the annuitization election request was received and logged in the Annuity Administration Platform. Serves as the RECORD_AUDIT_CREATED timestamp for this transaction.',
    `election_source_channel` STRING COMMENT 'The distribution or service channel through which the annuitization election was submitted. Used for operational analytics and agent commission impact assessment.. Valid values are `agent|owner_direct|tpa|digital_self_service|call_center`',
    `election_status` STRING COMMENT 'Current lifecycle state of the annuitization election. pending = submitted but not yet approved; approved = approved but payout not yet started; in_force = payout phase active; cancelled = withdrawn before effective date; rescinded = reversed after effective date per applicable free-look or regulatory provision.. Valid values are `pending|approved|in_force|cancelled|rescinded`',
    `exclusion_ratio` DECIMAL(18,2) COMMENT 'The IRC Section 72 exclusion ratio representing the proportion of each annuity payment that is a tax-free return of the owners cost basis. Calculated as investment in contract divided by expected return. Used for 1099-R tax reporting.',
    `expected_return` DECIMAL(18,2) COMMENT 'The total expected return from the annuity contract as calculated under IRC Section 72 tables, used as the denominator in the exclusion ratio calculation. For life annuities, derived from IRS actuarial tables based on annuitant age and payout option.',
    `first_payment_date` DATE COMMENT 'The scheduled date of the first annuity income payment to the payee following annuitization. May differ from the effective date depending on payout frequency and payment timing convention (immediate vs. deferred first payment).',
    `gmib_benefit_base_amount` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Income Benefit (GMIB) benefit base amount at the time of annuitization election, when the GMIB rider is exercised. Represents the guaranteed minimum value used to calculate the income stream, which may exceed the current account value.',
    `gmib_rider_applied` BOOLEAN COMMENT 'Indicates whether the Guaranteed Minimum Income Benefit (GMIB) rider was exercised as the basis for this annuitization election. True = GMIB benefit base used; False = standard account value annuitization.',
    `investment_in_contract` DECIMAL(18,2) COMMENT 'The owners total after-tax cost basis in the annuity contract at the time of annuitization, as defined under IRC Section 72. Used to calculate the exclusion ratio for tax-free recovery of basis in annuity payments.',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether the annuitization election involves a tax-free 1035 Exchange (IRC Section 1035) from another insurance or annuity contract. True = the annuitization basis includes proceeds from a 1035 exchange; False = no exchange involved.',
    `is_irrevocable` BOOLEAN COMMENT 'Indicates whether the annuitization election is irrevocable once the effective date is reached. True = the owner cannot reverse or modify the election after the annuity start date; False = election may be modified within applicable free-look or rescission period.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this annuitization election record was last modified in the source system or Silver Layer. Supports audit trail and data lineage requirements.',
    `rescission_deadline_date` DATE COMMENT 'The last date by which the contract owner may rescind or cancel the annuitization election under applicable state free-look or rescission provisions. Null for irrevocable elections or after the deadline has passed.',
    `source_system_election_reference` STRING COMMENT 'The native identifier assigned to this annuitization election record in the originating Annuity Administration Platform (e.g., Sapiens Annuity). Supports data lineage tracing from Silver Layer back to the operational system of record.',
    `surrender_charge_amount` DECIMAL(18,2) COMMENT 'The surrender charge amount that would have applied at the time of annuitization, prior to any waiver. Captured for audit and actuarial analysis even when waived. Null if no surrender charge schedule applies.',
    `surrender_charge_waived` BOOLEAN COMMENT 'Indicates whether the surrender charge was waived upon annuitization. Many annuity contracts waive surrender charges when the owner elects to annuitize, as an incentive for lifetime income election.',
    `tax_qualified_status` STRING COMMENT 'Indicates whether the annuity contract is tax-qualified (e.g., IRA, 403(b), 401(a)) or non-qualified. Governs IRC Section 72 tax treatment, RMD applicability, and 1099-R reporting codes.. Valid values are `qualified|non_qualified`',
    CONSTRAINT pk_annuitization_election PRIMARY KEY(`annuitization_election_id`)
) COMMENT 'Captures the annuitization election details when a contract transitions from the accumulation phase to the payout phase. Records election date, annuitization effective date, payout option selected (life only, life with period certain, joint and survivor, fixed period), annuity start date, annuitization basis (AV or guaranteed annuitization value), payout frequency, first payment date, and whether the election is irrevocable. Sourced from Sapiens Annuity benefit calculation and annuitization modules.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`payout_schedule` (
    `payout_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the annuity payout schedule record in the Annuity Administration Platform. Primary key for this entity.',
    `contract_id` BIGINT COMMENT 'Reference to the parent annuity contract for which this payout schedule is defined. Links the payout schedule to the annuity contract administration record.',
    `mortality_table_id` BIGINT COMMENT 'Foreign key linking to actuarial.mortality_table. Business justification: Life-contingent payout schedules (life only, joint-and-survivor, period certain and life) require mortality tables for payment calculation. Essential for accurate benefit payments, reserve adequacy, a',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Annuitization payout options, mortality tables, and annuity option rates are locked to plan version at election date. Critical for payout calculations, mortality table selection, and regulatory compli',
    `pricing_basis_id` BIGINT COMMENT 'Foreign key linking to actuarial.pricing_basis. Business justification: Payout schedule payment amounts are calculated using actuarial pricing_basis assumptions (assumed interest rate, mortality). This link enables SPIA/annuity payment rate validation against filed pricin',
    `annuitant_id` BIGINT COMMENT 'Reference to the primary annuitant (measuring life) whose life expectancy governs the payout duration. Required for life-contingent payout options.',
    `risk_class_id` BIGINT COMMENT 'Foreign key linking to underwriting.risk_class. Business justification: Life-contingent payout schedules (life-only, life with period certain) use the annuitants underwriting risk class to apply appropriate mortality assumptions for scheduled payment amounts and reserve ',
    `separate_account_id` BIGINT COMMENT 'Foreign key linking to investment.separate_account. Business justification: Variable annuity payout schedules calculate periodic payments using annuity unit values from a specific separate account. This link is required for annuity unit value lookups during payment calculatio',
    `state_regulation_id` BIGINT COMMENT 'Foreign key linking to compliance.state_regulation. Business justification: Payout schedules must comply with state-specific nonforfeiture regulations, minimum annuity payout options, and withholding rules. Payout administrators reference the applicable state regulation to va',
    `statutory_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.statutory_reserve. Business justification: Payout annuity schedules drive statutory reserve calculations (CARVM payout phase, Commissioners Annuity Reserve Valuation Method). Appointed actuaries link payout schedules to statutory reserve recor',
    `account_value_at_annuitization` DECIMAL(18,2) COMMENT 'The Account Value (AV) of the deferred annuity contract at the time of annuitization, used as the premium basis for calculating the annuity income payment amount. Null for SPIA contracts.',
    `annuitization_date` DATE COMMENT 'Date on which a deferred annuity contract was formally annuitized, converting the accumulated account value into a stream of annuity income payments. Null for SPIA contracts where annuitization occurs at contract issue.',
    `annuity_start_date` DATE COMMENT 'The annuity commencement date (ACD) — the date on which the annuity contract formally enters the payout phase and benefit calculations are locked. Distinct from payment_start_date, which is the first actual disbursement date. Governs IRC Section 72 exclusion ratio calculations.',
    `cola_anniversary_date` DATE COMMENT 'Annual date on which the Cost-of-Living Adjustment (COLA) is applied to increase the scheduled annuity income payment amount. Typically the contract anniversary date. Null if no COLA applies.',
    `cola_index_type` STRING COMMENT 'Type of inflation index used to determine the Cost-of-Living Adjustment (COLA) applied to annuity income payments. Fixed indicates a contractually specified fixed rate; CPI-U and CPI-W reference U.S. Bureau of Labor Statistics Consumer Price Index measures; none indicates no COLA applies.. Valid values are `fixed|CPI_U|CPI_W|none`',
    `cola_rate` DECIMAL(18,2) COMMENT 'Annual Cost-of-Living Adjustment (COLA) rate applied to the scheduled payment amount to increase annuity income payments over time to offset inflation. Expressed as a decimal (e.g., 0.03 for 3%). Zero or null if no COLA applies.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this payout schedule record was first created in the system of record. Used for audit trail and data lineage in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this payout schedule (e.g., USD). Required for multi-currency annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'Date from which this version of the payout schedule is in effect. Supports slowly changing dimension (SCD) tracking for schedule amendments such as COLA adjustments, payment amount changes, or payout option modifications.',
    `exclusion_ratio` DECIMAL(18,2) COMMENT 'The IRC Section 72 exclusion ratio applied to each annuity income payment to determine the non-taxable return-of-investment portion. Calculated as the investment in the contract divided by the expected return. Used for IRS Form 1099-R tax reporting.',
    `expected_return` DECIMAL(18,2) COMMENT 'The total amount expected to be received under the annuity contract over its payout period, as calculated under IRC Section 72 using IRS actuarial tables. Used as the denominator in the exclusion ratio calculation.',
    `federal_withholding_rate` DECIMAL(18,2) COMMENT 'Federal income tax withholding rate applied to the taxable portion of each annuity income payment, as elected by the annuitant or as mandated by IRS default withholding rules. Used for IRS Form 1099-R reporting and payment net calculation.',
    `interest_rate_basis` DECIMAL(18,2) COMMENT 'The assumed interest rate used in the actuarial calculation of the annuity income payment amount at the time of annuitization or SPIA pricing. Expressed as a decimal (e.g., 0.035 for 3.5%). Used in actuarial reserve calculations and FASB ASC 944 LDTI discount rate determinations.',
    `investment_in_contract` DECIMAL(18,2) COMMENT 'The annuitants after-tax cost basis in the annuity contract at the annuity start date, as defined under IRC Section 72. Used to calculate the exclusion ratio and the non-taxable portion of each annuity income payment for IRS Form 1099-R reporting.',
    `last_payment_amount` DECIMAL(18,2) COMMENT 'Gross amount of the most recently issued annuity income payment. May differ from scheduled_payment_amount due to COLA adjustments, partial-period proration, or manual adjustments.',
    `last_payment_date` DATE COMMENT 'Date on which the most recent annuity income payment was issued under this payout schedule. Used to confirm payment continuity and detect missed payments.',
    `next_payment_date` DATE COMMENT 'Date on which the next scheduled annuity income payment is due to be issued. Updated after each payment cycle by the Annuity Administration Platform. Used in benefit payment processing and cash flow management.',
    `payment_end_date` DATE COMMENT 'Date on which the last scheduled annuity income payment is due. Populated for period-certain and fixed-term payout options; null for life-only payout options where payments continue until the annuitants death.',
    `payment_frequency` STRING COMMENT 'Frequency at which annuity income payments are disbursed to the annuitant. Determines the payment schedule cadence and is used in benefit payment processing and actuarial liability calculations.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `payment_mode_code` STRING COMMENT 'Method by which annuity income payments are disbursed to the annuitant (e.g., Electronic Funds Transfer (EFT), check, wire transfer). Drives payment processing routing in the Annuity Administration Platform.. Valid values are `EFT|check|wire`',
    `payment_start_date` DATE COMMENT 'Date on which the first annuity income payment is scheduled to be issued. For Single Premium Immediate Annuities (SPIA), this is typically one payment period after the contract issue date. Governs the commencement of the payout phase.',
    `payments_made_count` STRING COMMENT 'Cumulative count of annuity income payments that have been issued to date under this payout schedule. Used to track progress against total expected payments and to determine remaining guaranteed payments.',
    `payout_option_code` STRING COMMENT 'Standardized code identifying the annuity payout form elected by the annuitant (e.g., life-only, life with period certain, joint-and-survivor, period certain only, installment refund, cash refund). Drives payment duration logic and survivor benefit calculations. [ENUM-REF-CANDIDATE: life_only|life_period_certain|joint_survivor|period_certain_only|installment_refund|cash_refund|life_with_refund — promote to reference product]',
    `payout_option_description` STRING COMMENT 'Human-readable description of the elected annuity payout option as it appears on the annuity contract and benefit statements (e.g., Life with 10-Year Period Certain, Joint and 50% Survivor). Used in annuitant communications and regulatory disclosures.',
    `period_certain_years` STRING COMMENT 'Number of years for which annuity income payments are guaranteed regardless of the annuitants survival (e.g., 5, 10, 20 years). Applicable to life-with-period-certain and period-certain-only payout options. Null for life-only options.',
    `pop_up_provision` BOOLEAN COMMENT 'Indicates whether the payout schedule includes a pop-up provision, whereby the annuity income payment increases (pops up) to the single-life amount if the joint annuitant predeceases the primary annuitant. Applicable to joint-and-survivor payout options only.',
    `qualified_plan_type` STRING COMMENT 'Type of tax-qualified retirement plan under which the annuity contract is held, governing Required Minimum Distribution (RMD) rules and tax reporting requirements. Non-qualified for contracts not held in a qualified plan. [ENUM-REF-CANDIDATE: IRA|Roth_IRA|403b|401a|457b|457f|SEP_IRA|SIMPLE_IRA|non_qualified — promote to reference product]. Valid values are `IRA|Roth_IRA|403b|401a|457b|non_qualified`',
    `refund_feature_type` STRING COMMENT 'Type of refund guarantee attached to the payout option. Cash refund pays the beneficiary a lump sum equal to the premium minus payments received; installment refund continues payments to the beneficiary until the total premium is recovered. None indicates no refund feature.. Valid values are `none|cash_refund|installment_refund`',
    `rmd_required_flag` BOOLEAN COMMENT 'Indicates whether the annuity payout schedule satisfies the Required Minimum Distribution (RMD) rules under IRC Section 401(a)(9). True for tax-qualified contracts where the annuitant has reached the applicable RMD age.',
    `rmd_start_date` DATE COMMENT 'Date by which Required Minimum Distributions (RMD) must commence under IRC Section 401(a)(9), based on the annuitants required beginning date. Null for non-qualified contracts or contracts not subject to RMD rules.',
    `schedule_number` STRING COMMENT 'Externally visible alphanumeric identifier for the payout schedule, as assigned by the Annuity Administration Platform (e.g., Sapiens Annuity or FAST Annuity). Used in benefit payment processing and annuitant correspondence.',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the payout schedule. Active indicates payments are being issued; suspended indicates a temporary hold; completed indicates all scheduled payments have been made; cancelled indicates the schedule was terminated before completion; pending indicates the schedule is set up but the first payment date has not yet arrived.. Valid values are `active|suspended|completed|cancelled|pending`',
    `scheduled_payment_amount` DECIMAL(18,2) COMMENT 'Gross periodic income payment amount due to the annuitant per payment frequency, before any applicable withholding taxes or deductions. Expressed in the contract currency. Core field for benefit payment processing and actuarial liability calculations.',
    `source_system_code` STRING COMMENT 'Code identifying the operational Annuity Administration Platform from which this payout schedule record was sourced (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Used for data lineage tracking in the Databricks Silver Layer.',
    `spia_flag` BOOLEAN COMMENT 'Indicates whether this payout schedule is associated with a Single Premium Immediate Annuity (SPIA) contract, as opposed to an annuitized deferred annuity. Drives product-specific processing rules in the Annuity Administration Platform.',
    `state_withholding_rate` DECIMAL(18,2) COMMENT 'State income tax withholding rate applied to the taxable portion of each annuity income payment, as elected by the annuitant or as required by the applicable state tax authority. Varies by state of residence.',
    `survivor_percentage` DECIMAL(18,2) COMMENT 'Percentage of the primary annuity income payment that continues to the joint annuitant upon the death of the primary annuitant, for joint-and-survivor payout options (e.g., 0.50 for 50%, 0.667 for 66.7%, 1.00 for 100%). Null for single-life payout options.',
    `tax_qualified_flag` BOOLEAN COMMENT 'Indicates whether the annuity contract funding this payout schedule is a tax-qualified contract (e.g., IRA, 403(b), 401(a)) or a non-qualified contract. Determines IRC Section 72 tax treatment and exclusion ratio applicability.',
    `total_expected_payments` STRING COMMENT 'Total number of periodic income payments expected over the guaranteed period of the payout schedule (e.g., 120 for a 10-year period certain with monthly payments). Used in actuarial liability calculations and benefit payment processing.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this payout schedule record was most recently modified in the system of record. Used for change detection, incremental ETL processing, and audit trail in the Databricks Silver Layer.',
    `withholding_state_code` STRING COMMENT 'Two-letter U.S. state code for the state to which income tax withholding on annuity payments is remitted. Determined by the annuitants state of residence at the time of payout commencement.. Valid values are `^[A-Z]{2}$`',
    CONSTRAINT pk_payout_schedule PRIMARY KEY(`payout_schedule_id`)
) COMMENT 'Defines the periodic income payment schedule for annuity contracts in the payout phase, including SPIA (Single Premium Immediate Annuity) and annuitized deferred contracts. Captures scheduled payment amount, payment frequency, payment start date, payment end date (if period certain), cost-of-living adjustment (COLA) rate, inflation index linkage, joint annuitant survivor percentage, and total expected payments. Supports benefit payment processing and actuarial liability calculations.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`benefit_payment` (
    `benefit_payment_id` BIGINT COMMENT 'Unique surrogate identifier for each benefit payment record disbursed under an annuity payout schedule or living benefit claim. Primary key for the benefit_payment data product in the Databricks Silver Layer.',
    `account_id` BIGINT COMMENT 'Foreign key linking to billing.billing_account. Business justification: Annuitization benefit payments are disbursed through billing accounts. Real business process: annuity payout processing, recurring payment execution, tax withholding coordination. Critical for post-an',
    `annuitant_id` BIGINT COMMENT 'Reference to the annuitant or beneficiary receiving this benefit payment. Supports party-level reporting and 1099-R tax reporting under IRC Section 72.',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract under which this benefit payment is disbursed. Links the payment to the governing contract in the Annuity Administration Platform.',
    `exclusion_rider_id` BIGINT COMMENT 'Foreign key linking to underwriting.exclusion_rider. Business justification: Benefit payment adjudication requires checking applicable exclusion riders to determine if the triggering cause (cause of death, disability type) is excluded. Claims and benefit operations teams use t',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Annuity benefit payments require journal entries for benefit expense (debit), tax withholding liability (credit), and cash disbursement (credit). Direct GL posting for every annuitization payment and ',
    `mortality_table_id` BIGINT COMMENT 'Foreign key linking to actuarial.mortality_table. Business justification: Life-contingent annuity benefit payments (period certain + life, joint life) require mortality table reference for reserve release calculations and expected payment duration. Actuaries use this link f',
    `original_payment_benefit_payment_id` BIGINT COMMENT 'Reference to the original benefit_payment_id that this record reverses or corrects. Populated only when payment_reversal_indicator is True. Enables tracing of correction chains for audit and reconciliation.',
    `payout_schedule_id` BIGINT COMMENT 'Foreign key linking to annuity.payout_schedule. Business justification: benefit_payment records each periodic income payment disbursed under an annuity payout. payout_schedule defines the payment schedule (frequency, amount, option) that governs those payments. A benefit_',
    `rider_benefit_id` BIGINT COMMENT 'Foreign key linking to annuity.rider_benefit. Business justification: benefit_payment records periodic income payments including rider-based payments (GMWB income, GMIB annuitization, GMAB maturity). rider_benefit is the master record for each optional rider. When a pay',
    `rmd_schedule_id` BIGINT COMMENT 'Foreign key linking to annuity.rmd_schedule. Business justification: benefit_payment has is_rmd_payment and rmd_tax_year fields indicating RMD-satisfying payments. When a benefit_payment satisfies an RMD obligation (common for qualified annuities in payout phase), it m',
    `sar_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.sar_filing. Business justification: Annuity payments to suspicious parties or unusual payment patterns may trigger SAR filing per BSA requirements. Links benefit payments to SAR filings for AML transaction monitoring and regulatory repo',
    `surrender_charge_id` BIGINT COMMENT 'Foreign key linking to annuity.surrender_charge. Business justification: benefit_payment captures surrender_charge_amount for payments that incur surrender charges (e.g., early annuitization or partial surrenders processed as benefit payments). surrender_charge holds the s',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: Benefit payments generate 1099-R tax documents that must be retained and linked to the originating payment for IRS reporting, owner tax inquiries, and state tax authority audits. The benefit_payment a',
    `account_value_at_payment` DECIMAL(18,2) COMMENT 'The annuity contracts Account Value (AV) as of the payment date, prior to the disbursement of this payment. Used to assess the relationship between the benefit base and AV, determine if the contract is in the money on living benefit riders, and support actuarial reserving.',
    `benefit_base_amount` DECIMAL(18,2) COMMENT 'The guaranteed benefit base (rider base) value at the time of this payment, applicable for GMWB, GMIB, or GMAB riders. The benefit base is the notional amount used to calculate guaranteed income or withdrawal amounts and may differ from the contract Account Value (AV).',
    `check_number` STRING COMMENT 'The sequential check number assigned to a paper check disbursement. Populated only when payment_method is check. Used for check reconciliation, stop-payment processing, and audit trail.',
    `contract_qualification_type` STRING COMMENT 'Indicates whether the annuity contract is qualified (funded with pre-tax dollars under ERISA/IRS qualified plans such as IRA, 401(k), 403(b)) or non-qualified (funded with after-tax dollars). Determines tax treatment, exclusion ratio applicability, and RMD obligations.. Valid values are `qualified|non_qualified`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this benefit payment record was first created in the Sapiens Annuity payment processing system. Serves as the record audit creation timestamp for data lineage and Silver Layer ingestion tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this payment record (e.g., USD). Supports multi-currency operations for international annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `distribution_code` STRING COMMENT 'IRS-defined distribution code reported in Box 7 of Form 1099-R that characterizes the nature of the distribution for tax purposes (e.g., 1=early distribution no exception, 2=early distribution exception applies, 3=disability, 4=death, 7=normal distribution, D=annuity payments from non-qualified annuity). [ENUM-REF-CANDIDATE: 1|2|3|4|7|D|G|L|P|Q|R|S|T|U|W — promote to reference product]',
    `early_withdrawal_penalty_amount` DECIMAL(18,2) COMMENT 'Dollar amount of the 10% federal early withdrawal penalty tax assessed on this distribution under IRC Section 72(t) when the annuitant is under age 59½ and no exception applies. Reported on IRS Form 5329.',
    `exclusion_ratio_amount` DECIMAL(18,2) COMMENT 'The non-taxable portion of the gross payment for non-qualified annuity contracts, calculated by applying the IRC Section 72 exclusion ratio (investment in contract divided by expected return) to the gross payment. Represents recovery of the annuitants after-tax investment in the contract.',
    `exclusion_ratio_pct` DECIMAL(18,2) COMMENT 'The IRC Section 72 exclusion ratio expressed as a decimal fraction (e.g., 0.312500 = 31.25%) applied to this payment to determine the non-taxable recovery of investment in contract. Calculated as investment in contract divided by expected return at annuity start date.',
    `federal_tax_withheld_amount` DECIMAL(18,2) COMMENT 'Dollar amount of federal income tax withheld from the gross benefit payment per the annuitants W-4P election or mandatory withholding rules under IRC Section 3405. Reported on IRS Form 1099-R Box 4.',
    `gross_payment_amount` DECIMAL(18,2) COMMENT 'The total scheduled benefit payment amount before any federal or state tax withholding deductions. Represents the full contractual income entitlement for the payment period. Used as the base for 1099-R gross distribution reporting.',
    `investment_in_contract_recovered` DECIMAL(18,2) COMMENT 'Cumulative after-tax investment in the annuity contract that has been recovered (returned tax-free) through all benefit payments up to and including this payment. Tracks the running total of basis recovered under IRC Section 72 to determine when the full investment has been recouped.',
    `is_mec_distribution` BOOLEAN COMMENT 'Indicates whether this payment is a distribution from a Modified Endowment Contract (MEC) as defined under IRC Section 7702A. MEC distributions are subject to income-first taxation and potential 10% penalty. Reported in IRS Form 1099-R Box 7 with code D.',
    `is_rmd_payment` BOOLEAN COMMENT 'Indicates whether this benefit payment satisfies all or part of the annuitants Required Minimum Distribution (RMD) obligation for the tax year under IRC Section 401(a)(9). True = this payment counts toward the RMD; False = not an RMD payment.',
    `net_payment_amount` DECIMAL(18,2) COMMENT 'The actual dollar amount remitted to the annuitant or beneficiary after deducting federal and state tax withholding from the gross payment amount. This is the amount deposited via ACH, issued by check, or wired.',
    `payee_bank_account_last4` STRING COMMENT 'Last four digits of the payees bank account number used for ACH or direct deposit disbursement. Stored as a masked reference for reconciliation and payment verification without retaining full account details. Full account data is stored in the EFT authorization record.. Valid values are `^[0-9]{4}$`',
    `payee_routing_number` STRING COMMENT 'ABA routing transit number of the payees financial institution used for ACH or wire transfer disbursement. Nine-digit identifier assigned by the American Bankers Association.. Valid values are `^[0-9]{9}$`',
    `payment_date` DATE COMMENT 'The actual calendar date on which the benefit payment was disbursed or issued to the annuitant or beneficiary. This is the principal real-world event date used for tax reporting, reconciliation, and regulatory compliance.',
    `payment_frequency` STRING COMMENT 'The contractual frequency at which benefit payments are scheduled to be disbursed. Drives the payment schedule generation in the Sapiens Annuity platform and is used for actuarial cash flow projections.. Valid values are `monthly|quarterly|semi_annual|annual|single`',
    `payment_method` STRING COMMENT 'The disbursement instrument used to remit the net payment to the annuitant or beneficiary. ach = Automated Clearing House electronic transfer; check = paper check mailed to payee; wire = domestic or international wire transfer; direct_deposit = direct deposit to a designated financial account.. Valid values are `ach|check|wire|direct_deposit`',
    `payment_period_end_date` DATE COMMENT 'The last day of the benefit period covered by this payment. Together with payment_period_start_date, defines the income interval for tax and actuarial reporting.',
    `payment_period_start_date` DATE COMMENT 'The first day of the benefit period covered by this payment. Used for income period attribution, tax year allocation, and actuarial reporting.',
    `payment_reference_number` STRING COMMENT 'Externally visible, human-readable reference number assigned by the Sapiens Annuity payment processing module to uniquely identify this disbursement for reconciliation, customer service, and audit purposes.',
    `payment_reversal_indicator` BOOLEAN COMMENT 'Indicates whether this payment record represents a reversal or correction of a previously issued payment. True = this is a reversal/correction entry; False = original payment. Used for reconciliation and audit trail integrity.',
    `payment_sequence_number` STRING COMMENT 'Sequential ordinal number of this payment within the annuity contracts payout schedule (e.g., 1 = first payment, 24 = 24th monthly payment). Used for payment tracking, duration analysis, and identifying the position within the payout phase.',
    `payment_status` STRING COMMENT 'Current lifecycle state of the benefit payment. scheduled = payment queued for future disbursement; issued = payment sent to payee; cleared = confirmed received by payees financial institution; returned = payment rejected or returned by bank; stopped = payment halted before issuance; voided = payment cancelled and reversed.. Valid values are `scheduled|issued|cleared|returned|stopped|voided`',
    `payment_type` STRING COMMENT 'Classification of the benefit payment by its contractual or regulatory basis. Distinguishes annuitization income, Guaranteed Minimum Withdrawal Benefit (GMWB) payments, Guaranteed Minimum Income Benefit (GMIB) income, systematic withdrawals, Required Minimum Distributions (RMD), death benefit payouts, partial surrenders, and lump-sum settlements. [ENUM-REF-CANDIDATE: annuitization|gmwb_withdrawal|gmib_income|systematic_withdrawal|rmd_distribution|death_benefit|surrender_partial|lump_sum — promote to reference product]',
    `payout_phase` STRING COMMENT 'Indicates the contractual phase of the annuity contract at the time of this payment. accumulation = contract still in growth phase (e.g., systematic withdrawal); annuitization = contract has been annuitized and is in income phase; payout = living benefit payout phase; surrender = payment associated with full or partial surrender.. Valid values are `accumulation|annuitization|payout|surrender`',
    `reportable_amount_1099r` DECIMAL(18,2) COMMENT 'The gross distribution amount to be reported on IRS Form 1099-R Box 1 for this payment. For most payments equals gross_payment_amount; may differ for corrected or adjusted payments. Drives annual 1099-R tax form generation for the annuitant.',
    `rmd_tax_year` STRING COMMENT 'The IRS tax year (four-digit year) to which this RMD payment is attributed. Populated only when is_rmd_payment is True. Used for RMD compliance tracking and IRS reporting under IRC Section 401(a)(9).',
    `scheduled_payment_date` DATE COMMENT 'The contractually scheduled date on which the benefit payment was originally planned to be disbursed per the annuity payout schedule. Used to identify late payments and measure payment timeliness against contractual obligations.',
    `state_tax_withheld_amount` DECIMAL(18,2) COMMENT 'Dollar amount of state income tax withheld from the gross benefit payment per the annuitants state withholding election or applicable state mandatory withholding rules. Reported on IRS Form 1099-R Box 14.',
    `state_withholding_state_code` STRING COMMENT 'Two-letter USPS state code identifying the state for which state income tax was withheld on this payment. Reported on IRS Form 1099-R Box 15. Required for multi-state tax reporting compliance.. Valid values are `^[A-Z]{2}$`',
    `surrender_charge_amount` DECIMAL(18,2) COMMENT 'Contractual deferred sales charge (surrender charge) deducted from the payment amount when a withdrawal or surrender occurs within the surrender charge period defined in the annuity contract. Reduces the net payment to the annuitant.',
    `tax_year` STRING COMMENT 'The IRS tax year (four-digit calendar year) to which this benefit payment is attributed for 1099-R reporting purposes. Typically the year in which the payment_date falls, but may differ for year-end payments processed in January.',
    `taxable_amount` DECIMAL(18,2) COMMENT 'The portion of the gross payment amount that is subject to ordinary income tax. For non-qualified contracts, this equals gross payment minus the exclusion ratio amount. For qualified contracts, typically equals the full gross payment. Reported on IRS Form 1099-R Box 2a.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this benefit payment record was last modified in the source system. Used for incremental ETL processing in the Databricks Silver Layer and audit trail maintenance.',
    `withholding_election_type` STRING COMMENT 'Indicates the basis for federal tax withholding on this payment. elected = annuitant submitted a W-4P withholding election; mandatory = mandatory withholding applies (e.g., eligible rollover distributions); waived = annuitant elected to waive withholding where permitted under IRC Section 3405.. Valid values are `elected|mandatory|waived`',
    CONSTRAINT pk_benefit_payment PRIMARY KEY(`benefit_payment_id`)
) COMMENT 'Records each periodic income payment disbursed to an annuitant or beneficiary under an annuity payout schedule or living benefit claim. Captures payment date, scheduled payment amount, actual payment amount, federal and state tax withholding, net payment amount, payment method (ACH, check, wire), payment status, 1099-R reportable amount, exclusion ratio applied (for non-qualified contracts under IRC Section 72), and cumulative investment in contract recovered. Sourced from Sapiens Annuity payment processing module.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`tax_free_exchange` (
    `tax_free_exchange_id` BIGINT COMMENT 'Primary key for tax_free_exchange',
    `aml_case_id` BIGINT COMMENT 'Foreign key linking to compliance.aml_case. Business justification: 1035 exchanges require AML review per BSA source-of-funds verification requirements. High-value exchanges from unknown carriers trigger enhanced due diligence. Links exchange transactions to AML inves',
    `annuity_premium_payment_id` BIGINT COMMENT 'Foreign key linking to annuity.annuity_premium_payment. Business justification: A 1035 tax-free exchange transfers funds from a source contract to a new annuity contract, resulting in a premium payment on the new contract. The tax_free_exchange record tracks the exchange transact',
    `contract_id` BIGINT COMMENT 'Reference to the new (receiving) annuity contract issued as a result of this 1035 exchange. Links to the annuity contract master record.',
    `document_id` BIGINT COMMENT 'Foreign key linking to document.document. Business justification: 1035 tax-free exchanges require signed authorization forms and carrier acknowledgment letters per IRS regulations. Links exchange transaction to supporting documents for tax reporting, suitability rev',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: 1035 exchanges have specific accounting treatment requiring journal entries for cost basis transfer, gain deferral, and new contract establishment. Required for GAAP compliance and tax reporting (Form',
    `party_id` BIGINT COMMENT 'Reference to the policyholder or contract owner initiating the 1035 exchange. Used for KYC, AML, and tax reporting linkage.',
    `producer_id` BIGINT COMMENT 'Reference to the licensed agent or broker who facilitated the 1035 exchange transaction. Used for commission and suitability tracking.',
    `in_force_policy_id` BIGINT COMMENT 'Foreign key linking to policy.in_force_policy. Business justification: IRC Section 1035 tax-free exchange from a life policy to an annuity is a core regulatory compliance process requiring direct FK traceability to the originating life policy for cost basis transfer, IRS',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: 1035 exchanges INTO annuities from life insurance policies need to reference the original underwriting application for the surrendered life policy. Real business process: replacement documentation, su',
    `suitability_review_id` BIGINT COMMENT 'Foreign key linking to compliance.suitability_review. Business justification: NAIC Replacement Regulation requires a suitability review specific to 1035 exchange/replacement transactions. This is distinct from the premium payment suitability review — it evaluates whether the re',
    `workflow_id` BIGINT COMMENT 'Foreign key linking to document.workflow. Business justification: 1035 exchanges require multi-step document workflows: replacement notices, suitability reviews, carrier transfer forms, and NIGO resolution. Linking tax_free_exchange to its workflow enables SLA track',
    `aml_review_status` STRING COMMENT 'Status of the Anti-Money Laundering (AML) review conducted for this 1035 exchange transaction. Large or unusual exchanges may trigger enhanced due diligence under BSA/AML requirements.. Valid values are `not_required|pending|cleared|escalated`',
    `cancellation_reason` STRING COMMENT 'The reason for cancellation if the 1035 exchange was cancelled before completion. Captures owner-initiated cancellations, carrier rejections, or regulatory holds.',
    `completion_date` DATE COMMENT 'The date on which all funds were received from the source carrier and the exchange was fully processed and posted to the new annuity contract.',
    `cost_basis_transferred` DECIMAL(18,2) COMMENT 'The investment in contract (cost basis) transferred from the source contract to the new annuity contract. Preserves the owners after-tax basis for future distribution tax calculations under IRC Section 72.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this 1035 exchange record was first created in the annuity administration system. Used for audit trail and data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this exchange record. Typically USD for domestic US annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'The date on which the 1035 exchange is legally effective — i.e., when the transferred funds are applied to the new annuity contract and the tax-free treatment is established.',
    `exchange_reference_number` STRING COMMENT 'Externally-visible business reference number assigned to this 1035 exchange transaction, used in correspondence with the source carrier and the contract owner.',
    `exchange_status` STRING COMMENT 'Current workflow status of the 1035 exchange transaction. nigo indicates the exchange is Not In Good Order and requires remediation before processing can continue. [ENUM-REF-CANDIDATE: pending|in_progress|completed|cancelled|nigo|rejected — promote to reference product if additional statuses are needed]. Valid values are `pending|in_progress|completed|cancelled|nigo|rejected`',
    `exchange_type` STRING COMMENT 'Classification of the 1035 exchange based on the source and target contract types as permitted under IRC Section 1035. Annuity-to-annuity and life-to-annuity are the most common types in the annuity domain.. Valid values are `annuity_to_annuity|life_to_annuity|life_to_life|endowment_to_annuity`',
    `form_1099r_issued` BOOLEAN COMMENT 'Indicates whether IRS Form 1099-R has been issued to the contract owner and filed with the IRS for this 1035 exchange transaction.',
    `form_1099r_required` BOOLEAN COMMENT 'Indicates whether IRS Form 1099-R must be issued for this exchange. A 1099-R is required even for tax-free 1035 exchanges to report the distribution from the source contract, using distribution code 6.',
    `form_5498_issued` BOOLEAN COMMENT 'Indicates whether IRS Form 5498 has been issued to the contract owner and filed with the IRS for this 1035 exchange transaction.',
    `form_5498_required` BOOLEAN COMMENT 'Indicates whether IRS Form 5498 must be issued by the receiving carrier to report the rollover or exchange contribution to the new annuity contract.',
    `free_look_expiry_date` DATE COMMENT 'The date on which the free-look (right to return) period expires for the new annuity contract issued as a result of this exchange. State-mandated free-look periods typically range from 10 to 30 days.',
    `funds_received_date` DATE COMMENT 'The date on which the transferred funds were actually received from the source carrier by the receiving company. Used to track processing timelines and determine the contracts account value start date.',
    `gain_deferred` DECIMAL(18,2) COMMENT 'The amount of taxable gain deferred as a result of the 1035 exchange (transferred amount minus cost basis transferred). This gain is not recognized at the time of exchange but will be subject to ordinary income tax upon future distributions.',
    `is_mec_new_contract` BOOLEAN COMMENT 'Indicates whether the new annuity contract issued as a result of this exchange is classified as a Modified Endowment Contract (MEC). Determined based on MEC carryover from source and new contract funding.',
    `is_mec_source` BOOLEAN COMMENT 'Indicates whether the source contract was classified as a Modified Endowment Contract (MEC) under IRC Section 7702A. MEC status carries over to the new contract in a 1035 exchange, affecting tax treatment of distributions.',
    `nigo_reason` STRING COMMENT 'Free-text or coded description of the reason(s) the exchange application was flagged as Not In Good Order (NIGO). Documents the specific deficiency requiring remediation.',
    `nigo_resolved_date` DATE COMMENT 'The date on which all NIGO deficiencies were resolved and the exchange application was cleared for processing.',
    `nigo_status` STRING COMMENT 'Tracks the Not In Good Order (NIGO) resolution status for this exchange application. NIGO occurs when required documentation or information is missing or incorrect, preventing processing.. Valid values are `not_nigo|nigo_identified|nigo_in_remediation|nigo_resolved|nigo_cancelled`',
    `partial_exchange_indicator` BOOLEAN COMMENT 'Indicates whether this is a partial 1035 exchange (only a portion of the source contracts value is transferred) as opposed to a full exchange. Partial exchanges have specific IRS rules regarding basis allocation.',
    `replacement_notice_date` DATE COMMENT 'The date on which the replacement notice was sent to the contract owner as required by NAIC Model Regulation #613 and applicable state replacement regulations.',
    `replacement_notice_sent` BOOLEAN COMMENT 'Indicates whether the required replacement notice (NAIC Model Regulation on Replacement of Life Insurance and Annuities) was sent to the contract owner prior to processing the exchange.',
    `request_date` DATE COMMENT 'The date on which the contract owner formally submitted the 1035 exchange request. Used as the business event initiation date for processing timelines and regulatory reporting.',
    `source_account_value_at_exchange` DECIMAL(18,2) COMMENT 'The total account value (AV) of the source contract at the time of the exchange request. Used for partial exchange basis allocation calculations and suitability documentation.',
    `source_carrier_naic_code` STRING COMMENT 'The five-digit NAIC company code assigned to the source carrier. Used for regulatory identification and carrier verification during the exchange process.. Valid values are `^[0-9]{5}$`',
    `source_carrier_name` STRING COMMENT 'The name of the insurance company or financial institution from which the existing contract is being exchanged. Required for coordination of transfer and IRS Form 1099-R reporting.',
    `source_contract_issue_date` DATE COMMENT 'The original issue date of the source contract being exchanged. Used to determine the contracts age, surrender charge schedule applicability, and MEC status carryover.',
    `source_contract_type` STRING COMMENT 'The product type of the source contract being exchanged. Determines eligibility under IRC Section 1035 and influences tax treatment. [ENUM-REF-CANDIDATE: fixed_annuity|variable_annuity|fia|whole_life|universal_life|term_life — promote to reference product if additional types are needed]. Valid values are `fixed_annuity|variable_annuity|fia|whole_life|universal_life|term_life`',
    `source_surrender_charge_amount` DECIMAL(18,2) COMMENT 'The surrender charge or contingent deferred sales charge (CDSC) assessed by the source carrier upon surrender of the existing contract as part of the exchange. Reduces the net transferred amount.',
    `tax_year` STRING COMMENT 'The calendar tax year in which the 1035 exchange is reportable for IRS purposes. Determines the tax reporting period for Form 1099-R and Form 5498 filings.',
    `transfer_method` STRING COMMENT 'The method by which funds were transferred from the source carrier to the receiving company. Affects processing timelines and reconciliation procedures.. Valid values are `wire_transfer|check|direct_transfer|ach`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this 1035 exchange record was last modified in the annuity administration system. Used for change tracking and audit compliance.',
    CONSTRAINT pk_tax_free_exchange PRIMARY KEY(`tax_free_exchange_id`)
) COMMENT 'Manages tax-free 1035 exchange transactions where an existing annuity or life insurance contract is exchanged for a new annuity contract without triggering a taxable event under IRC Section 1035. Captures source contract details, source carrier, exchange request date, exchange effective date, transferred amount, cost basis transferred, gain deferred, IRS Form 1099-R and 5498 reporting flags, exchange type (annuity-to-annuity, life-to-annuity), and NIGO (Not In Good Order) resolution status. Critical for tax compliance and new business processing.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`rider_benefit` (
    `rider_benefit_id` BIGINT COMMENT 'Unique surrogate identifier for each rider or optional benefit record attached to an annuity contract. Primary key of this entity. Entity role: MASTER_AGREEMENT — represents a contractual benefit attachment with its own lifecycle, charge structure, and eligibility rules.',
    `annuitant_id` BIGINT COMMENT 'Foreign key linking to policyholder.annuitant. Business justification: Rider eligibility (LTC, joint-life, disability waiver, nursing home waiver) requires annuitant age, health status, and ADL impairment count. rider_benefit.annuitant_age_at_election is denormalized fro',
    `assumption_set_id` BIGINT COMMENT 'Foreign key linking to actuarial.assumption_set. Business justification: Living benefit rider reserve calculations (GMWB, GMIB, GMAB, GMDB) depend on actuarial assumption sets for lapse, utilization, and mortality. This link supports rider reserve adequacy review, charge r',
    `contract_id` BIGINT COMMENT 'Reference to the parent annuity contract to which this rider or benefit is attached. Links the rider to its owning contract record in the annuity contract administration system.',
    `gaap_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.gaap_reserve. Business justification: Rider benefits (GMDB, GMWB, GMIB, GMAB) are classified as Market Risk Benefits under LDTI, requiring fair value measurement in GAAP reserves. Finance teams link each rider benefit election to its GAAP',
    `derivative_contract_id` BIGINT COMMENT 'Foreign key linking to investment.derivative_contract. Business justification: GMWB/GMDB/GMIB riders are hedged with specific derivative contracts (equity options, variance swaps). This link supports GAAP ASC 815 hedge effectiveness testing, rider-level NAR hedge reporting, and ',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Optional riders (death benefit enhancements, income riders) create guaranteed liabilities hedged via derivative portfolios. Risk management calculates net amount at risk, hedge effectiveness, and RBC ',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Rider availability, charge rates, benefit structures, and eligibility rules vary by plan version. Essential for rider charge calculations, benefit eligibility validation, and tracking version-specific',
    `policy_form_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.policy_form_approval. Business justification: Rider forms require separate state approval; rider_form_number must match approved filing. Links rider elections to approved form filings for compliance validation. Essential for market conduct exams ',
    `pricing_basis_id` BIGINT COMMENT 'Foreign key linking to actuarial.pricing_basis. Business justification: Living benefit rider terms (charge_rate, rollup_rate, withdrawal_rate) are derived from actuarial pricing_basis assumptions. This link supports product profitability analysis, charge rate adequacy rev',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: Rider charges (GMWB, GMIB, GMAB charge rates) are subject to state rate filings and DOI approval. rider_benefit must reference the approved rate filing to validate that charge_rate complies with filed',
    `rider_definition_id` BIGINT COMMENT 'Foreign key linking to product.rider_definition. Business justification: Contract rider elections reference product rider definitions for benefit structure, charge rate schedules, eligibility rules, and underwriting requirements. Critical for rider charge calculations, ben',
    `risk_class_id` BIGINT COMMENT 'Foreign key linking to underwriting.risk_class. Business justification: Living benefit riders (GMIB, GMWB, GMDB, LTC) are priced and reserved using the insureds underwriting risk class. Rider charge rates and benefit eligibility thresholds are risk-class-dependent. Actua',
    `statutory_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.statutory_reserve. Business justification: Living benefit riders require dedicated statutory reserve components under CARVM and PBR. Appointed actuaries must link rider benefit records to statutory reserve calculations for annual statement Exh',
    `suitability_review_id` BIGINT COMMENT 'Foreign key linking to compliance.suitability_review. Business justification: Living benefit rider elections (GMWB, GMIB, GMAB) require suitability reviews under NAIC Senior Protection regulations, particularly for annuitants over 65. The rider_benefit must reference its suitab',
    `adl_trigger_count` STRING COMMENT 'Minimum number of Activities of Daily Living (ADL) impairments required to trigger benefit eligibility under an LTC rider. Typically 2 out of 6 standard ADLs per HIPAA Section 7702B. Null for non-LTC riders.',
    `benefit_base_amount` DECIMAL(18,2) COMMENT 'Current dollar value of the guaranteed benefit base associated with this rider. For GMWB/GMIB/GMAB riders, this is the protected value used to calculate guaranteed withdrawals or income. Distinct from account value (AV); may be higher than AV after market downturns. Tracked separately in benefit_base product but captured here as the riders principal financial fact.',
    `benefit_election_status` STRING COMMENT 'Indicates whether the contract owner has formally elected to begin receiving benefits under this rider. Not_elected = rider is in force but benefits not yet activated; Elected = owner has triggered benefit commencement; In_payout = benefit payments are actively being made; Exhausted = benefit pool fully depleted; Waived = owner waived benefit election rights.. Valid values are `not_elected|elected|in_payout|exhausted|waived`',
    `benefit_eligible_date` DATE COMMENT 'Earliest calendar date on which the contract owner becomes eligible to elect or receive benefits under this rider, calculated from the effective_date plus any applicable waiting period. Used in customer service, benefit election processing, and proactive outreach campaigns.',
    `charge_basis` STRING COMMENT 'The financial base against which the rider charge rate is applied. Benefit_base = charge applied to the guaranteed benefit base; Account_value = charge applied to the current account value (AV); Premium_base = charge applied to cumulative premiums paid; NAV = charge applied to net asset value for variable products.. Valid values are `benefit_base|account_value|premium_base|nav`',
    `charge_frequency` STRING COMMENT 'Frequency at which the rider charge is assessed and deducted from the contract. Drives billing cycle integration and account value deduction scheduling in the annuity administration platform.. Valid values are `daily|monthly|quarterly|annual`',
    `charge_rate` DECIMAL(18,2) COMMENT 'Annual rider charge rate expressed as a decimal (e.g., 0.009500 = 0.95% per annum) assessed against the benefit base or account value. This is the MEASUREMENT_OR_VALUE for this MASTER_AGREEMENT entity. Used in premium billing, account value deduction calculations, and profitability analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this rider benefit record was first created in the data platform (Silver layer). Serves as the RECORD_AUDIT_CREATED category for this MASTER_AGREEMENT entity. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX per platform conventions.',
    `death_benefit_type` STRING COMMENT 'Specifies the type of death benefit provided by this rider for GMDB or enhanced death benefit riders. Return_of_premium = beneficiary receives at least cumulative premiums paid; Highest_anniversary = DB equals highest contract anniversary value; Earnings_enhancement = DB includes a percentage of earnings; Standard = base contract DB with no enhancement; None = rider does not provide a death benefit.. Valid values are `return_of_premium|highest_anniversary|earnings_enhancement|standard|none`',
    `effective_date` DATE COMMENT 'Calendar date on which the rider becomes contractually effective and benefit guarantees begin to accrue. Marks the start of the riders binding period. Used in benefit base calculations, waiting period tracking, and actuarial reserving.',
    `election_date` DATE COMMENT 'Date on which the contract owner formally elected or added this rider to the annuity contract. May differ from effective_date if there is a processing lag or waiting period. Relevant for suitability review and new business processing audit trails.',
    `inflation_protection_type` STRING COMMENT 'Type of inflation protection feature included in the rider, primarily relevant for LTC riders. None = no inflation protection; Simple = benefit increases by a fixed percentage of the original benefit; Compound = benefit increases by a fixed percentage of the current benefit; CPI_linked = benefit increases tied to the Consumer Price Index.. Valid values are `none|simple|compound|cpi_linked`',
    `is_irrevocable` BOOLEAN COMMENT 'Indicates whether this rider, once elected, cannot be removed by the contract owner during the contracts life (True = irrevocable; False = owner may remove the rider). Relevant for LTC riders and certain GMIB riders that become irrevocable upon benefit election.',
    `is_optional` BOOLEAN COMMENT 'Indicates whether this rider was optionally elected by the contract owner (True) or is a mandatory benefit included in the base contract without separate election (False). Drives charge assessment logic and suitability review requirements.',
    `joint_life_indicator` BOOLEAN COMMENT 'Indicates whether this rider covers both the primary annuitant and a joint annuitant (True = joint life coverage; False = single life coverage). Joint life riders typically carry a higher charge rate and provide continued benefits upon the death of the first annuitant.',
    `ltc_benefit_period_months` STRING COMMENT 'Maximum number of months for which long-term care benefits are payable under an LTC rider. Applicable only to LTC rider types. Null for non-LTC riders. Used in LTC benefit pool calculations and NAIC Long-Term Care Insurance Model Regulation compliance reporting.',
    `max_benefit_amount` DECIMAL(18,2) COMMENT 'Contractual ceiling on the total benefit payable under this rider over its lifetime. Applicable to riders with aggregate benefit caps (e.g., LTC riders with lifetime maximum benefit pools, enhanced death benefit riders with maximum DB multiples). Null if no contractual maximum applies.',
    `max_charge_rate` DECIMAL(18,2) COMMENT 'Contractually guaranteed maximum annual charge rate that the insurer may assess for this rider, expressed as a decimal. Protects the contract owner from unlimited charge increases. Required disclosure under NAIC Annuity Disclosure Model Regulation.',
    `max_issue_age` STRING COMMENT 'Maximum age of the annuitant at which this rider may be elected, as defined in the riders contractual terms. Used in new business eligibility validation and underwriting rules engine checks.',
    `min_issue_age` STRING COMMENT 'Minimum age of the annuitant at which this rider may be elected, as defined in the riders contractual terms. Used in new business eligibility validation.',
    `reinsurance_indicator` BOOLEAN COMMENT 'Indicates whether the risk associated with this rider is subject to a reinsurance treaty (True = reinsured; False = retained). Relevant for GMDB and LTC riders which are commonly reinsured. Drives cession processing in the reinsurance management system.',
    `reserve_basis` STRING COMMENT 'Accounting basis under which actuarial reserves for this rider are calculated. GAAP = Generally Accepted Accounting Principles (FASB ASC 944 / LDTI); SAP = Statutory Accounting Principles (NAIC); PBR = Principle-Based Reserving; IFRS17 = International Financial Reporting Standards 17. Used in actuarial valuation system configuration.. Valid values are `GAAP|SAP|PBR|IFRS17`',
    `rider_status` STRING COMMENT 'Current lifecycle state of the rider or benefit attachment. Active = rider is in force and charges are being assessed; Suspended = rider temporarily not in force (e.g., during free-look period); Terminated = rider has been removed or contract surrendered; Pending = rider elected but not yet effective; Lapsed = rider lapsed due to non-payment of rider charge; Matured = rider has reached its contractual maturity date.. Valid values are `active|suspended|terminated|pending|lapsed|matured`',
    `rider_version` STRING COMMENT 'Version identifier of the rider product design, corresponding to a specific generation of benefit terms, charge rates, and eligibility rules. Insurers periodically update rider versions; this field distinguishes legacy riders from current offerings and is critical for actuarial valuation and reserving under LDTI.',
    `rollup_period_years` STRING COMMENT 'Maximum number of years during which the guaranteed rollup rate is applied to grow the benefit base. After this period, the benefit base stops rolling up but the rider may remain in force. Null if rollup continues indefinitely until benefit election.',
    `rollup_rate` DECIMAL(18,2) COMMENT 'Annual guaranteed growth rate applied to the benefit base during the accumulation (deferral) phase, expressed as a decimal (e.g., 0.060000 = 6.00% per annum). Applicable to GMWB, GMIB, and GMAB riders. Null for riders without a rollup feature. Critical input for actuarial reserving and LDTI cash flow projections.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this rider benefit record was sourced (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Used for data lineage tracking, ETL reconciliation, and Silver layer audit in the Databricks Lakehouse.',
    `source_system_rider_reference` STRING COMMENT 'Native identifier of this rider record in the originating operational system of record (e.g., Sapiens Annuity internal rider ID). Enables back-referencing to the source system for reconciliation, issue resolution, and ETL lineage tracing.',
    `state_availability` STRING COMMENT 'Comma-separated list of US state codes (2-letter USPS abbreviations) in which this rider form has been approved and is available for sale. Null or ALL if available in all states. Used in new business eligibility validation and regulatory compliance tracking.',
    `step_up_frequency` STRING COMMENT 'Frequency at which the automatic step-up (ratchet) evaluation occurs for the benefit base. Annual = evaluated each contract anniversary; Triennial = every 3 years; Quinquennial = every 5 years; On_demand = owner may request step-up at any time subject to conditions; None = no step-up provision. Null if step_up_provision is False.. Valid values are `annual|triennial|quinquennial|on_demand|none`',
    `step_up_provision` BOOLEAN COMMENT 'Indicates whether this rider includes an automatic or optional step-up (ratchet) provision that locks in market gains by resetting the benefit base to the current account value if the account value exceeds the benefit base on a specified anniversary date. True = step-up provision exists; False = no step-up.',
    `termination_date` DATE COMMENT 'Calendar date on which the rider was or is scheduled to be terminated. Null if the rider is still in force. Populated upon rider lapse, voluntary removal, contract surrender, annuitization, or death claim settlement.',
    `termination_trigger` STRING COMMENT 'The contractual condition or event that caused or will cause this rider to terminate. Surrender = full contract surrender; Death = death of the annuitant or owner; Annuitization = contract converted to income stream; Account_value_zero = account value depleted to zero; Owner_request = voluntary rider removal by owner; Non_payment = rider charge could not be deducted. Null if rider is still active.. Valid values are `surrender|death|annuitization|account_value_zero|owner_request|non_payment`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this rider benefit record was last modified in the data platform. Used for incremental ETL processing, change data capture, and audit trail compliance under SOX. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX per platform conventions.',
    `waiting_period_years` STRING COMMENT 'Number of contract years that must elapse before the contract owner is eligible to elect benefits under this rider. Common for GMIB riders which typically require a 10-year deferral period before annuitization. Zero if no waiting period applies.',
    `withdrawal_rate` DECIMAL(18,2) COMMENT 'Annual guaranteed withdrawal percentage of the benefit base that the contract owner may withdraw each year without reducing the guaranteed benefit, expressed as a decimal (e.g., 0.050000 = 5.00%). Applicable to GMWB riders. May vary by age band at election. Null for non-GMWB riders.',
    CONSTRAINT pk_rider_benefit PRIMARY KEY(`rider_benefit_id`)
) COMMENT 'Master record for each optional rider or benefit attached to an annuity contract, including GMWB, GMIB, GMAB, GMDB (Guaranteed Minimum Death Benefit), enhanced death benefit, long-term care (LTC) riders, return-of-premium riders, and earnings enhancement riders. Captures rider type, rider effective date, rider charge rate, benefit election status, benefit trigger conditions, maximum benefit amount, rider termination conditions, and rider version/form number. Distinct from benefit_base which tracks the financial balance of living benefit guarantees; this entity tracks the contractual terms, eligibility rules, and charge structure of the rider.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`annuity_premium_payment` (
    `annuity_premium_payment_id` BIGINT COMMENT 'Unique surrogate identifier for each annuity premium payment transaction record in the annuity payment receipt ledger.',
    `aml_case_id` BIGINT COMMENT 'Reference to the AML case record in the compliance domain when this payment has been escalated for AML investigation. Null if no AML case has been opened for this payment.',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract to which this premium payment is applied. Links the payment to the contract administration record in the Annuity Administration Platform.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Premium receipts require journal entries for cash receipt (debit), premium revenue recognition (credit), premium load (credit), and DAC capitalization (debit). Core accounting transaction for every pr',
    `premium_schedule_id` BIGINT COMMENT 'Reference to the modal premium schedule that governs the payment frequency and amount for flexible premium deferred annuities. Null for single-premium or ad-hoc payments not tied to a scheduled billing cycle.',
    `party_id` BIGINT COMMENT 'Reference to the party record of the annuity contract owner who is making or authorizing the premium payment. Used for KYC/AML validation and tax reporting under IRC Section 72.',
    `premium_bill_id` BIGINT COMMENT 'Foreign key linking to billing.premium_bill. Business justification: Annuity premium reconciliation requires tracing each annuity_premium_payment to the premium_bill that triggered it. Supports billing statement reconciliation, audit trails, and NSF/grace period proces',
    `sar_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.sar_filing. Business justification: BSA/AML regulations require SAR filings for suspicious premium payments (e.g., large cash deposits, structuring). annuity_premium_payment needs a direct sar_filing_id for the SAR reporting workflow — ',
    `suitability_review_id` BIGINT COMMENT 'Reference to the suitability review record in the compliance domain associated with this premium payment, particularly for subsequent premium payments that may trigger re-suitability assessment under NAIC Annuity Suitability Model Regulation.',
    `suspense_account_id` BIGINT COMMENT 'Reference to the suspense account record where the payment funds are held pending NIGO resolution or contract identification. Null for payments applied directly without suspense.',
    `application_id` BIGINT COMMENT 'Foreign key linking to underwriting.application. Business justification: Premium payments on annuities may reference the originating underwriting application for audit trail, especially for 1035 exchanges from life policies or initial annuity applications requiring underwr',
    `ach_trace_number` STRING COMMENT 'The ACH trace number assigned by the originating depository financial institution (ODFI) for ACH electronic payment transactions. Used for NACHA reconciliation and return item tracking when payment_source is ach.',
    `aml_review_flag` BOOLEAN COMMENT 'Flag indicating whether this payment has been flagged for AML review due to large cash transaction reporting thresholds, structuring patterns, or other suspicious activity indicators per FinCEN BSA requirements.',
    `applied_amount` DECIMAL(18,2) COMMENT 'The net dollar amount actually credited to the annuity contract Account Value (AV) after deduction of any applicable premium load, surrender charges on exchanged contracts, or other fees. May equal gross_payment_amount if no deductions apply.',
    `bonus_credited_amount` DECIMAL(18,2) COMMENT 'The actual dollar amount of premium bonus credited to the contract AV as a result of this payment. Calculated as bonus_eligible_amount multiplied by the applicable bonus rate per the contract terms.',
    `bonus_eligible_amount` DECIMAL(18,2) COMMENT 'The portion of the gross payment amount that qualifies for a premium bonus credit under the annuity contract terms. Some annuity products offer a percentage bonus on qualifying premium payments. Null if the contract does not offer a premium bonus.',
    `check_number` STRING COMMENT 'The check number printed on the physical check when payment_source is check. Used for bank reconciliation and payment tracing. Null for non-check payment sources.',
    `contract_year` STRING COMMENT 'The contract year in which this payment falls, calculated from the contract issue date. Used for surrender charge schedule application, bonus crediting eligibility, and actuarial valuation purposes.',
    `cost_basis_contribution` DECIMAL(18,2) COMMENT 'The after-tax cost basis amount contributed by this payment to the annuity contracts cumulative investment in the contract (IIC). For non-qualified annuities, this is the after-tax portion of the payment. For qualified annuities, this is typically zero. Critical for IRC Section 72 exclusion ratio calculations and IRS Form 1099-R reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this payment record was first created in the annuity administration system. Used for audit trail, data lineage, and SOX compliance.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the payment amount. Typically USD for domestic US annuity contracts. Required for multi-currency reporting and GAAP/SAP financial statements.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'The contract effective date on which the payment is credited to the annuity contract Account Value (AV). May differ from payment_date due to processing lag, back-dating rules, or 1035 exchange settlement timing.',
    `exchange_cost_basis_received` DECIMAL(18,2) COMMENT 'The cost basis (investment in the contract) transferred from the surrendered contract in a 1035 exchange. This amount carries over to the new annuity contract and is critical for IRC Section 72 exclusion ratio calculations. Null for non-exchange payments.',
    `exchange_source_carrier` STRING COMMENT 'Name of the insurance carrier or financial institution from which 1035 exchange proceeds were transferred. Required for 1035 exchange documentation and AML source-of-funds verification.',
    `exchange_source_contract_number` STRING COMMENT 'The contract or policy number of the surrendered/exchanged contract from which 1035 exchange proceeds originated. Required for IRS Form 1035 documentation and audit trail when is_1035_exchange = true. Null for non-exchange payments.',
    `gross_payment_amount` DECIMAL(18,2) COMMENT 'The total gross dollar amount of the premium payment as received from the payor before any deductions, fees, or adjustments. This is the base monetary amount used for AV crediting and cost basis calculations.',
    `is_1035_exchange` BOOLEAN COMMENT 'Flag indicating whether this payment represents proceeds received from a tax-free 1035 exchange (IRC Section 1035 — Tax-Free Insurance Policy Exchange). When true, additional 1035 exchange tracking fields apply and the payment requires IRS Form 1035 documentation.',
    `is_unscheduled` BOOLEAN COMMENT 'Flag indicating whether this payment is an unscheduled additional premium contribution not tied to the modal premium schedule. Common for flexible premium deferred annuities where owners make ad-hoc contributions.',
    `nigo_reason` STRING COMMENT 'Free-text description of the NIGO deficiency reason when nigo_status is nigo_pending or nigo_rejected. Examples: missing suitability form, missing signature, missing source of funds documentation, incomplete beneficiary designation.',
    `nigo_resolution_date` DATE COMMENT 'The date on which the NIGO deficiency was resolved and the payment was cleared for application to the annuity contract. Null if nigo_status is good_order or nigo_pending.',
    `nigo_status` STRING COMMENT 'Indicates whether the payment application was received in good order or flagged as Not In Good Order (NIGO). good_order = all required documentation and information received; nigo_pending = deficiency identified, awaiting resolution; nigo_resolved = NIGO deficiency resolved and payment applied; nigo_rejected = NIGO could not be resolved and payment returned.. Valid values are `good_order|nigo_pending|nigo_resolved|nigo_rejected`',
    `payment_date` DATE COMMENT 'The business date on which the premium payment was received by the company. This is the principal real-world event date used for contract crediting, cost basis tracking, and IRC Section 72 tax reporting.',
    `payment_frequency` STRING COMMENT 'The modal frequency at which this payment is made under the contracts premium schedule. single = one-time single premium; annual = annual mode; semi_annual = semi-annual mode; quarterly = quarterly mode; monthly = monthly mode. Drives premium billing schedule and APE (Annual Premium Equivalent) calculations.. Valid values are `single|annual|semi_annual|quarterly|monthly`',
    `payment_number` STRING COMMENT 'Externally visible, human-readable reference number assigned to this premium payment transaction by the Annuity Administration Platform (e.g., Sapiens Annuity or FAST Annuity). Used for reconciliation, customer correspondence, and audit trails.',
    `payment_source` STRING COMMENT 'The remittance instrument or channel through which the premium payment funds were received. Drives reconciliation workflows and AML monitoring thresholds. check = personal or cashiers check; wire = wire transfer; ach = ACH electronic funds transfer; 1035_exchange = proceeds from a 1035 tax-free exchange; rollover_check = qualified plan rollover check; credit_card = credit card payment.. Valid values are `check|wire|ach|1035_exchange|rollover_check|credit_card`',
    `payment_status` STRING COMMENT 'Current lifecycle status of the premium payment transaction. pending = received but not yet applied to contract AV; posted = successfully applied; reversed = payment reversed after posting; returned = payment returned by financial institution (e.g., NSF); suspended = held in suspense pending NIGO resolution; rejected = rejected and not applied.. Valid values are `pending|posted|reversed|returned|suspended|rejected`',
    `payment_type` STRING COMMENT 'Classification of the premium payment by its business purpose. initial_single_premium = first and only premium for SPIAs or single-premium deferred annuities; subsequent_flexible_premium = additional premium for flexible premium deferred annuities; 1035_exchange_proceeds = funds received via a tax-free 1035 exchange; rollover = qualified plan rollover (IRA, 401k); transfer = direct trustee-to-trustee transfer. [ENUM-REF-CANDIDATE: initial_single_premium|subsequent_flexible_premium|1035_exchange_proceeds|rollover|transfer|direct_transfer|trustee_transfer — promote to reference product]. Valid values are `initial_single_premium|subsequent_flexible_premium|1035_exchange_proceeds|rollover|transfer`',
    `payor_name` STRING COMMENT 'Full legal name of the individual or entity that remitted the premium payment. May differ from the contract owner when a third party remits payment. Required for AML/KYC source-of-funds verification and IRS tax reporting.',
    `payor_relationship_to_owner` STRING COMMENT 'Describes the relationship of the payor to the annuity contract owner when the payor is not the owner. Used for AML third-party payment monitoring and suitability review. self = owner is the payor. [ENUM-REF-CANDIDATE: self|spouse|parent|child|trust|employer|other — 7 candidates stripped; promote to reference product]',
    `premium_load_amount` DECIMAL(18,2) COMMENT 'Dollar amount of premium load or front-end charge deducted from the gross payment before crediting to the contract AV. Represents the difference between gross_payment_amount and applied_amount attributable to premium loads.',
    `reversal_date` DATE COMMENT 'The date on which the payment reversal was processed and the AV adjustment was made to the annuity contract. Null for non-reversed payments.',
    `reversal_reason` STRING COMMENT 'Description of the reason for payment reversal when payment_status is reversed. Examples: duplicate payment, incorrect contract application, owner request, NSF return. Null for non-reversed payments.',
    `scheduled_payment_amount` DECIMAL(18,2) COMMENT 'The contractually scheduled premium amount for this payment period as defined in the modal premium schedule. Compared against gross_payment_amount to identify over-payments, under-payments, or unscheduled additional premiums.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this payment record originated. Supports data lineage tracking in the Databricks Silver Layer. SAPIENS_ANNUITY = Sapiens Annuity platform; FAST_ANNUITY = FAST Annuity platform; POLICY_ADMIN = Policy Administration System; MANUAL = manually entered correction.. Valid values are `SAPIENS_ANNUITY|FAST_ANNUITY|POLICY_ADMIN|MANUAL`',
    `source_transaction_reference` STRING COMMENT 'The native transaction identifier assigned by the originating operational system (e.g., Sapiens Annuity or FAST Annuity) for this payment record. Used for data lineage, reconciliation between Silver Layer and source systems, and audit trail.',
    `tax_qualification_code` STRING COMMENT 'Indicates the tax qualification status of the premium payment, which determines cost basis treatment and tax reporting obligations under IRC Section 72. qualified = pre-tax qualified plan funds (IRA, 401k, 403b); non_qualified = after-tax funds; roth_ira = Roth IRA funds; sep_ira = SEP-IRA; simple_ira = SIMPLE IRA; 403b = 403(b) tax-sheltered annuity. [ENUM-REF-CANDIDATE: qualified|non_qualified|roth_ira|sep_ira|simple_ira|403b|457b|pension — promote to reference product]. Valid values are `qualified|non_qualified|roth_ira|sep_ira|simple_ira|403b`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this payment record was last modified in the annuity administration system. Tracks status changes, NIGO resolution updates, and corrections.',
    `wire_reference_number` STRING COMMENT 'The wire transfer reference or IMAD (Input Message Accountability Data) number assigned by the sending financial institution when payment_source is wire. Used for Fedwire reconciliation and AML source-of-funds documentation.',
    CONSTRAINT pk_annuity_premium_payment PRIMARY KEY(`annuity_premium_payment_id`)
) COMMENT 'Records all premium and purchase payment transactions applied to annuity contracts, including initial single premiums, subsequent flexible premiums (for flexible premium deferred annuities), and 1035 exchange proceeds received. Captures payment date, payment amount, payment source (check, wire, ACH, 1035 exchange), tax qualification of payment (qualified/non-qualified), cost basis contribution, modal premium schedule reference, and NIGO resolution status. Distinct from billing domain premium billing records; this is the annuity-specific payment receipt ledger.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`cost_basis_ledger` (
    `cost_basis_ledger_id` BIGINT COMMENT 'Unique surrogate identifier for each cost basis ledger record in the annuity domain. Primary key for the cost_basis_ledger data product.',
    `annuitant_id` BIGINT COMMENT 'Foreign key linking to policyholder.annuitant. Business justification: IRC §72 exclusion ratio calculation requires the annuitants age at annuity start date. cost_basis_ledger.owner_age_at_annuity_start is a denormalized value from annuitant; a direct FK enables exclusi',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract for which this cost basis ledger record is maintained. Links to the annuity contract master.',
    `contract_owner_id` BIGINT COMMENT 'Reference to the contract owner (policyholder) party record. The owner is the taxpayer responsible for IRC Section 72 cost basis tracking and 1099-R reporting.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Cost basis adjustments (1035 exchange basis transfers, partial surrender basis reductions, MEC reclassifications) generate journal entries for deferred gain/loss accounting. Finance teams link cost ba',
    `mortality_table_id` BIGINT COMMENT 'Foreign key linking to actuarial.mortality_table. Business justification: Exclusion ratio calculations for annuity taxation use IRS mortality tables (IRC Section 72) to determine expected return. Required for accurate Form 1099-R reporting, tax compliance, and audit defense',
    `plan_version_id` BIGINT COMMENT 'Foreign key linking to product.plan_version. Business justification: Tax qualification rules, IRC 72 compliance parameters, and exclusion ratio calculations are version-specific. Required for accurate 1099-R reporting, cost basis recovery calculations, and ensuring ver',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Cost basis ledgers directly support IRS Form 1099-R and Form 5498 regulatory filings. The cost_basis_ledger must reference the regulatory filing it supports for tax reporting compliance and audit trai',
    `tax_free_exchange_id` BIGINT COMMENT 'Foreign key linking to annuity.tax_free_exchange. Business justification: cost_basis_ledger tracks investment in contract (cost basis) including exchange_basis_received and source_contract_number fields that indicate 1035 exchange origin. tax_free_exchange manages the 1035 ',
    `annual_exclusion_amount` DECIMAL(18,2) COMMENT 'The annual dollar amount of annuity payments that is excludable from gross income under the exclusion ratio. Equals the periodic payment amount times payment frequency times the exclusion ratio. Reported as the non-taxable amount on IRS Form 1099-R.',
    `annuitization_start_date` DATE COMMENT 'The date on which the annuity contract entered the payout (annuitization) phase. Marks the transition from accumulation to distribution phase and triggers the exclusion ratio calculation for periodic payments.',
    `annuity_start_date_basis` STRING COMMENT 'Indicates the event that established the annuity start date for IRC Section 72 purposes. Determines which date is used as the reference point for expected return and exclusion ratio calculations.. Valid values are `contract_issue|annuitization|1035_exchange|rider_election`',
    `contract_issue_date` DATE COMMENT 'The date the annuity contract was originally issued. Establishes the start of the investment-in-contract accumulation period for IRC Section 72 cost basis purposes.',
    `cost_basis_adjustment_reason` STRING COMMENT 'The reason code for the most recent adjustment to the investment in contract. Used for audit trail and tax reporting reconciliation. [ENUM-REF-CANDIDATE: 1035_exchange_in|1035_exchange_out|partial_surrender|correction|court_order|divorce_transfer|death_claim|annuitization|premium_addition — promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this cost basis ledger record was first created in the system. Used for audit trail and data lineage tracking.',
    `cumulative_premiums_paid` DECIMAL(18,2) COMMENT 'Total after-tax premium contributions made to the annuity contract since inception or since the last 1035 exchange. Represents the gross cost basis before adjustments for tax-free distributions received.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this cost basis ledger record. Typically USD for domestic annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `distribution_code` STRING COMMENT 'The IRS distribution code to be reported in Box 7 of IRS Form 1099-R. Indicates the type of distribution for tax purposes (e.g., 1=early distribution no exception, 2=early distribution exception applies, 4=death, 6=1035 exchange, 7=normal distribution). [ENUM-REF-CANDIDATE: 1|2|3|4|5|6|7|8|9|A|B|C|D|E|F|G|H|J|K|L|M|N|P|Q|R|S|T|U|W — promote to reference product]. Valid values are `1|2|3|4|6|7`',
    `early_withdrawal_penalty_applies` BOOLEAN COMMENT 'Indicates whether the 10% additional tax on early distributions under IRC Section 72(q) applies to distributions from this contract. True if the owner is under age 59½ and no exception applies.',
    `exchange_basis_received` DECIMAL(18,2) COMMENT 'The cost basis transferred into this annuity contract from a prior contract via a tax-free 1035 exchange. Carries over the investment-in-contract from the surrendered contract per IRC Section 1035.',
    `exchange_basis_transferred_out` DECIMAL(18,2) COMMENT 'The cost basis transferred out of this annuity contract to a receiving contract via a tax-free 1035 exchange. Reduces the investment-in-contract of this contract.',
    `exclusion_ratio` DECIMAL(18,2) COMMENT 'The ratio of the investment in contract to the expected return, expressed as a decimal (e.g., 0.35000000 = 35%). Applied to each annuity payment to determine the non-taxable portion under IRC Section 72(b). Calculated as remaining_investment_in_contract divided by expected_return.',
    `exclusion_ratio_exhausted` BOOLEAN COMMENT 'Indicates whether the investment in contract has been fully recovered through prior non-taxable distributions. When True, all future annuity payments are fully taxable with no exclusion allowed under IRC Section 72(b)(2).',
    `exclusion_ratio_exhausted_date` DATE COMMENT 'The date on which the investment in contract was fully recovered and the exclusion ratio was exhausted. Null if the exclusion ratio has not yet been exhausted.',
    `expected_return` DECIMAL(18,2) COMMENT 'The total amount expected to be received under the annuity contract over the payment period, calculated using IRS actuarial tables (life expectancy multiples) per IRC Section 72(c). Used as the denominator in the exclusion ratio calculation.',
    `expected_return_multiple` DECIMAL(18,2) COMMENT 'The life expectancy multiple from the applicable IRS actuarial table (IRS Publication 939) used to calculate the expected return. Expressed in years (e.g., 20.0 years). Multiplied by the annual payment amount to derive the expected return.',
    `form_1099r_box1_amount` DECIMAL(18,2) COMMENT 'The gross distribution amount to be reported in Box 1 of IRS Form 1099-R for the applicable tax year. Represents total distributions paid from the contract during the tax year.',
    `form_1099r_box2a_amount` DECIMAL(18,2) COMMENT 'The taxable amount to be reported in Box 2a of IRS Form 1099-R for the applicable tax year. Represents the portion of gross distributions that is includable in gross income after applying the exclusion ratio.',
    `form_1099r_taxable_amount_not_determined` BOOLEAN COMMENT 'Indicates whether the taxable amount cannot be determined by the insurance company and Box 2b Taxable amount not determined should be checked on IRS Form 1099-R. True when the company lacks sufficient cost basis information to compute the taxable amount.',
    `investment_in_contract` DECIMAL(18,2) COMMENT 'The cumulative after-tax investment in the annuity contract as defined under IRC Section 72(e)(6). Represents the total premiums paid less any amounts previously received tax-free. This is the primary cost basis figure used for exclusion ratio calculations and 1099-R reporting.',
    `last_adjustment_date` DATE COMMENT 'The date of the most recent adjustment to the investment in contract (cost basis). Used for audit trail and reconciliation with the annuity administration platform.',
    `ledger_as_of_date` DATE COMMENT 'The business date through which this cost basis ledger snapshot is current. Used for point-in-time reporting, year-end tax reporting, and 1099-R preparation.',
    `ledger_effective_date` DATE COMMENT 'The date on which this cost basis ledger record became effective, typically the contract issue date or the date of a 1035 exchange that established the initial investment in contract.',
    `ledger_status` STRING COMMENT 'Current lifecycle status of the cost basis ledger record. Active indicates ongoing tracking; closed indicates the contract has been fully surrendered or annuitized; suspended indicates a hold pending review or correction; pending_review indicates an audit or reconciliation is in progress.. Valid values are `active|closed|suspended|pending_review`',
    `mec_determination_date` DATE COMMENT 'The date on which the contract was determined to be or not to be a Modified Endowment Contract (MEC). Null if MEC determination has not been triggered.',
    `mec_status` BOOLEAN COMMENT 'Indicates whether the annuity contract has been classified as a Modified Endowment Contract (MEC) under IRC Section 7702A. MEC status affects the tax treatment of distributions, subjecting them to LIFO (last-in, first-out) income recognition and potential 10% penalty tax.',
    `nontaxable_distributions_received` DECIMAL(18,2) COMMENT 'Cumulative amount of distributions that have been treated as non-taxable return of cost basis (investment in contract) under the IRC Section 72 exclusion ratio. Reduces the remaining investment in contract.',
    `partial_surrender_basis_adjustment` DECIMAL(18,2) COMMENT 'Cumulative reduction to the investment in contract resulting from partial surrenders or withdrawals that returned cost basis to the owner. Tracks the pro-rata cost basis recovery applied to partial surrenders of non-qualified annuities.',
    `payout_option` STRING COMMENT 'The annuitization payout option elected by the contract owner. Determines the expected return calculation method and applicable IRS actuarial table (Table V, VI, or VII) for the exclusion ratio.. Valid values are `life_only|life_with_period_certain|joint_and_survivor|period_certain_only|lump_sum`',
    `periodic_payment_amount` DECIMAL(18,2) COMMENT 'The fixed periodic payment amount received under the annuitization option. Used to calculate the annual exclusion amount (periodic_payment_amount multiplied by payment frequency multiplied by exclusion_ratio).',
    `remaining_investment_in_contract` DECIMAL(18,2) COMMENT 'The remaining unrecovered cost basis in the annuity contract as of the ledger_as_of_date. Calculated as investment_in_contract minus nontaxable_distributions_received. Drives the exclusion ratio for future annuity payments.',
    `source_contract_number` STRING COMMENT 'The contract number of the prior annuity or life insurance contract from which cost basis was received via a 1035 exchange. Null if no 1035 exchange occurred.',
    `tax_year` STRING COMMENT 'The calendar tax year for which this cost basis ledger snapshot is prepared. Used for annual 1099-R tax reporting and IRS compliance. Format: YYYY (e.g., 2024).',
    `taxable_distributions_received` DECIMAL(18,2) COMMENT 'Cumulative amount of distributions that have been treated as taxable income (earnings above cost basis) under IRC Section 72. Reported on IRS Form 1099-R Box 2a.',
    `total_distributions_received` DECIMAL(18,2) COMMENT 'Cumulative gross distributions (withdrawals, partial surrenders, annuity payments) received from the contract since inception. Used in conjunction with the exclusion ratio to determine the taxable and non-taxable portions of each distribution.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this cost basis ledger record was most recently modified. Used for change tracking, audit trail, and incremental ETL processing in the Databricks Lakehouse Silver Layer.',
    CONSTRAINT pk_cost_basis_ledger PRIMARY KEY(`cost_basis_ledger_id`)
) COMMENT 'Tracks the investment in contract (cost basis) for each annuity contract for IRC Section 72 tax reporting purposes. Captures cumulative after-tax premiums paid, cost basis adjustments from 1035 exchanges, partial surrender cost basis recovery, exclusion ratio calculation inputs, total distributions received, remaining investment in contract, and MEC (Modified Endowment Contract) status flag. Essential for accurate 1099-R tax reporting and IRC Section 72 exclusion ratio calculations for non-qualified annuities.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`contract_valuation` (
    `contract_valuation_id` BIGINT COMMENT 'Unique surrogate identifier for each contract valuation snapshot record in the Silver layer lakehouse. Primary key for this entity.',
    `account_value_id` BIGINT COMMENT 'Foreign key linking to annuity.account_value. Business justification: contract_valuation is a periodic valuation snapshot capturing the full financial position of an annuity contract. account_value is the authoritative periodic valuation ledger for the same contract. A ',
    `assumption_set_id` BIGINT COMMENT 'Foreign key linking to actuarial.assumption_set. Business justification: LDTI/GAAP reserve reporting requires tracing which actuarial assumption set (discount rate, lapse, mortality) produced each contract valuation snapshot. Actuaries and finance teams depend on this link',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract being valued. Links this valuation snapshot to the parent annuity contract master record.',
    `gaap_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.gaap_reserve. Business justification: Valuation outputs feed GAAP reserve calculations for financial statement liability reporting under LDTI. Actuarial cash flow projections and discount rates from valuation runs populate reserve balance',
    `party_id` BIGINT COMMENT 'Reference to the contract owner/policyholder party record. Supports policyholder-level aggregation and annual statement generation.',
    `portfolio_id` BIGINT COMMENT 'Foreign key linking to investment.portfolio. Business justification: Contract valuation snapshots must reference the investment portfolio driving reserve calculations for ALM reporting, GAAP/STAT reserve attribution, and investment performance reporting. Actuaries and ',
    `scenario_set_id` BIGINT COMMENT 'Foreign key linking to actuarial.scenario_set. Business justification: Variable and FIA annuity contract valuations under VM-21 CTE70 stochastic reserving reference a specific economic scenario set. This link enables traceability of which scenario set drove a contract-le',
    `statutory_reserve_id` BIGINT COMMENT 'Foreign key linking to finance.statutory_reserve. Business justification: Valuation run results directly populate statutory reserve amounts for regulatory filings. Actuarial valuation outputs feed reserve balances reported in NAIC Annual Statement and state regulatory submi',
    `valuation_run_id` BIGINT COMMENT 'Identifier for the actuarial valuation batch run that produced this record. Enables traceability of valuation results back to a specific run of the actuarial valuation system (MoSes, AXIS, or Prophet). Supports audit and restatement workflows.',
    `account_value` DECIMAL(18,2) COMMENT 'The total Account Value (AV) of the annuity contract as of the valuation date. Represents the accumulated fund value including premiums paid, credited interest/index credits, and less withdrawals and charges. Core financial metric for annuity contract administration.',
    `accrued_rider_charges` DECIMAL(18,2) COMMENT 'Total rider charges accrued but not yet deducted from the AV as of the valuation date. Includes charges for GMWB, GMIB, GMAB, GMDB, and other optional benefit riders. Used for accurate AV reconciliation and income statement accruals.',
    `annuitization_date` DATE COMMENT 'The date on which the contract transitioned from the accumulation phase to the annuitization/payout phase. Null if the contract has not yet been annuitized. Triggers shift from AV-based to income-stream-based valuation.',
    `cash_surrender_value` DECIMAL(18,2) COMMENT 'The Cash Surrender Value (CSV) available to the contract owner upon full surrender as of the valuation date. Equals AV less applicable surrender charges and market value adjustments. Used for policyholder statements and surrender processing.',
    `contract_phase` STRING COMMENT 'Current lifecycle phase of the annuity contract at the valuation date. Accumulation phase tracks AV growth; annuitization/payout phase tracks income stream; surrender and death claim phases indicate terminal events.. Valid values are `accumulation|annuitization|payout|surrender|death_claim`',
    `cost_basis` DECIMAL(18,2) COMMENT 'The owners investment in the contract (cost basis) as of the valuation date per IRC Section 72. Represents after-tax premiums paid less any tax-free distributions received. Used to determine the taxable gain upon surrender or annuitization.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this contract valuation record was first created in the Silver layer lakehouse. Supports audit trail and data lineage requirements under SOX.',
    `credited_interest_rate` DECIMAL(18,2) COMMENT 'The current credited interest rate applied to the contract AV for the valuation period. For fixed annuities, this is the declared rate. For FIA contracts, this reflects the effective rate after index crediting. Expressed as a decimal (e.g., 0.045 = 4.5%).',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this valuation record. Typically USD for domestic US annuity contracts.. Valid values are `^[A-Z]{3}$`',
    `death_benefit_amount` DECIMAL(18,2) COMMENT 'The Death Benefit (DB) payable to the beneficiary upon the death of the annuitant or contract owner as of the valuation date. May equal AV, a return-of-premium guarantee, or a stepped-up value depending on contract terms.',
    `gaap_reserve` DECIMAL(18,2) COMMENT 'The GAAP (Generally Accepted Accounting Principles) reserve for this contract as of the valuation date, calculated under FASB ASC 944 including LDTI requirements. Supports financial statement reporting and SOX compliance.',
    `gmab_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Accumulation Benefit (GMAB) benefit base as of the valuation date. Represents the guaranteed minimum AV at the end of the accumulation period, protecting against investment losses.',
    `gmab_rider_active` BOOLEAN COMMENT 'Indicates whether the GMAB rider is currently active on this contract as of the valuation date. Drives inclusion of GMAB benefit base and maturity guarantee calculations.',
    `gmdb_value` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Death Benefit (GMDB) base or benefit amount as of the valuation date. Represents the minimum death benefit guaranteed regardless of investment performance. Applicable for variable and indexed annuities with GMDB riders.',
    `gmib_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Income Benefit (GMIB) benefit base as of the valuation date. Used to calculate the minimum annuitization income stream the contract owner is guaranteed upon exercising the GMIB rider.',
    `gmib_rider_active` BOOLEAN COMMENT 'Indicates whether the GMIB rider is currently active on this contract as of the valuation date. Drives inclusion of GMIB benefit base calculations and annuitization guarantee valuations.',
    `gmwb_annual_withdrawal_amount` DECIMAL(18,2) COMMENT 'The maximum annual withdrawal amount guaranteed under the GMWB rider as of the valuation date. Calculated as the GMWB benefit base multiplied by the applicable withdrawal percentage. Used for RMD compliance checks and policyholder benefit illustrations.',
    `gmwb_benefit_base` DECIMAL(18,2) COMMENT 'The Guaranteed Minimum Withdrawal Benefit (GMWB) benefit base as of the valuation date. This is the notional amount used to calculate the guaranteed annual withdrawal amount, which may differ from AV due to step-ups, roll-ups, or bonus credits.',
    `gmwb_rider_active` BOOLEAN COMMENT 'Indicates whether the GMWB rider is currently active on this contract as of the valuation date. Drives inclusion of GMWB benefit base and NAR calculations in the valuation.',
    `index_credit_amount` DECIMAL(18,2) COMMENT 'The index credit amount applied to the contract AV during the current index crediting period as of the valuation date. Applicable for Fixed Indexed Annuity (FIA) contracts. Reflects the gain linked to the selected index strategy.',
    `is_1035_exchange` BOOLEAN COMMENT 'Indicates whether this contract was funded via a 1035 tax-free exchange from a prior insurance or annuity contract. True if funded by 1035 exchange; False if funded by direct premium. Affects cost basis tracking and tax reporting.',
    `is_mec` BOOLEAN COMMENT 'Indicates whether the annuity contract has been classified as a Modified Endowment Contract (MEC) under IRC Section 7702A. MEC status affects the tax treatment of withdrawals and loans. True if MEC; False otherwise.',
    `issue_date` DATE COMMENT 'The original issue date of the annuity contract. Used to calculate contract duration, surrender charge schedule position, and benefit base roll-up periods.',
    `market_value_adjustment` DECIMAL(18,2) COMMENT 'The Market Value Adjustment (MVA) applicable to the contract as of the valuation date. Positive or negative adjustment applied to the surrender value based on changes in interest rates since contract issue. Applicable for MVA-type fixed annuities.',
    `maturity_date` DATE COMMENT 'The contractual maturity date of the annuity contract, after which the contract must be annuitized or surrendered per contract terms. Used for GMAB maturity benefit calculations and policyholder notifications.',
    `nar_gmdb` DECIMAL(18,2) COMMENT 'The Net Amount at Risk (NAR) for the GMDB rider as of the valuation date. Calculated as the excess of the GMDB value over the current AV. Represents the insurers economic exposure on the death benefit guarantee. Key input for actuarial reserving and reinsurance cession.',
    `nar_gmwb` DECIMAL(18,2) COMMENT 'The Net Amount at Risk (NAR) for the GMWB rider as of the valuation date. Represents the present value of projected future guaranteed withdrawals in excess of projected AV. Key input for LDTI/IFRS 17 liability measurement.',
    `product_code` STRING COMMENT 'Code identifying the specific annuity product type (e.g., FIA, SPIA, variable annuity, fixed annuity) associated with this contract. Drives product-specific valuation logic and benefit calculations.',
    `rmd_amount` DECIMAL(18,2) COMMENT 'The Required Minimum Distribution (RMD) amount calculated for the contract for the current tax year as of the valuation date. Applicable for qualified annuity contracts (IRA, 401(k)). Ensures IRS compliance under IRC Section 401(a)(9).',
    `source_system_code` STRING COMMENT 'Code identifying the operational source system that originated this valuation data. Supports data lineage tracking across the lakehouse Silver layer.. Valid values are `sapiens_annuity|fast_annuity|moses|axis|prophet`',
    `statutory_reserve` DECIMAL(18,2) COMMENT 'The estimated statutory reserve for this contract as of the valuation date, calculated under SAP (Statutory Accounting Principles) per NAIC requirements. Includes Commissioners Annuity Reserve Valuation Method (CARVM) or Principle-Based Reserving (PBR) as applicable. Feeds state regulatory reserve filings.',
    `surrender_charge_amount` DECIMAL(18,2) COMMENT 'The contingent deferred sales charge (CDSC) or surrender charge applicable to the contract as of the valuation date. Deducted from AV to arrive at CSV. Typically declines over the surrender charge period.',
    `surrender_charge_period_end_date` DATE COMMENT 'The date on which the surrender charge period expires for this contract. After this date, the contract owner may surrender without incurring a surrender charge. Key date for policyholder communications and surrender processing.',
    `tax_qualification_type` STRING COMMENT 'The tax qualification status of the annuity contract. Determines applicable IRC tax rules, RMD requirements, and 1099-R reporting codes. Non-qualified contracts are funded with after-tax dollars; qualified contracts are funded with pre-tax dollars. [ENUM-REF-CANDIDATE: non_qualified|traditional_ira|roth_ira|401k|403b|sep_ira|simple_ira — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this contract valuation record was last modified in the Silver layer lakehouse. Tracks restatements, corrections, and status transitions for audit purposes.',
    `valuation_cycle` STRING COMMENT 'Frequency classification of this valuation run. Indicates whether the snapshot was generated as part of a daily, monthly, quarterly, or annual valuation cycle. Drives downstream actuarial and reporting workflows.. Valid values are `daily|monthly|quarterly|annual`',
    `valuation_date` DATE COMMENT 'The as-of date for this valuation snapshot. Represents the specific calendar date on which all financial positions (AV, CSV, DB, guarantees) are measured. Used as the primary time dimension for actuarial feeds, LDTI/IFRS 17 reporting, and policyholder statements.',
    `valuation_status` STRING COMMENT 'Lifecycle status of this valuation record. Preliminary records are in-process; final records are approved for reporting; restated records reflect corrections; superseded records have been replaced by a newer run for the same contract and valuation date.. Valid values are `preliminary|final|restated|superseded`',
    `ytd_withdrawals` DECIMAL(18,2) COMMENT 'Total withdrawal amounts taken from the contract from the beginning of the current contract year through the valuation date. Used to determine excess withdrawal amounts that may reduce the GMWB benefit base and for IRC Section 72 tax reporting.',
    CONSTRAINT pk_contract_valuation PRIMARY KEY(`contract_valuation_id`)
) COMMENT 'Periodic valuation snapshot of each annuity contract capturing the full financial position at a valuation date. Records contract AV, surrender value (CSV), death benefit amount, GMDB value, GMWB benefit base, GMIB benefit base, GMAB benefit base, net amount at risk (NAR) for each guarantee, accrued rider charges, and statutory reserve estimate. Supports actuarial valuation feeds, policyholder annual statements, and LDTI/IFRS 17 reporting. Generated at each valuation cycle (daily, monthly, quarterly, annually).';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`sub_account_allocation` (
    `sub_account_allocation_id` BIGINT COMMENT 'Unique surrogate identifier for each sub-account allocation record within a variable annuity contract. Primary key for this entity.',
    `contract_id` BIGINT COMMENT 'Reference to the variable annuity contract to which this sub-account allocation belongs. Links the allocation to the parent annuity contract record.',
    `separate_account_fund_id` BIGINT COMMENT 'Reference to the investment fund (sub-account) available within the variable annuity separate account. Identifies the specific fund option selected by the contract owner.',
    `separate_account_id` BIGINT COMMENT 'Foreign key linking to investment.separate_account. Business justification: Each sub-account allocation maps to a specific investment.separate_account for daily unit value pricing, NAV reporting, and SEC/NAIC regulatory filings. The existing separate_account_code is a denorma',
    `allocation_instruction_source` STRING COMMENT 'Identifies the originating source of the allocation instruction. Distinguishes between owner-directed, agent-directed, system-default, automatic rebalancing, DCA transfer, and system-generated allocations. Used for suitability review and audit trail.. Valid values are `owner_instruction|agent_instruction|default|rebalancing|dca_transfer|system_generated`',
    `allocation_number` STRING COMMENT 'Externally-visible business identifier for this sub-account allocation record, as assigned by the Annuity Administration Platform (e.g., Sapiens Annuity, FAST Annuity). Used in client statements and correspondence.',
    `allocation_pct` DECIMAL(18,2) COMMENT 'Percentage of new premium and/or rebalancing proceeds directed to this sub-account fund, expressed as a decimal (e.g., 25.0000 = 25%). All active allocations for a contract must sum to 100%. Used in premium allocation and rebalancing processing.',
    `allocation_status` STRING COMMENT 'Current lifecycle status of the sub-account allocation. active indicates the allocation is in force; pending indicates awaiting effective date or processing; suspended indicates temporarily halted; terminated indicates closed; transferred indicates moved to another fund.. Valid values are `active|pending|suspended|terminated|transferred`',
    `asset_transfer_rebalance_pct` DECIMAL(18,2) COMMENT 'Target allocation percentage used specifically for automatic rebalancing calculations. May differ from the current allocation_pct if the owner has submitted a pending rebalancing instruction not yet effective.',
    `cost_basis` DECIMAL(18,2) COMMENT 'Aggregate cost basis (investment in contract) allocated to this sub-account, used for tax reporting under IRC Section 72 to determine the taxable portion of withdrawals and annuity payments.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this sub-account allocation record was first created in the Annuity Administration Platform. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values in this allocation record (e.g., USD). Supports multi-currency annuity contracts and regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `dca_end_date` DATE COMMENT 'Date on which the Dollar Cost Averaging (DCA) transfer program for this sub-account allocation is scheduled to end. Null if DCA is not active or has no defined end date.',
    `dca_transfer_amount` DECIMAL(18,2) COMMENT 'Periodic dollar amount transferred into this sub-account under the Dollar Cost Averaging (DCA) program per the defined frequency. Applicable only when dollar_cost_averaging_flag is True.',
    `dollar_cost_averaging_flag` BOOLEAN COMMENT 'Indicates whether this sub-account allocation participates in a Dollar Cost Averaging (DCA) program, where funds are systematically transferred from a fixed account or money market into this sub-account over a defined period.',
    `effective_date` DATE COMMENT 'Date on which this sub-account allocation instruction became effective for the contract. Represents the business event date when the allocation was applied, distinct from the record creation timestamp.',
    `expense_ratio` DECIMAL(18,2) COMMENT 'Annual expense ratio of the underlying investment fund expressed as a percentage (e.g., 0.7500 = 0.75%). Includes management fees and fund operating expenses. Required for prospectus disclosure and suitability analysis.',
    `is_default_allocation` BOOLEAN COMMENT 'Indicates whether this sub-account allocation is part of the contracts default investment allocation (e.g., applied when no explicit owner instruction is on file). Used in new business processing and NIGO resolution workflows.',
    `is_restricted_fund` BOOLEAN COMMENT 'Indicates whether this sub-account fund is subject to trading restrictions (e.g., market timing restrictions, fund closure to new investments). When True, new allocations or transfers into this fund may be blocked.',
    `last_transfer_date` DATE COMMENT 'Most recent date on which a fund transfer (in or out) was processed for this sub-account allocation. Used to enforce transfer restriction periods and market timing compliance.',
    `market_value` DECIMAL(18,2) COMMENT 'Current fair market value (FMV) of the contract owners holdings in this sub-account, calculated as units_held multiplied by unit_value as of the valuation date. Contributes to the total Account Value (AV) of the annuity contract.',
    `mortality_expense_risk_charge_rate` DECIMAL(18,2) COMMENT 'Annual Mortality and Expense (M&E) risk charge rate assessed against this sub-accounts market value, expressed as a percentage. Covers the insurers mortality risk and expense guarantees. Required for cost disclosure and actuarial reserving.',
    `prospectus_date` DATE COMMENT 'Date of the most recent fund prospectus under which this sub-account allocation was made. Required for SEC disclosure compliance and ensures the contract owner received current fund information.',
    `rebalancing_flag` BOOLEAN COMMENT 'Indicates whether automatic portfolio rebalancing is enabled for this sub-account allocation. When True, the contracts holdings are periodically rebalanced back to the target allocation percentages per the rebalancing frequency.',
    `rebalancing_frequency` STRING COMMENT 'Frequency at which automatic portfolio rebalancing is performed for this sub-account allocation, when rebalancing_flag is True. Determines how often the allocation is reset to the target percentage.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `risk_rating` STRING COMMENT 'Standardized risk rating category assigned to this sub-account fund based on its investment objective and volatility profile. Used for suitability matching, asset allocation reporting, and client disclosure.. Valid values are `conservative|moderate_conservative|moderate|moderate_aggressive|aggressive`',
    `source_system_code` STRING COMMENT 'Code identifying the operational source system from which this allocation record originated (e.g., SAPIENS_ANNUITY, FAST_ANNUITY). Supports data lineage and ETL reconciliation in the Silver Layer lakehouse.',
    `suitability_review_status` STRING COMMENT 'Status of the suitability review for this sub-account allocation instruction, per NAIC Suitability in Annuity Transactions Model Regulation and DOL fiduciary standards. Tracks whether the investment selection has been reviewed and approved as suitable for the contract owner.. Valid values are `not_required|pending|approved|rejected|escalated`',
    `termination_date` DATE COMMENT 'Date on which this sub-account allocation was terminated, transferred, or zeroed out. Null if the allocation is still active. Used for historical allocation tracking and audit trail.',
    `transfer_restriction_days` STRING COMMENT 'Minimum number of calendar days that must elapse between transfers into and out of this sub-account fund. Enforces market timing restrictions per SEC Rule 22c-2 and fund prospectus requirements.',
    `unit_value` DECIMAL(18,2) COMMENT 'Current Net Asset Value (NAV) per accumulation unit for this sub-account fund as of the valuation date. Sourced from the Investment Management System (e.g., Charles River IMS, SimCorp Dimension) daily pricing feed. Used to compute sub-account market value.',
    `units_held` DECIMAL(18,2) COMMENT 'Number of accumulation units held in this sub-account as of the most recent valuation date. Multiplied by the current unit value to derive the sub-account market value. Core field for NAV-based Account Value (AV) calculation.',
    `units_purchased_ytd` DECIMAL(18,2) COMMENT 'Cumulative number of accumulation units purchased in this sub-account during the current calendar year. Used for investment activity reporting and tax cost basis tracking under IRC Section 72.',
    `units_redeemed_ytd` DECIMAL(18,2) COMMENT 'Cumulative number of accumulation units redeemed from this sub-account during the current calendar year due to withdrawals, transfers, or charges. Used for investment activity reporting and cost basis tracking.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this sub-account allocation record. Used for change tracking, incremental ETL processing, and audit compliance.',
    `valuation_date` DATE COMMENT 'Business date as of which the unit value, units held, and market value are reported. Corresponds to the NAV pricing date from the Investment Management System. Critical for daily AV reconciliation and regulatory reporting.',
    CONSTRAINT pk_sub_account_allocation PRIMARY KEY(`sub_account_allocation_id`)
) COMMENT 'Manages the sub-account investment allocations for variable annuity (VUL annuity) contracts, defining how the contract AV is distributed across available investment options (equity funds, bond funds, money market, fixed account). Captures sub-account fund name, fund CUSIP, allocation percentage, current unit value, number of units held, current market value, allocation effective date, and rebalancing instructions. Supports NAV-based AV calculations and investment performance attribution for variable annuity contracts.';

CREATE OR REPLACE TABLE `life_insurance_ecm`.`annuity`.`surrender_charge` (
    `surrender_charge_id` BIGINT COMMENT 'Unique identifier for the surrender charge schedule record.',
    `charge_schedule_id` BIGINT COMMENT 'Foreign key linking to product.charge_schedule. Business justification: annuity.surrender_charge is the contract-specific instantiation of a product.charge_schedule definition. Actuarial reserve calculations, rate filing compliance, and surrender charge waiver processing ',
    `contract_id` BIGINT COMMENT 'Reference to the annuity contract to which this surrender charge schedule applies.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Surrender charge collections are recognized as revenue and require journal entries for GAAP deferred revenue release and SAP income recognition. Finance teams reconcile surrender charge income to GL p',
    `pricing_basis_id` BIGINT COMMENT 'Foreign key linking to actuarial.pricing_basis. Business justification: Surrender charge schedules (period length, rates) are actuarially derived from pricing assumptions (investment return, lapse rates, DAC recovery). This link supports rate filing validation and actuari',
    `rate_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.rate_filing. Business justification: Surrender charge schedules require rate filing approval in many states. Links surrender charge schedules to approved rate filings for regulatory compliance validation. Required for market conduct exam',
    `superseded_surrender_charge_id` BIGINT COMMENT 'Self-referencing FK on surrender_charge (superseded_surrender_charge_id)',
    `charge_application_method` STRING COMMENT 'Method by which surrender charges are applied to withdrawals (e.g., pro-rata across all withdrawals, only on amounts exceeding free withdrawal limit, or tiered based on withdrawal amount).. Valid values are `pro_rata|excess_only|tiered`',
    `charge_calculation_basis` STRING COMMENT 'The basis upon which the surrender charge is calculated (e.g., current account value, premium paid, or withdrawal amount).. Valid values are `account_value|premium|withdrawal_amount`',
    `contract_year` STRING COMMENT 'The contract year to which this surrender charge rate applies, starting from 1 at contract issue.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this surrender charge schedule record was first created in the system.',
    `cumulative_free_withdrawal_flag` BOOLEAN COMMENT 'Indicates whether unused free withdrawal amounts from prior years can be carried forward and used in subsequent years.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts in this surrender charge schedule.. Valid values are `^[A-Z]{3}$`',
    `effective_date` DATE COMMENT 'Date when this surrender charge schedule becomes effective for the contract.',
    `expiry_date` DATE COMMENT 'Date when the surrender charge schedule expires or is no longer applicable, typically at the end of the surrender charge period.',
    `free_withdrawal_basis` STRING COMMENT 'The basis upon which the free withdrawal amount is calculated (e.g., account value, premium paid, or benefit base).. Valid values are `account_value|premium|benefit_base`',
    `free_withdrawal_pct` DECIMAL(18,2) COMMENT 'The percentage of account value that can be withdrawn annually without incurring a surrender charge, expressed as a decimal (e.g., 0.1000 for 10%).',
    `mva_applicable_flag` BOOLEAN COMMENT 'Indicates whether a market value adjustment is applied to surrenders in addition to the surrender charge.',
    `mva_formula_code` STRING COMMENT 'Code identifying the specific formula or calculation method used to determine the market value adjustment.',
    `mva_index_type` STRING COMMENT 'The interest rate index or benchmark used to calculate the market value adjustment (e.g., 10-Year Treasury, LIBOR).',
    `period_years` STRING COMMENT 'Total number of years during which surrender charges apply to the contract.',
    `product_code` STRING COMMENT 'Code identifying the annuity product to which this surrender charge schedule applies.',
    `product_type` STRING COMMENT 'Type of annuity product (fixed, variable, indexed, or immediate) to which this surrender charge schedule applies.. Valid values are `fixed|variable|indexed|immediate`',
    `rate` DECIMAL(18,2) COMMENT 'The percentage rate applied to calculate the surrender charge for this contract year, expressed as a decimal (e.g., 0.0800 for 8%).',
    `schedule_number` STRING COMMENT 'Business identifier for the surrender charge schedule, typically aligned with product or contract version.',
    `schedule_status` STRING COMMENT 'Current lifecycle status of the surrender charge schedule.. Valid values are `active|inactive|superseded|expired`',
    `schedule_version` STRING COMMENT 'Version identifier for the surrender charge schedule, used to track changes over time.',
    `source_system_code` STRING COMMENT 'Code identifying the source system from which this surrender charge schedule data originated (e.g., FAST, Sapiens, EXL).',
    `state_of_issue` STRING COMMENT 'Two-letter state code where the contract was issued, relevant for state-specific surrender charge regulations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this surrender charge schedule record was last updated in the system.',
    `waiver_annuitization_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the contract is annuitized according to the available payout options.',
    `waiver_death_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived upon the death of the owner or annuitant.',
    `waiver_disability_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the owner becomes disabled, subject to policy terms.',
    `waiver_ltc_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the owner qualifies for long-term care benefits under the contract.',
    `waiver_nursing_home_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the owner is confined to a nursing home for a specified period.',
    `waiver_rmd_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived for withdrawals taken to satisfy IRS required minimum distribution requirements.',
    `waiver_terminal_illness_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the owner is diagnosed with a terminal illness.',
    `waiver_unemployment_flag` BOOLEAN COMMENT 'Indicates whether surrender charges are waived if the owner becomes involuntarily unemployed.',
    CONSTRAINT pk_surrender_charge PRIMARY KEY(`surrender_charge_id`)
) COMMENT 'Tracks the surrender charge schedule and calculations for annuity contracts. Captures surrender charge percentage by contract year, free withdrawal allowance, market value adjustment (MVA) calculations, and waiver conditions.';

